    ls_class_t *class_unbound_variable;

    /* Standard streams. */
    ls_stream_t *stdin_;
    ls_stream_t *stdout_;
    ls_stream_t *stderr_;

    /* Dynamic / handler / escape stacks. */
    ls_dynframe_t *dyn_top;
    ls_handler_t  *hnd_top;
