/*** Begin: lscore.c ***/
/* lscore.c -- core value/type operations, allocator, hashtable,
 * vector, and the small utility functions every other module leans on. */

/* ---------- Basic value builders ---------- */

ls_value_t ls_nil_v(void) {
    ls_value_t v;
    memset(&v, 0, sizeof v);
    v.tag = LS_T_NIL;
    return v;
}

ls_value_t ls_t_v(void) {
    ls_value_t v;
    memset(&v, 0, sizeof v);
    v.tag = LS_T_T;
    return v;
}

ls_value_t ls_nil(void) { return ls_nil_v(); }
ls_value_t ls_t(void)   { return ls_t_v(); }

ls_value_t ls_make_fixnum(int64_t x) {
    ls_value_t v;
    memset(&v, 0, sizeof v);
    v.tag = LS_T_FIXNUM;
    v.u.fixnum = x;
    return v;
}

ls_value_t ls_make_flonum(double x) {
    ls_value_t v;
    memset(&v, 0, sizeof v);
    v.tag = LS_T_FLONUM;
    v.u.flonum = x;
    return v;
}

ls_value_t ls_make_char(uint32_t cp) {
    ls_value_t v;
    memset(&v, 0, sizeof v);
    v.tag = LS_T_CHAR;
    v.u.character = cp;
    return v;
}

ls_value_t ls_wrap(uint16_t tag, void *p) {
    ls_value_t v;
    memset(&v, 0, sizeof v);
    v.tag = tag;
    v.u.ptr = p;
    return v;
}

int ls_is_nil    (ls_value_t v) { return v.tag == LS_T_NIL; }
int ls_is_t      (ls_value_t v) { return v.tag == LS_T_T; }
int ls_is_fixnum (ls_value_t v) { return v.tag == LS_T_FIXNUM; }
int ls_is_flonum (ls_value_t v) { return v.tag == LS_T_FLONUM; }
int ls_is_number (ls_value_t v) {
    return v.tag == LS_T_FIXNUM || v.tag == LS_T_FLONUM
        || v.tag == LS_T_RATIO  || v.tag == LS_T_BIGNUM
        || v.tag == LS_T_COMPLEX;
}
int ls_is_string (ls_value_t v) { return v.tag == LS_T_STRING; }
int ls_is_symbol (ls_value_t v) { return v.tag == LS_T_SYMBOL; }
int ls_is_cons   (ls_value_t v) { return v.tag == LS_T_CONS; }
int ls_is_list   (ls_value_t v) { return v.tag == LS_T_CONS || v.tag == LS_T_NIL; }
int ls_is_vector (ls_value_t v) { return v.tag == LS_T_VECTOR; }
int ls_is_hash   (ls_value_t v) { return v.tag == LS_T_HASHTABLE; }
int ls_is_fn     (ls_value_t v) {
    return v.tag == LS_T_FUNCTION || v.tag == LS_T_BYTECODE
        || v.tag == LS_T_NATIVE   || v.tag == LS_T_GENERIC;
}

int64_t ls_to_fixnum(ls_value_t v) {
    if (v.tag == LS_T_FIXNUM) return v.u.fixnum;
    if (v.tag == LS_T_FLONUM) return (int64_t)v.u.flonum;
    return 0;
}
double ls_to_flonum(ls_value_t v) {
    if (v.tag == LS_T_FLONUM) return v.u.flonum;
    if (v.tag == LS_T_FIXNUM) return (double)v.u.fixnum;
    return 0.0;
}
const char *ls_to_string(ls_value_t v, size_t *len_out) {
    if (v.tag == LS_T_STRING) {
        ls_string_t *s = (ls_string_t *)v.u.ptr;
        if (len_out) *len_out = s->len;
        return s->chars;
    }
    if (len_out) *len_out = 0;
    return "";
}

/* ---------- Heap object allocation ---------- */

ls_value_t ls_make_obj(ls_state_t *L, uint16_t tag, uint32_t size) {
    ls_obj_header_t *h = (ls_obj_header_t *)calloc(1, size);
    if (!h) {
        ls_error(L, "out of memory (allocating %u bytes, tag %u)", size, tag);
        return ls_nil_v();
    }
    h->tag = tag;
    h->size = size;
    h->flags = 0;
    h->next = L->gc.all_objects;
    L->gc.all_objects = h;
    L->gc.bytes_allocated += size;
    return ls_wrap(tag, h);
}

/* Typed accessors */
ls_cons_t       *ls_cons_p      (ls_value_t v) { return v.tag == LS_T_CONS      ? (ls_cons_t       *)v.u.ptr : NULL; }
ls_symbol_t     *ls_symbol_p    (ls_value_t v) { return v.tag == LS_T_SYMBOL    ? (ls_symbol_t     *)v.u.ptr : NULL; }
ls_string_t     *ls_string_p    (ls_value_t v) { return v.tag == LS_T_STRING    ? (ls_string_t     *)v.u.ptr : NULL; }
ls_vector_t     *ls_vector_p    (ls_value_t v) { return v.tag == LS_T_VECTOR    ? (ls_vector_t     *)v.u.ptr : NULL; }
ls_hashtable_t  *ls_hash_p      (ls_value_t v) { return v.tag == LS_T_HASHTABLE ? (ls_hashtable_t  *)v.u.ptr : NULL; }
ls_function_t   *ls_function_p  (ls_value_t v) { return v.tag == LS_T_FUNCTION  ? (ls_function_t   *)v.u.ptr : NULL; }
ls_bytecode_fn_t*ls_bytecode_p  (ls_value_t v) { return v.tag == LS_T_BYTECODE  ? (ls_bytecode_fn_t*)v.u.ptr : NULL; }
ls_native_t     *ls_native_p    (ls_value_t v) { return v.tag == LS_T_NATIVE    ? (ls_native_t     *)v.u.ptr : NULL; }
ls_package_t    *ls_package_p   (ls_value_t v) { return v.tag == LS_T_PACKAGE   ? (ls_package_t    *)v.u.ptr : NULL; }
ls_stream_t     *ls_stream_p    (ls_value_t v) { return v.tag == LS_T_STREAM    ? (ls_stream_t     *)v.u.ptr : NULL; }
ls_class_t      *ls_class_p     (ls_value_t v) { return v.tag == LS_T_CLASS     ? (ls_class_t      *)v.u.ptr : NULL; }
ls_instance_t   *ls_instance_p  (ls_value_t v) { return v.tag == LS_T_INSTANCE  ? (ls_instance_t   *)v.u.ptr : NULL; }

/* ---------- Strings ---------- */

ls_value_t ls_make_string(ls_state_t *L, const char *s, size_t n) {
    ls_value_t v = ls_make_obj(L, LS_T_STRING, sizeof(ls_string_t));
    ls_string_t *str = (ls_string_t *)v.u.ptr;
    str->len = n;
    str->cap = n + 1;
    str->chars = (char *)malloc(n + 1);
    if (!str->chars) { ls_error(L, "out of memory"); return ls_nil_v(); }
    if (s && n) memcpy(str->chars, s, n);
    str->chars[n] = 0;
    return v;
}

/* ---------- Cons cells ---------- */

ls_value_t ls_cons(ls_state_t *L, ls_value_t car, ls_value_t cdr) {
    ls_value_t v = ls_make_obj(L, LS_T_CONS, sizeof(ls_cons_t));
    ls_cons_t *c = (ls_cons_t *)v.u.ptr;
    c->car = car;
    c->cdr = cdr;
    return v;
}

ls_value_t ls_car(ls_value_t v) {
    if (v.tag == LS_T_NIL) return v;
    if (v.tag != LS_T_CONS) {
        ls_value_t z = { 0 };
        z.tag = LS_T_NIL;
        return z;
    }
    return ((ls_cons_t *)v.u.ptr)->car;
}
ls_value_t ls_cdr(ls_value_t v) {
    if (v.tag == LS_T_NIL) return v;
    if (v.tag != LS_T_CONS) {
        ls_value_t z = { 0 };
        z.tag = LS_T_NIL;
        return z;
    }
    return ((ls_cons_t *)v.u.ptr)->cdr;
}

size_t ls_list_length(ls_value_t list) {
    size_t n = 0;
    while (list.tag == LS_T_CONS) { n++; list = ((ls_cons_t *)list.u.ptr)->cdr; }
    return n;
}

ls_value_t ls_list_nth(ls_value_t list, size_t n) {
    while (n-- && list.tag == LS_T_CONS) list = ((ls_cons_t *)list.u.ptr)->cdr;
    if (list.tag != LS_T_CONS) return ls_nil_v();
    return ((ls_cons_t *)list.u.ptr)->car;
}

ls_value_t ls_list_reverse(ls_state_t *L, ls_value_t list) {
    ls_value_t acc = ls_nil_v();
    while (list.tag == LS_T_CONS) {
        acc  = ls_cons(L, ((ls_cons_t *)list.u.ptr)->car, acc);
        list = ((ls_cons_t *)list.u.ptr)->cdr;
    }
    return acc;
}

ls_value_t ls_list_append(ls_state_t *L, ls_value_t a, ls_value_t b) {
    if (a.tag == LS_T_NIL) return b;
    /* naive: reverse a, then cons onto b */
    ls_value_t ra = ls_list_reverse(L, a);
    ls_value_t out = b;
    while (ra.tag == LS_T_CONS) {
        out = ls_cons(L, ((ls_cons_t *)ra.u.ptr)->car, out);
        ra  = ((ls_cons_t *)ra.u.ptr)->cdr;
    }
    return out;
}

/* ---------- Vector ---------- */

ls_vector_t *ls_vec_new(ls_state_t *L, size_t cap, int adjustable) {
    ls_value_t v = ls_make_obj(L, LS_T_VECTOR, sizeof(ls_vector_t));
    ls_vector_t *vec = (ls_vector_t *)v.u.ptr;
    vec->len = 0;
    vec->cap = cap ? cap : 4;
    vec->fill_ptr = (size_t)-1;
    vec->adjustable = adjustable;
    vec->data = (ls_value_t *)calloc(vec->cap, sizeof(ls_value_t));
    if (!vec->data) { ls_error(L, "out of memory"); }
    return vec;
}

void ls_vec_push(ls_state_t *L, ls_vector_t *v, ls_value_t x) {
    (void)L;
    if (v->len == v->cap) {
        size_t ncap = v->cap * 2;
        ls_value_t *nd = (ls_value_t *)realloc(v->data, ncap * sizeof(ls_value_t));
        if (!nd) return;
        memset(nd + v->cap, 0, (ncap - v->cap) * sizeof(ls_value_t));
        v->data = nd;
        v->cap  = ncap;
    }
    v->data[v->len++] = x;
}

/* ---------- Hashtable (robin-hood) ---------- */

static void hash_grow(ls_state_t *L, ls_hashtable_t *h);

uint32_t ls_hash_string(const char *s, size_t n) {
    /* FNV-1a-ish */
    uint32_t h = 2166136261u;
    for (size_t i = 0; i < n; i++) {
        h ^= (uint8_t)s[i];
        h *= 16777619u;
    }
    return h ? h : 1;
}

uint32_t ls_hash_value(ls_value_t v, ls_hash_test_t t) {
    uint32_t h;
    switch (v.tag) {
    case LS_T_NIL:      return 0xdeadbeefu;
    case LS_T_T:        return 0xfee1dead;
    case LS_T_FIXNUM:   {
        uint64_t x = (uint64_t)v.u.fixnum;
        x ^= (x >> 33); x *= 0xff51afd7ed558ccdULL;
        x ^= (x >> 33); x *= 0xc4ceb9fe1a85ec53ULL;
        x ^= (x >> 33);
        return (uint32_t)x;
    }
    case LS_T_FLONUM:   {
        uint64_t x; memcpy(&x, &v.u.flonum, 8);
        x ^= (x >> 33); x *= 0xff51afd7ed558ccdULL; x ^= (x >> 33);
        return (uint32_t)x;
    }
    case LS_T_CHAR:     return v.u.character ^ 0xc0ffee;
    case LS_T_SYMBOL: {
        ls_symbol_t *s = (ls_symbol_t *)v.u.ptr;
        return s->hash;
    }
    case LS_T_STRING: {
        ls_string_t *s = (ls_string_t *)v.u.ptr;
        if (t == LS_HASH_EQUALP) {
            uint32_t hh = 2166136261u;
            for (size_t i = 0; i < s->len; i++) {
                hh ^= (uint8_t)tolower((unsigned char)s->chars[i]);
                hh *= 16777619u;
            }
            return hh ? hh : 1;
        }
        return ls_hash_string(s->chars, s->len);
    }
    case LS_T_CONS: {
        if (t == LS_HASH_EQUAL || t == LS_HASH_EQUALP) {
            /* hash a bounded number of elements */
            uint32_t hh = 0x9e3779b9u;
            int depth = 0;
            while (v.tag == LS_T_CONS && depth < 8) {
                hh ^= ls_hash_value(((ls_cons_t*)v.u.ptr)->car, t) + 0x9e3779b9u + (hh<<6) + (hh>>2);
                v = ((ls_cons_t*)v.u.ptr)->cdr;
                depth++;
            }
            return hh ? hh : 1;
        }
        /* fall through for EQ/EQL: hash pointer identity */
    }
    /* fall through */
    default: {
        uintptr_t p = (uintptr_t)v.u.ptr;
        h = (uint32_t)(p ^ (p >> 32));
        return h ? h : 1;
    }
    }
}

int ls_value_equal(ls_value_t a, ls_value_t b, ls_hash_test_t t) {
    if (a.tag != b.tag) {
        /* fixnum-flonum equality under EQL is false; under EQUAL also false.
         * But = (numeric comparison) is separate. */
        return 0;
    }
    switch (a.tag) {
    case LS_T_NIL: case LS_T_T: return 1;
    case LS_T_FIXNUM: return a.u.fixnum == b.u.fixnum;
    case LS_T_FLONUM: return a.u.flonum == b.u.flonum;
    case LS_T_CHAR:
        if (t == LS_HASH_EQUALP)
            return tolower((unsigned char)a.u.character) == tolower((unsigned char)b.u.character);
        return a.u.character == b.u.character;
    case LS_T_SYMBOL: return a.u.ptr == b.u.ptr;
    case LS_T_STRING: {
        ls_string_t *sa = (ls_string_t*)a.u.ptr, *sb = (ls_string_t*)b.u.ptr;
        if (t == LS_HASH_EQ || t == LS_HASH_EQL) return sa == sb;
        if (sa->len != sb->len) return 0;
        if (t == LS_HASH_EQUALP) {
            for (size_t i = 0; i < sa->len; i++)
                if (tolower((unsigned char)sa->chars[i]) != tolower((unsigned char)sb->chars[i]))
                    return 0;
            return 1;
        }
        return memcmp(sa->chars, sb->chars, sa->len) == 0;
    }
    case LS_T_CONS:
        if (t == LS_HASH_EQ || t == LS_HASH_EQL) return a.u.ptr == b.u.ptr;
        {
            ls_value_t va = a, vb = b;
            while (va.tag == LS_T_CONS && vb.tag == LS_T_CONS) {
                ls_cons_t *ca = (ls_cons_t*)va.u.ptr, *cb = (ls_cons_t*)vb.u.ptr;
                if (!ls_value_equal(ca->car, cb->car, t)) return 0;
                va = ca->cdr; vb = cb->cdr;
            }
            return ls_value_equal(va, vb, t);
        }
    case LS_T_VECTOR:
        if (t == LS_HASH_EQ || t == LS_HASH_EQL) return a.u.ptr == b.u.ptr;
        {
            ls_vector_t *va = (ls_vector_t*)a.u.ptr, *vb = (ls_vector_t*)b.u.ptr;
            if (va->len != vb->len) return 0;
            for (size_t i = 0; i < va->len; i++)
                if (!ls_value_equal(va->data[i], vb->data[i], t)) return 0;
            return 1;
        }
    default:
        return a.u.ptr == b.u.ptr;
    }
}

ls_hashtable_t *ls_hash_new(ls_state_t *L, ls_hash_test_t test, size_t cap_hint) {
    ls_value_t v = ls_make_obj(L, LS_T_HASHTABLE, sizeof(ls_hashtable_t));
    ls_hashtable_t *h = (ls_hashtable_t *)v.u.ptr;
    size_t cap = 16;
    while (cap < cap_hint * 2) cap *= 2;
    h->cap = cap;
    h->count = 0;
    h->test = test;
    h->entries = (ls_hash_entry_t *)calloc(cap, sizeof(ls_hash_entry_t));
    return h;
}

static void hash_insert_raw(ls_hashtable_t *h, uint32_t hash, ls_value_t k, ls_value_t v) {
    uint32_t mask = (uint32_t)(h->cap - 1);
    uint32_t idx = hash & mask;
    uint32_t dist = 0;
    ls_hash_entry_t e; e.hash = hash; e.dist = 0; e.key = k; e.val = v;
    for (;;) {
        if (h->entries[idx].hash == 0) {
            h->entries[idx] = e;
            h->entries[idx].dist = dist;
            h->count++;
            return;
        }
        if (h->entries[idx].dist < dist) {
            ls_hash_entry_t tmp = h->entries[idx];
            h->entries[idx] = e;
            h->entries[idx].dist = dist;
            e = tmp;
            dist = e.dist;
        }
        idx = (idx + 1) & mask;
        dist++;
    }
}

static void hash_grow(ls_state_t *L, ls_hashtable_t *h) {
    (void)L;
    size_t old_cap = h->cap;
    ls_hash_entry_t *old = h->entries;
    h->cap *= 2;
    h->entries = (ls_hash_entry_t *)calloc(h->cap, sizeof(ls_hash_entry_t));
    h->count = 0;
    for (size_t i = 0; i < old_cap; i++)
        if (old[i].hash)
            hash_insert_raw(h, old[i].hash, old[i].key, old[i].val);
    free(old);
}

void ls_hash_put(ls_state_t *L, ls_hashtable_t *h, ls_value_t k, ls_value_t v) {
    if (h->count * 10 > h->cap * 9) hash_grow(L, h);
    uint32_t hash = ls_hash_value(k, h->test);
    if (hash == 0) hash = 1;
    /* first, look up to update in place */
    uint32_t mask = (uint32_t)(h->cap - 1);
    uint32_t idx = hash & mask;
    uint32_t dist = 0;
    for (;;) {
        if (h->entries[idx].hash == 0) break;
        if (h->entries[idx].hash == hash && ls_value_equal(h->entries[idx].key, k, h->test)) {
            h->entries[idx].val = v;
            return;
        }
        if (h->entries[idx].dist < dist) break;
        idx = (idx + 1) & mask; dist++;
    }
    hash_insert_raw(h, hash, k, v);
}

int ls_hash_get_sv(ls_hashtable_t *h, ls_value_t k, ls_value_t *out) {
    if (!h) return 0;
    uint32_t hash = ls_hash_value(k, h->test);
    if (hash == 0) hash = 1;
    uint32_t mask = (uint32_t)(h->cap - 1);
    uint32_t idx = hash & mask;
    uint32_t dist = 0;
    for (;;) {
        if (h->entries[idx].hash == 0) return 0;
        if (h->entries[idx].hash == hash && ls_value_equal(h->entries[idx].key, k, h->test)) {
            *out = h->entries[idx].val;
            return 1;
        }
        if (h->entries[idx].dist < dist) return 0;
        idx = (idx + 1) & mask; dist++;
    }
}

ls_value_t ls_hash_get(ls_hashtable_t *h, ls_value_t k) {
    ls_value_t v;
    if (ls_hash_get_sv(h, k, &v)) return v;
    return ls_nil_v();
}

int ls_hash_remove(ls_hashtable_t *h, ls_value_t k) {
    if (!h) return 0;
    uint32_t hash = ls_hash_value(k, h->test);
    if (hash == 0) hash = 1;
    uint32_t mask = (uint32_t)(h->cap - 1);
    uint32_t idx = hash & mask;
    uint32_t dist = 0;
    for (;;) {
        if (h->entries[idx].hash == 0) return 0;
        if (h->entries[idx].hash == hash && ls_value_equal(h->entries[idx].key, k, h->test)) {
            /* backward shift */
            uint32_t nidx = (idx + 1) & mask;
            while (h->entries[nidx].hash != 0 && h->entries[nidx].dist > 0) {
                h->entries[idx] = h->entries[nidx];
                h->entries[idx].dist--;
                idx = nidx;
                nidx = (nidx + 1) & mask;
            }
            memset(&h->entries[idx], 0, sizeof(ls_hash_entry_t));
            h->count--;
            return 1;
        }
        if (h->entries[idx].dist < dist) return 0;
        idx = (idx + 1) & mask; dist++;
    }
}

/* ---------- Symbol / package ---------- */

ls_package_t *ls_find_package(ls_state_t *L, const char *name, size_t namelen) {
    /* linear scan of package hashtable since pkg names are keys as strings */
    ls_value_t name_v = ls_make_string(L, name, namelen);
    ls_value_t pkg_v;
    if (ls_hash_get_sv(L->packages, name_v, &pkg_v)) return (ls_package_t *)pkg_v.u.ptr;
    return NULL;
}

ls_package_t *ls_ensure_package(ls_state_t *L, const char *name) {
    size_t n = strlen(name);
    ls_package_t *p = ls_find_package(L, name, n);
    if (p) return p;
    ls_value_t v = ls_make_obj(L, LS_T_PACKAGE, sizeof(ls_package_t));
    p = (ls_package_t *)v.u.ptr;
    p->name       = (ls_string_t *)ls_make_string(L, name, n).u.ptr;
    p->internal   = ls_hash_new(L, LS_HASH_EQUAL, 64);
    p->external   = ls_hash_new(L, LS_HASH_EQUAL, 16);
    p->use_list   = ls_nil_v();
    p->nicknames  = ls_nil_v();
    ls_hash_put(L, L->packages, ls_make_string(L, name, n), v);
    return p;
}

ls_value_t ls_intern_sym(ls_state_t *L, ls_package_t *pkg, const char *name, size_t namelen, int *is_external) {
    ls_value_t key = ls_make_string(L, name, namelen);
    ls_value_t out;
    if (ls_hash_get_sv(pkg->external, key, &out)) { if (is_external) *is_external = 1; return out; }
    if (ls_hash_get_sv(pkg->internal, key, &out)) { if (is_external) *is_external = 0; return out; }
    /* also search USE-list externally */
    ls_value_t uses = pkg->use_list;
    while (uses.tag == LS_T_CONS) {
        ls_package_t *up = (ls_package_t *)((ls_cons_t *)uses.u.ptr)->car.u.ptr;
        if (ls_hash_get_sv(up->external, key, &out)) { if (is_external) *is_external = 1; return out; }
        uses = ((ls_cons_t *)uses.u.ptr)->cdr;
    }
    /* create new internal symbol */
    ls_value_t sv = ls_make_obj(L, LS_T_SYMBOL, sizeof(ls_symbol_t));
    ls_symbol_t *s = (ls_symbol_t *)sv.u.ptr;
    s->name     = (ls_string_t *)key.u.ptr;
    s->package  = pkg;
    s->value    = ls_nil_v();
    s->function = ls_nil_v();
    s->plist    = ls_nil_v();
    s->sym_flags = 0;
    s->hash     = ls_hash_string(name, namelen);
    if (pkg == L->pkg_keyword) {
        s->sym_flags |= LS_SYM_KEYWORD | LS_SYM_CONSTANT;
        s->value      = sv;
        ls_hash_put(L, pkg->external, key, sv);
        if (is_external) *is_external = 1;
    } else {
        ls_hash_put(L, pkg->internal, key, sv);
        if (is_external) *is_external = 0;
    }
    return sv;
}

ls_value_t ls_intern(ls_state_t *L, const char *pkg, const char *name) {
    ls_package_t *p = pkg ? ls_ensure_package(L, pkg) : L->current_package;
    int ext;
    return ls_intern_sym(L, p, name, strlen(name), &ext);
}

void ls_export_symbol(ls_state_t *L, ls_package_t *pkg, ls_symbol_t *sym) {
    ls_value_t key = ls_make_string(L, sym->name->chars, sym->name->len);
    ls_value_t sv; sv.tag = LS_T_SYMBOL; sv.flags = 0; sv.u.ptr = sym;
    /* Remove from internal if present, add to external. */
    ls_hash_remove(pkg->internal, key);
    ls_hash_put(L, pkg->external, key, sv);
}

ls_value_t ls_make_symbol(ls_state_t *L, const char *name) {
    return ls_intern(L, NULL, name);
}

/* ---------- Varargs funcall ---------- */

ls_value_t ls_funcall(ls_state_t *L, ls_value_t fn, int nargs, ...) {
    ls_value_t args[32];
    va_list ap;
    va_start(ap, nargs);
    for (int i = 0; i < nargs && i < 32; i++)
        args[i] = va_arg(ap, ls_value_t);
    va_end(ap);
    return ls_apply(L, fn, nargs, args);
}

/* ---------- Error reporting ---------- */

void ls_error(ls_state_t *L, const char *fmt, ...) {
    va_list ap; va_start(ap, fmt);
    vsnprintf(L->err_buf, sizeof L->err_buf, fmt, ap);
    va_end(ap);
    /* long-jump to outermost escape frame if any */
    if (L->esc_top) {
        L->esc_top->kind = 2;
        L->esc_top->value = ls_nil_v();
        longjmp(L->esc_top->buf, 1);
    }
    fprintf(stderr, "litesrpent: error: %s\n", L->err_buf);
}

void ls_type_error(ls_state_t *L, const char *expected, ls_value_t got) {
    (void)got;
    ls_error(L, "type error: expected %s", expected);
}
void ls_arity_error(ls_state_t *L, const char *name, int got, int min, int max) {
    ls_error(L, "arity error in %s: got %d, expected %d..%d", name, got, min, max);
}
void ls_undefined_function_error(ls_state_t *L, ls_symbol_t *s) {
    ls_error(L, "undefined function: %s", s && s->name ? s->name->chars : "?");
}
void ls_unbound_variable_error(ls_state_t *L, ls_symbol_t *s) {
    ls_error(L, "unbound variable: %s", s && s->name ? s->name->chars : "?");
}

const char *ls_last_error(ls_state_t *L) { return L->err_buf; }

int ls_signal(ls_state_t *L, const char *type, const char *fmt, ...) {
    va_list ap; va_start(ap, fmt);
    vsnprintf(L->err_buf, sizeof L->err_buf, fmt, ap);
    va_end(ap);
    (void)type;
    if (L->esc_top) {
        L->esc_top->kind = 2;
        longjmp(L->esc_top->buf, 1);
    }
    return -1;
}

/* Global get/set convenience used by embedders. */
ls_value_t ls_getvar(ls_state_t *L, ls_value_t sym) {
    ls_symbol_t *s = ls_symbol_p(sym);
    if (!s) { ls_error(L, "getvar: not a symbol"); return ls_nil_v(); }
    if (!(s->sym_flags & LS_SYM_HAS_VALUE)) {
        ls_unbound_variable_error(L, s);
        return ls_nil_v();
    }
    return s->value;
}
void ls_setvar(ls_state_t *L, ls_value_t sym, ls_value_t val) {
    ls_symbol_t *s = ls_symbol_p(sym);
    if (!s) { ls_error(L, "setvar: not a symbol"); return; }
    s->value = val;
    s->sym_flags |= LS_SYM_HAS_VALUE;
}

void ls_defun(ls_state_t *L, const char *pkg, const char *name,
              ls_native_fn fn, int min_args, int max_args) {
    ls_value_t sv = ls_intern(L, pkg, name);
    ls_value_t nv = ls_make_obj(L, LS_T_NATIVE, sizeof(ls_native_t));
    ls_native_t *n = (ls_native_t *)nv.u.ptr;
    n->fn = fn;
    n->name = name;
    n->min_args = (int16_t)min_args;
    n->max_args = (int16_t)max_args;
    ls_symbol_t *s = (ls_symbol_t *)sv.u.ptr;
    s->function = nv;
    s->sym_flags |= LS_SYM_HAS_FN;
    /* Also export from the package. */
    if (s->package) {
        ls_value_t key = ls_wrap(LS_T_STRING, s->name);
        ls_hash_put(L, s->package->external, key, sv);
    }
}
/*** End: lscore.c ***/

/*** Begin: lsgc.c ***/
/* lsgc.c -- mark-and-sweep garbage collector.
 *
 * The GC walks every live ls_value_t starting from a small set of
 * roots (state pointers, escape frames, dyn frames), marks each
 * reachable heap object, then sweeps the all-objects list to free
 * anything not marked.  It is stop-the-world, precise on the heap,
 * and conservative only with respect to C local variables (which
 * we do NOT scan -- instead we require call sites that need GC
 * safety to use ls_gc_push_root).
 *
 * For Litesrpent's use case (a Lisp REPL + compiler) this is plenty. */


#define LS_MAX_ROOT_SLOTS 256

static ls_value_t **g_root_slots;
static size_t       g_root_count;
static size_t       g_root_cap;

void ls_gc_push_root(ls_state_t *L, ls_value_t *slot) {
    (void)L;
    if (g_root_count == g_root_cap) {
        size_t nc = g_root_cap ? g_root_cap * 2 : 64;
        g_root_slots = (ls_value_t **)realloc(g_root_slots, nc * sizeof(*g_root_slots));
        g_root_cap = nc;
    }
    g_root_slots[g_root_count++] = slot;
}
void ls_gc_pop_root(ls_state_t *L) { (void)L; if (g_root_count) g_root_count--; }

/* Gray-stack based marker. */
static void gray_push(ls_gc_t *g, ls_obj_header_t *h) {
    if (!h || (h->flags & LS_GC_MARK)) return;
    h->flags |= LS_GC_MARK;
    if (g->gray_count == g->gray_cap) {
        size_t nc = g->gray_cap ? g->gray_cap * 2 : 256;
        g->gray_stack = (ls_value_t *)realloc(g->gray_stack, nc * sizeof(ls_value_t));
        g->gray_cap = nc;
    }
    ls_value_t v; memset(&v, 0, sizeof v);
    v.tag = h->tag;
    v.u.ptr = h;
    g->gray_stack[g->gray_count++] = v;
}

static void mark_value(ls_gc_t *g, ls_value_t v) {
    switch (v.tag) {
    case LS_T_NIL: case LS_T_T: case LS_T_FIXNUM:
    case LS_T_FLONUM: case LS_T_CHAR: case LS_T_SPECIAL:
        return;
    default:
        if (v.u.ptr) gray_push(g, (ls_obj_header_t *)v.u.ptr);
    }
}

static void trace_object(ls_gc_t *g, ls_obj_header_t *h) {
    switch (h->tag) {
    case LS_T_CONS: {
        ls_cons_t *c = (ls_cons_t *)h;
        mark_value(g, c->car); mark_value(g, c->cdr);
        break;
    }
    case LS_T_SYMBOL: {
        ls_symbol_t *s = (ls_symbol_t *)h;
        if (s->name)    gray_push(g, &s->name->h);
        if (s->package) gray_push(g, &s->package->h);
        mark_value(g, s->value);
        mark_value(g, s->function);
        mark_value(g, s->plist);
        break;
    }
    case LS_T_STRING: break;
    case LS_T_VECTOR: {
        ls_vector_t *v = (ls_vector_t *)h;
        for (size_t i = 0; i < v->len; i++) mark_value(g, v->data[i]);
        break;
    }
    case LS_T_HASHTABLE: {
        ls_hashtable_t *ht = (ls_hashtable_t *)h;
        for (size_t i = 0; i < ht->cap; i++) {
            if (ht->entries[i].hash) {
                mark_value(g, ht->entries[i].key);
                mark_value(g, ht->entries[i].val);
            }
        }
        break;
    }
    case LS_T_FUNCTION: {
        ls_function_t *f = (ls_function_t *)h;
        mark_value(g, f->lambda_list);
        mark_value(g, f->body);
        mark_value(g, f->docstring);
        if (f->closure) gray_push(g, &f->closure->h);
        if (f->name) gray_push(g, &f->name->h);
        break;
    }
    case LS_T_BYTECODE: {
        ls_bytecode_fn_t *f = (ls_bytecode_fn_t *)h;
        if (f->proto) gray_push(g, &f->proto->h);
        for (uint32_t i = 0; i < f->nupvals; i++) mark_value(g, f->upvals[i]);
        if (f->name) gray_push(g, &f->name->h);
        break;
    }
    case LS_T_PACKAGE: {
        ls_package_t *p = (ls_package_t *)h;
        if (p->name) gray_push(g, &p->name->h);
        if (p->internal) gray_push(g, &p->internal->h);
        if (p->external) gray_push(g, &p->external->h);
        mark_value(g, p->use_list);
        mark_value(g, p->nicknames);
        break;
    }
    case LS_T_STREAM: break;
    case LS_T_FOREIGN: break;
    case LS_T_FOREIGN_LIB: {
        ls_foreign_lib_t *lib = (ls_foreign_lib_t *)h;
        if (lib->path) gray_push(g, &lib->path->h);
        break;
    }
    case LS_T_FOREIGN_FN: {
        ls_foreign_fn_t *fn = (ls_foreign_fn_t *)h;
        if (fn->lib) gray_push(g, &fn->lib->h);
        if (fn->name) gray_push(g, &fn->name->h);
        break;
    }
    case LS_T_CLASS: {
        ls_class_t *c = (ls_class_t *)h;
        if (c->name) gray_push(g, &c->name->h);
        mark_value(g, c->direct_supers);
        mark_value(g, c->direct_slots);
        mark_value(g, c->precedence_list);
        mark_value(g, c->effective_slots);
        mark_value(g, c->metaclass);
        if (c->slot_index) gray_push(g, &c->slot_index->h);
        break;
    }
    case LS_T_INSTANCE: {
        ls_instance_t *in = (ls_instance_t *)h;
        if (in->class_) gray_push(g, &in->class_->h);
        if (in->slots)
            for (uint32_t i = 0; i < in->class_->n_slots; i++)
                mark_value(g, in->slots[i]);
        break;
    }
    case LS_T_GENERIC: {
        ls_generic_t *gf = (ls_generic_t *)h;
        if (gf->name) gray_push(g, &gf->name->h);
        mark_value(g, gf->lambda_list);
        mark_value(g, gf->methods);
        mark_value(g, gf->combination);
        break;
    }
    case LS_T_METHOD: {
        ls_method_t *m = (ls_method_t *)h;
        mark_value(g, m->specializers);
        mark_value(g, m->qualifiers);
        mark_value(g, m->lambda);
        mark_value(g, m->generic);
        break;
    }
    case LS_T_CONDITION: {
        ls_condition_t *c = (ls_condition_t *)h;
        if (c->class_) gray_push(g, &c->class_->h);
        mark_value(g, c->initargs);
        mark_value(g, c->format_control);
        mark_value(g, c->format_arguments);
        break;
    }
    default: break;
    }
}

static void mark_roots(ls_state_t *L) {
    ls_gc_t *g = &L->gc;
    if (L->genv)    gray_push(g, &L->genv->h);
    if (L->packages) gray_push(g, &L->packages->h);
    if (L->pkg_cl)       gray_push(g, &L->pkg_cl->h);
    if (L->pkg_cl_user)  gray_push(g, &L->pkg_cl_user->h);
    if (L->pkg_keyword)  gray_push(g, &L->pkg_keyword->h);
    if (L->pkg_system)   gray_push(g, &L->pkg_system->h);
    if (L->current_package) gray_push(g, &L->current_package->h);
    if (L->symbol_cache) gray_push(g, &L->symbol_cache->h);
    if (L->stdin_)  gray_push(g, &L->stdin_->h);
    if (L->stdout_) gray_push(g, &L->stdout_->h);
    if (L->stderr_) gray_push(g, &L->stderr_->h);
    /* cached symbols */
#define ROOT_SYM(f) if (L->f) gray_push(g, &L->f->h)
    ROOT_SYM(sym_quote); ROOT_SYM(sym_quasiquote); ROOT_SYM(sym_unquote);
    ROOT_SYM(sym_unquote_splicing); ROOT_SYM(sym_function); ROOT_SYM(sym_lambda);
    ROOT_SYM(sym_if); ROOT_SYM(sym_let); ROOT_SYM(sym_letstar); ROOT_SYM(sym_progn);
    ROOT_SYM(sym_setq); ROOT_SYM(sym_defun); ROOT_SYM(sym_defmacro);
    ROOT_SYM(sym_defvar); ROOT_SYM(sym_defparameter); ROOT_SYM(sym_defconstant);
    ROOT_SYM(sym_defgeneric); ROOT_SYM(sym_defmethod); ROOT_SYM(sym_defclass);
    ROOT_SYM(sym_block); ROOT_SYM(sym_return_from); ROOT_SYM(sym_tagbody); ROOT_SYM(sym_go);
    ROOT_SYM(sym_catch); ROOT_SYM(sym_throw); ROOT_SYM(sym_unwind_protect);
    ROOT_SYM(sym_handler_case); ROOT_SYM(sym_handler_bind);
    ROOT_SYM(sym_restart_case); ROOT_SYM(sym_restart_bind);
    ROOT_SYM(sym_multiple_value_bind); ROOT_SYM(sym_multiple_value_call);
    ROOT_SYM(sym_multiple_value_prog1); ROOT_SYM(sym_the); ROOT_SYM(sym_declare);
    ROOT_SYM(sym_eval_when); ROOT_SYM(sym_flet); ROOT_SYM(sym_labels);
    ROOT_SYM(sym_macrolet); ROOT_SYM(sym_symbol_macrolet);
    ROOT_SYM(sym_load_time_value); ROOT_SYM(sym_locally);
    ROOT_SYM(sym_and); ROOT_SYM(sym_or); ROOT_SYM(sym_when); ROOT_SYM(sym_unless);
    ROOT_SYM(sym_cond); ROOT_SYM(sym_case); ROOT_SYM(sym_typecase);
    ROOT_SYM(sym_ampersand_rest); ROOT_SYM(sym_ampersand_optional);
    ROOT_SYM(sym_ampersand_key); ROOT_SYM(sym_ampersand_aux);
    ROOT_SYM(sym_ampersand_body); ROOT_SYM(sym_ampersand_allow_other_keys);
    ROOT_SYM(sym_ampersand_whole); ROOT_SYM(sym_ampersand_environment);
    ROOT_SYM(sym_otherwise); ROOT_SYM(sym_t);
#undef ROOT_SYM

    /* classes */
#define ROOT_CL(f) if (L->f) gray_push(g, &L->f->h)
    ROOT_CL(class_t); ROOT_CL(class_standard_object); ROOT_CL(class_cons);
    ROOT_CL(class_symbol); ROOT_CL(class_string); ROOT_CL(class_number);
    ROOT_CL(class_integer); ROOT_CL(class_fixnum); ROOT_CL(class_float);
    ROOT_CL(class_vector); ROOT_CL(class_hashtable); ROOT_CL(class_function);
    ROOT_CL(class_condition); ROOT_CL(class_error); ROOT_CL(class_simple_error);
    ROOT_CL(class_type_error); ROOT_CL(class_arith_error);
    ROOT_CL(class_undefined_function); ROOT_CL(class_unbound_variable);
#undef ROOT_CL

    /* escape/handler/dynamic bindings */
    for (ls_dynframe_t *d = L->dyn_top; d; d = d->next) {
        if (d->sym) gray_push(g, &d->sym->h);
        mark_value(g, d->old_val);
    }
    for (ls_handler_t *h = L->hnd_top; h; h = h->next) {
        if (h->type) gray_push(g, &h->type->h);
        mark_value(g, h->fn);
    }
    for (ls_restart_frame_t *r = L->restart_top; r; r = r->next) {
        if (r->restart) gray_push(g, &r->restart->h);
    }
    for (ls_escape_t *e = L->esc_top; e; e = e->next) {
        mark_value(g, e->tag);
        mark_value(g, e->value);
    }
    /* multiple values */
    for (int i = 0; i < L->mv.n; i++) mark_value(g, L->mv.v[i]);

    /* user-pushed roots */
    for (size_t i = 0; i < g_root_count; i++) mark_value(g, *g_root_slots[i]);
}

static void sweep(ls_state_t *L) {
    ls_gc_t *g = &L->gc;
    ls_obj_header_t **pp = &g->all_objects;
    while (*pp) {
        ls_obj_header_t *h = *pp;
        if ((h->flags & LS_GC_MARK) || (h->flags & LS_GC_PINNED)) {
            h->flags &= ~LS_GC_MARK;
            pp = &h->next;
        } else {
            *pp = h->next;
            /* free any owned internal buffers */
            switch (h->tag) {
            case LS_T_STRING:    free(((ls_string_t *)h)->chars); break;
            case LS_T_VECTOR:    free(((ls_vector_t *)h)->data); break;
            case LS_T_HASHTABLE: free(((ls_hashtable_t *)h)->entries); break;
            case LS_T_INSTANCE:  free(((ls_instance_t *)h)->slots); break;
            case LS_T_ARRAY:     free(((ls_array_t *)h)->dims); free(((ls_array_t *)h)->data); break;
            case LS_T_STREAM: {
                ls_stream_t *s = (ls_stream_t *)h;
                if (s->owns_fp && s->fp) fclose(s->fp);
                free(s->buffer);
                break;
            }
            case LS_T_FOREIGN: {
                ls_foreign_t *f = (ls_foreign_t *)h;
                if (f->owned && f->ptr) free(f->ptr);
                break;
            }
            default: break;
            }
            g->bytes_allocated -= h->size;
            free(h);
        }
    }
}

void ls_gc_collect(ls_state_t *L) {
    if (L->gc.disabled) return;
    L->gc.gray_count = 0;
    mark_roots(L);
    while (L->gc.gray_count) {
        ls_value_t v = L->gc.gray_stack[--L->gc.gray_count];
        trace_object(&L->gc, (ls_obj_header_t *)v.u.ptr);
    }
    sweep(L);
    L->gc.next_gc = L->gc.bytes_allocated * 2 + (1u << 20);
}
/*** End: lsgc.c ***/

/*** Begin: lsenv.c ***/
/* lsenv.c -- lexical environments.
 *
 * An ls_env is a frame holding (symbol -> value) bindings, with a
 * parent pointer.  Lookup walks the chain.  Special variables
 * (declared via defvar/defparameter or marked SPECIAL) bypass the
 * lexical chain and use the dynamic binding stack instead. */

ls_env_t *ls_env_new(ls_state_t *L, ls_env_t *parent) {
    ls_value_t v = ls_make_obj(L, LS_T_SPECIAL, sizeof(ls_env_t));
    /* tag isn't really used for env -- it's an internal type */
    ls_env_t *e = (ls_env_t *)v.u.ptr;
    e->parent = parent;
    e->count = 0;
    e->cap = 0;
    e->bindings = NULL;
    return e;
}

void ls_env_bind(ls_state_t *L, ls_env_t *e, ls_symbol_t *sym, ls_value_t val) {
    (void)L;
    if (e->count == e->cap) {
        size_t nc = e->cap ? e->cap * 2 : 4;
        e->bindings = (ls_env_binding_t *)realloc(e->bindings, nc * sizeof *e->bindings);
        e->cap = nc;
    }
    e->bindings[e->count].sym = sym;
    e->bindings[e->count].val = val;
    e->bindings[e->count].special = (sym->sym_flags & LS_SYM_SPECIAL) ? 1 : 0;
    e->count++;
}

int ls_env_lookup(ls_env_t *e, ls_symbol_t *sym, ls_value_t *out) {
    while (e) {
        for (size_t i = e->count; i-- > 0; )
            if (e->bindings[i].sym == sym) { *out = e->bindings[i].val; return 1; }
        e = e->parent;
    }
    return 0;
}

int ls_env_set(ls_env_t *e, ls_symbol_t *sym, ls_value_t val) {
    while (e) {
        for (size_t i = e->count; i-- > 0; )
            if (e->bindings[i].sym == sym) { e->bindings[i].val = val; return 1; }
        e = e->parent;
    }
    return 0;
}

/* Dynamic bindings: pushed when binding a SPECIAL variable. */
void ls_dyn_push(ls_state_t *L, ls_symbol_t *sym, ls_value_t new_val) {
    ls_dynframe_t *d = (ls_dynframe_t *)calloc(1, sizeof *d);
    d->sym = sym;
    d->old_val = sym->value;
    d->had_value = (sym->sym_flags & LS_SYM_HAS_VALUE) ? 1 : 0;
    d->next = L->dyn_top;
    L->dyn_top = d;
    sym->value = new_val;
    sym->sym_flags |= LS_SYM_HAS_VALUE;
}
void ls_dyn_pop(ls_state_t *L) {
    ls_dynframe_t *d = L->dyn_top;
    if (!d) return;
    L->dyn_top = d->next;
    if (d->had_value) d->sym->value = d->old_val;
    else { d->sym->value = ls_nil_v(); d->sym->sym_flags &= ~LS_SYM_HAS_VALUE; }
    free(d);
}
/*** End: lsenv.c ***/

/*** Begin: lsreader.c ***/
/* lsreader.c -- lexer + reader for S-expressions.
 *
 * Accepts the usual Common Lisp read syntax: symbols, numbers
 * (decimal integer, hex #x, octal #o, binary #b, ratios, floats,
 * negative numbers), strings "...", characters #\x, quote '...,
 * quasiquote `..., unquote ,..., splicing ,@..., vectors #(...)
 * and a few reader macros (#+, #- feature tests and #|...|# block
 * comments, ;... line comments, #'symbol for (function symbol)).
 *
 * The reader returns the parsed S-expression; it does not evaluate.
 */
#ifdef _WIN32
#define strcasecmp _stricmp
#endif

typedef struct {
    ls_state_t *L;
    const char *src;
    size_t      pos;
    size_t      len;
    int         line;
    int         col;
} reader_t;

static int peek(reader_t *r) { return r->pos < r->len ? (unsigned char)r->src[r->pos] : -1; }
static int peek2(reader_t *r, size_t off) {
    return r->pos + off < r->len ? (unsigned char)r->src[r->pos + off] : -1;
}
static int get(reader_t *r) {
    if (r->pos >= r->len) return -1;
    int c = (unsigned char)r->src[r->pos++];
    if (c == '\n') { r->line++; r->col = 0; } else r->col++;
    return c;
}

static void skip_ws_and_comments(reader_t *r) {
    for (;;) {
        int c = peek(r);
        if (c == -1) return;
        if (c == ' ' || c == '\t' || c == '\n' || c == '\r' || c == '\f' || c == ',') {
            if (c == ',') {
                /* in CL, comma is reserved for unquote -- not whitespace.
                 * We check upstream for that; here, only skip if preceded
                 * by nothing special. Actually never skip: rely on unquote. */
                return;
            }
            get(r);
            continue;
        }
        if (c == ';') { while (c != -1 && c != '\n') c = get(r); continue; }
        if (c == '#' && peek2(r, 1) == '|') {
            get(r); get(r); int depth = 1;
            while (depth) {
                int d = get(r);
                if (d == -1) return;
                if (d == '#' && peek(r) == '|') { get(r); depth++; }
                else if (d == '|' && peek(r) == '#') { get(r); depth--; }
            }
            continue;
        }
        return;
    }
}

static int is_sym_char(int c) {
    if (c == -1) return 0;
    if (isspace(c)) return 0;
    if (c == '(' || c == ')' || c == '"' || c == '\'' || c == '`' ||
        c == ',' || c == ';' || c == '|') return 0;
    return 1;
}

static ls_value_t read_expr(reader_t *r);

static ls_value_t read_string(reader_t *r) {
    get(r); /* opening quote */
    char buf[4096];
    size_t n = 0;
    size_t cap = sizeof buf;
    char *heap = NULL;
    char *dst = buf;
    for (;;) {
        int c = get(r);
        if (c == -1) { ls_error(r->L, "unterminated string"); break; }
        if (c == '"') break;
        if (c == '\\') {
            int d = get(r);
            switch (d) {
            case 'n': c = '\n'; break;
            case 't': c = '\t'; break;
            case 'r': c = '\r'; break;
            case '0': c = '\0'; break;
            case '\\': c = '\\'; break;
            case '"': c = '"'; break;
            default: c = d;
            }
        }
        if (n + 1 >= cap) {
            size_t ncap = cap * 2;
            char *nh = (char *)malloc(ncap);
            memcpy(nh, dst, n);
            if (heap) free(heap);
            heap = nh; dst = nh; cap = ncap;
        }
        dst[n++] = (char)c;
    }
    ls_value_t v = ls_make_string(r->L, dst, n);
    if (heap) free(heap);
    return v;
}

static ls_value_t parse_number_or_symbol(ls_state_t *L, const char *buf, size_t n) {
    /* Try to parse as number.  Supported:
     *   integer: optional sign, [0-9]+
     *   ratio:   [0-9]+/[0-9]+
     *   float:   [-+]?\d+(\.\d+)?([eE][-+]?\d+)?
     */
    if (n == 0) return ls_intern(L, NULL, "||");
    size_t i = 0;
    int sign = 1;
    if (buf[0] == '+' || buf[0] == '-') { if (buf[0] == '-') sign = -1; i = 1; }
    if (i == n) goto as_symbol;
    /* check if all digits (with one optional '.', 'e', '/'), a valid number */
    int saw_digit = 0, saw_dot = 0, saw_exp = 0, saw_slash = 0;
    for (size_t j = i; j < n; j++) {
        char c = buf[j];
        if (isdigit((unsigned char)c)) { saw_digit = 1; continue; }
        if (c == '.' && !saw_dot && !saw_exp && !saw_slash) { saw_dot = 1; continue; }
        if ((c == 'e' || c == 'E' || c == 'd' || c == 'D' || c == 'f' || c == 'F')
            && saw_digit && !saw_exp && !saw_slash) {
            saw_exp = 1;
            if (j + 1 < n && (buf[j+1] == '+' || buf[j+1] == '-')) j++;
            continue;
        }
        if (c == '/' && saw_digit && !saw_dot && !saw_exp && !saw_slash) {
            saw_slash = 1; saw_digit = 0; continue;
        }
        goto as_symbol;
    }
    if (!saw_digit) goto as_symbol;

    if (saw_dot || saw_exp) {
        double d = strtod(buf, NULL);
        return ls_make_flonum(d);
    }
    if (saw_slash) {
        /* represent ratio as cons (num . denom) for now */
        long num = 0, den = 0;
        size_t k = 0;
        if (buf[0] == '+' || buf[0] == '-') k = 1;
        while (k < n && buf[k] != '/') { num = num * 10 + (buf[k] - '0'); k++; }
        if (sign < 0) num = -num;
        k++;
        while (k < n) { den = den * 10 + (buf[k] - '0'); k++; }
        if (den == 0) return ls_make_fixnum(0);
        if (num % den == 0) return ls_make_fixnum(num / den);
        /* just store as float for now */
        return ls_make_flonum((double)num / (double)den);
    }
    int64_t x = 0;
    size_t k = (buf[0] == '+' || buf[0] == '-') ? 1 : 0;
    while (k < n) { x = x * 10 + (buf[k] - '0'); k++; }
    return ls_make_fixnum(sign * x);

as_symbol:
    /* Symbol.  Handle package prefix a:b or a::b, keyword :foo,
     * uninterned #:foo, and ||-quoted names. */
    if (n >= 1 && buf[0] == ':') {
        /* keyword -- upcase the name */
        char kwn[512];
        size_t klen = n - 1;
        if (klen > 511) klen = 511;
        for (size_t k = 0; k < klen; k++) kwn[k] = (char)toupper((unsigned char)buf[k+1]);
        kwn[klen] = 0;
        ls_package_t *kp = ls_ensure_package(L, "KEYWORD");
        int ext;
        return ls_intern_sym(L, kp, kwn, klen, &ext);
    }
    /* look for package prefix */
    for (size_t j = 0; j < n; j++) {
        if (buf[j] == ':') {
            int dbl = (j + 1 < n && buf[j+1] == ':') ? 1 : 0;
            char pkg[256], name[512];
            if (j > 255) j = 255;
            memcpy(pkg, buf, j); pkg[j] = 0;
            for (size_t k = 0; k < j; k++) pkg[k] = (char)toupper((unsigned char)pkg[k]);
            size_t off = j + 1 + dbl;
            size_t m   = n - off;
            if (m > 511) m = 511;
            memcpy(name, buf + off, m); name[m] = 0;
            for (size_t k = 0; k < m; k++) name[k] = (char)toupper((unsigned char)name[k]);
            ls_package_t *p = ls_ensure_package(L, pkg);
            int ext;
            return ls_intern_sym(L, p, name, m, &ext);
        }
    }
    /* uppercase default */
    char tmp[512];
    if (n > 511) n = 511;
    for (size_t k = 0; k < n; k++) tmp[k] = (char)toupper((unsigned char)buf[k]);
    /* Special atoms NIL and T */
    if (n == 3 && tmp[0] == 'N' && tmp[1] == 'I' && tmp[2] == 'L') return ls_nil_v();
    if (n == 1 && tmp[0] == 'T') return ls_t_v();
    return ls_intern_sym(L, L->current_package, tmp, n, NULL);
}

static ls_value_t read_token(reader_t *r) {
    char buf[512];
    size_t n = 0;
    while (is_sym_char(peek(r))) {
        if (n + 1 >= sizeof buf) { ls_error(r->L, "token too long"); break; }
        buf[n++] = (char)get(r);
    }
    buf[n] = 0;
    return parse_number_or_symbol(r->L, buf, n);
}

static ls_value_t read_list(reader_t *r) {
    get(r); /* '(' */
    ls_value_t head = ls_nil_v();
    ls_value_t tail = ls_nil_v();
    for (;;) {
        skip_ws_and_comments(r);
        int c = peek(r);
        if (c == -1) { ls_error(r->L, "unterminated list"); return ls_nil_v(); }
        if (c == ')') { get(r); return head; }
        if (c == '.' && (peek2(r, 1) == ' ' || peek2(r, 1) == '\t' || peek2(r, 1) == '\n')) {
            get(r);
            ls_value_t tailv = read_expr(r);
            if (tail.tag == LS_T_CONS) ((ls_cons_t *)tail.u.ptr)->cdr = tailv;
            else head = tailv;
            skip_ws_and_comments(r);
            if (peek(r) != ')') { ls_error(r->L, "expected ')' after dotted tail"); return head; }
            get(r);
            return head;
        }
        ls_value_t item = read_expr(r);
        ls_value_t cell = ls_cons(r->L, item, ls_nil_v());
        if (head.tag == LS_T_NIL) head = tail = cell;
        else { ((ls_cons_t *)tail.u.ptr)->cdr = cell; tail = cell; }
    }
}

static ls_value_t read_quote_like(reader_t *r, const char *opname) {
    get(r);
    ls_value_t q = read_expr(r);
    ls_value_t sym = ls_intern(r->L, "COMMON-LISP", opname);
    return ls_cons(r->L, sym, ls_cons(r->L, q, ls_nil_v()));
}

static ls_value_t read_char(reader_t *r) {
    /* already consumed '#\\' */
    /* read char name: letters/digits */
    char buf[16]; size_t n = 0;
    int first = get(r);
    if (first == -1) { ls_error(r->L, "bad #\\"); return ls_nil_v(); }
    buf[n++] = (char)first;
    while (n < sizeof buf - 1 && isalpha(peek(r))) buf[n++] = (char)get(r);
    buf[n] = 0;
    if (n == 1) return ls_make_char((uint32_t)buf[0]);
    if (strcasecmp(buf, "space")   == 0) return ls_make_char(' ');
    if (strcasecmp(buf, "tab")     == 0) return ls_make_char('\t');
    if (strcasecmp(buf, "newline") == 0) return ls_make_char('\n');
    if (strcasecmp(buf, "return")  == 0) return ls_make_char('\r');
    if (strcasecmp(buf, "null")    == 0) return ls_make_char('\0');
    if (strcasecmp(buf, "linefeed")== 0) return ls_make_char('\n');
    if (strcasecmp(buf, "page")    == 0) return ls_make_char('\f');
    if (strcasecmp(buf, "backspace")==0) return ls_make_char('\b');
    if (strcasecmp(buf, "rubout")  == 0) return ls_make_char(127);
    return ls_make_char((uint32_t)buf[0]);
}

static ls_value_t read_expr(reader_t *r) {
    skip_ws_and_comments(r);
    int c = peek(r);
    if (c == -1) return ls_nil_v();
    if (c == '(') return read_list(r);
    if (c == ')') { ls_error(r->L, "unexpected ')'"); get(r); return ls_nil_v(); }
    if (c == '"') return read_string(r);
    if (c == '\'') return read_quote_like(r, "QUOTE");
    if (c == '`')  return read_quote_like(r, "QUASIQUOTE");
    if (c == ',') {
        get(r);
        if (peek(r) == '@') { get(r);
            ls_value_t q = read_expr(r);
            ls_value_t sym = ls_intern(r->L, "COMMON-LISP", "UNQUOTE-SPLICING");
            return ls_cons(r->L, sym, ls_cons(r->L, q, ls_nil_v()));
        }
        ls_value_t q = read_expr(r);
        ls_value_t sym = ls_intern(r->L, "COMMON-LISP", "UNQUOTE");
        return ls_cons(r->L, sym, ls_cons(r->L, q, ls_nil_v()));
    }
    if (c == '#') {
        get(r);
        int d = get(r);
        switch (d) {
        case '\'': {
            ls_value_t q = read_expr(r);
            ls_value_t sym = ls_intern(r->L, "COMMON-LISP", "FUNCTION");
            return ls_cons(r->L, sym, ls_cons(r->L, q, ls_nil_v()));
        }
        case '\\': return read_char(r);
        case '(': {
            /* vector literal */
            r->pos--; /* push back '(' */
            ls_value_t list = read_list(r);
            ls_vector_t *v = ls_vec_new(r->L, ls_list_length(list), 0);
            while (list.tag == LS_T_CONS) {
                ls_vec_push(r->L, v, ((ls_cons_t *)list.u.ptr)->car);
                list = ((ls_cons_t *)list.u.ptr)->cdr;
            }
            return ls_wrap(LS_T_VECTOR, v);
        }
        case 'x': case 'X': {
            int64_t x = 0; int sign = 1;
            if (peek(r) == '-') { sign = -1; get(r); }
            while (isxdigit(peek(r))) {
                int ch = get(r);
                int d2 = (ch <= '9') ? ch - '0' :
                         (ch <= 'F') ? ch - 'A' + 10 : ch - 'a' + 10;
                x = x * 16 + d2;
            }
            return ls_make_fixnum(sign * x);
        }
        case 'o': case 'O': {
            int64_t x = 0; int sign = 1;
            if (peek(r) == '-') { sign = -1; get(r); }
            while (peek(r) >= '0' && peek(r) <= '7') x = x * 8 + (get(r) - '0');
            return ls_make_fixnum(sign * x);
        }
        case 'b': case 'B': {
            int64_t x = 0; int sign = 1;
            if (peek(r) == '-') { sign = -1; get(r); }
            while (peek(r) == '0' || peek(r) == '1') x = x * 2 + (get(r) - '0');
            return ls_make_fixnum(sign * x);
        }
        case 'p': case 'P': {
            /* pathname literal: just read a string and wrap it */
            ls_value_t s = read_string(r);
            ls_value_t sym = ls_intern(r->L, "COMMON-LISP", "PATHNAME");
            return ls_cons(r->L, sym, ls_cons(r->L, s, ls_nil_v()));
        }
        case '+': case '-': {
            /* feature test -- we just accept any feature for now */
            ls_value_t feat = read_expr(r);
            ls_value_t form = read_expr(r);
            (void)feat;
            return (d == '+') ? form : ls_nil_v();
        }
        case ':': {
            /* uninterned symbol */
            char buf[256]; size_t n = 0;
            while (is_sym_char(peek(r))) buf[n++] = (char)get(r);
            buf[n] = 0;
            for (size_t k = 0; k < n; k++) buf[k] = (char)toupper((unsigned char)buf[k]);
            ls_value_t sv = ls_make_obj(r->L, LS_T_SYMBOL, sizeof(ls_symbol_t));
            ls_symbol_t *s = (ls_symbol_t *)sv.u.ptr;
            s->name = (ls_string_t *)ls_make_string(r->L, buf, n).u.ptr;
            s->package = NULL; s->value = ls_nil_v();
            s->function = ls_nil_v(); s->plist = ls_nil_v();
            s->hash = ls_hash_string(buf, n);
            return sv;
        }
        default:
            ls_error(r->L, "unknown #%c reader macro", d);
            return ls_nil_v();
        }
    }
    return read_token(r);
}

ls_value_t ls_read_from_string(ls_state_t *L, const char *src, const char **end) {
    reader_t r = { L, src, 0, strlen(src), 1, 0 };
    ls_value_t v = read_expr(&r);
    if (end) *end = src + r.pos;
    return v;
}
/*** End: lsreader.c ***/

/*** Begin: lsprinter.c ***/
/* lsprinter.c -- printer / write / print / prin1 / princ. */

static void putstr(ls_stream_t *s, const char *buf, size_t n) {
    if (!s) return;
    if (s->string_stream) {
        if (s->bufpos + n + 1 > s->bufcap) {
            size_t nc = s->bufcap ? s->bufcap * 2 : 128;
            while (nc < s->bufpos + n + 1) nc *= 2;
            s->buffer = (char *)realloc(s->buffer, nc);
            s->bufcap = nc;
        }
        memcpy(s->buffer + s->bufpos, buf, n);
        s->bufpos += n;
        if (s->bufpos > s->buflen) s->buflen = s->bufpos;
        s->buffer[s->bufpos] = 0;
    } else if (s->fp) {
        fwrite(buf, 1, n, s->fp);
    }
}

static void putch(ls_stream_t *s, char c) { putstr(s, &c, 1); }
static void putcstr(ls_stream_t *s, const char *z) { putstr(s, z, strlen(z)); }

static void print_escaped(ls_stream_t *s, const char *str, size_t n) {
    putch(s, '"');
    for (size_t i = 0; i < n; i++) {
        char c = str[i];
        if (c == '"' || c == '\\') putch(s, '\\');
        putch(s, c);
    }
    putch(s, '"');
}

static int print_rec(ls_state_t *L, ls_value_t v, ls_stream_t *s, int esc, int depth) {
    char buf[64];
    if (depth > 1000) { putcstr(s, "#<deep>"); return 0; }
    switch (v.tag) {
    case LS_T_NIL: putcstr(s, "NIL"); break;
    case LS_T_T:   putcstr(s, "T"); break;
    case LS_T_FIXNUM: snprintf(buf, sizeof buf, "%lld", (long long)v.u.fixnum); putcstr(s, buf); break;
    case LS_T_FLONUM: snprintf(buf, sizeof buf, "%.16g", v.u.flonum);
        /* add trailing .0 if it looks integral, to keep float identity visible */
        if (!strchr(buf, '.') && !strchr(buf, 'e') && !strchr(buf, 'n') && !strchr(buf, 'i'))
            strcat(buf, ".0");
        putcstr(s, buf); break;
    case LS_T_CHAR:
        if (esc) {
            putcstr(s, "#\\");
            if (v.u.character == ' ') putcstr(s, "Space");
            else if (v.u.character == '\n') putcstr(s, "Newline");
            else if (v.u.character == '\t') putcstr(s, "Tab");
            else if (v.u.character == '\r') putcstr(s, "Return");
            else { char cc = (char)v.u.character; putch(s, cc); }
        } else {
            char cc = (char)v.u.character; putch(s, cc);
        }
        break;
    case LS_T_SYMBOL: {
        ls_symbol_t *sym = (ls_symbol_t *)v.u.ptr;
        if (esc && sym->package == L->pkg_keyword) putch(s, ':');
        if (sym->name) putstr(s, sym->name->chars, sym->name->len);
        else putcstr(s, "#:?");
        break;
    }
    case LS_T_STRING: {
        ls_string_t *str = (ls_string_t *)v.u.ptr;
        if (esc) print_escaped(s, str->chars, str->len);
        else     putstr(s, str->chars, str->len);
        break;
    }
    case LS_T_CONS: {
        putch(s, '(');
        ls_value_t cur = v;
        int first = 1;
        while (cur.tag == LS_T_CONS) {
            if (!first) putch(s, ' ');
            first = 0;
            print_rec(L, ((ls_cons_t *)cur.u.ptr)->car, s, esc, depth + 1);
            cur = ((ls_cons_t *)cur.u.ptr)->cdr;
        }
        if (cur.tag != LS_T_NIL) {
            putcstr(s, " . ");
            print_rec(L, cur, s, esc, depth + 1);
        }
        putch(s, ')');
        break;
    }
    case LS_T_VECTOR: {
        ls_vector_t *vec = (ls_vector_t *)v.u.ptr;
        putcstr(s, "#(");
        for (size_t i = 0; i < vec->len; i++) {
            if (i) putch(s, ' ');
            print_rec(L, vec->data[i], s, esc, depth + 1);
        }
        putch(s, ')');
        break;
    }
    case LS_T_HASHTABLE:    putcstr(s, "#<HASH-TABLE>"); break;
    case LS_T_FUNCTION: {
        ls_function_t *f = (ls_function_t *)v.u.ptr;
        putcstr(s, "#<FUNCTION ");
        if (f->name) putstr(s, f->name->name->chars, f->name->name->len);
        else putcstr(s, "(ANON)");
        putch(s, '>');
        break;
    }
    case LS_T_BYTECODE: {
        ls_bytecode_fn_t *f = (ls_bytecode_fn_t *)v.u.ptr;
        putcstr(s, "#<COMPILED-FUNCTION ");
        if (f->name) putstr(s, f->name->name->chars, f->name->name->len);
        else putcstr(s, "(ANON)");
        putch(s, '>');
        break;
    }
    case LS_T_NATIVE: {
        ls_native_t *n = (ls_native_t *)v.u.ptr;
        putcstr(s, "#<BUILTIN ");
        if (n->name) putcstr(s, n->name);
        putch(s, '>');
        break;
    }
    case LS_T_PACKAGE: {
        ls_package_t *p = (ls_package_t *)v.u.ptr;
        putcstr(s, "#<PACKAGE ");
        putstr(s, p->name->chars, p->name->len);
        putch(s, '>');
        break;
    }
    case LS_T_STREAM:       putcstr(s, "#<STREAM>"); break;
    case LS_T_FOREIGN: {
        ls_foreign_t *f = (ls_foreign_t *)v.u.ptr;
        snprintf(buf, sizeof buf, "#<FOREIGN 0x%p>", f->ptr); putcstr(s, buf);
        break;
    }
    case LS_T_FOREIGN_LIB: {
        ls_foreign_lib_t *lib = (ls_foreign_lib_t *)v.u.ptr;
        putcstr(s, "#<FOREIGN-LIB ");
        if (lib->path) putstr(s, lib->path->chars, lib->path->len);
        putch(s, '>');
        break;
    }
    case LS_T_FOREIGN_FN: {
        ls_foreign_fn_t *fn = (ls_foreign_fn_t *)v.u.ptr;
        putcstr(s, "#<FOREIGN-FN ");
        if (fn->name) putstr(s, fn->name->chars, fn->name->len);
        putch(s, '>');
        break;
    }
    case LS_T_CLASS: {
        ls_class_t *c = (ls_class_t *)v.u.ptr;
        putcstr(s, "#<CLASS ");
        if (c->name) putstr(s, c->name->name->chars, c->name->name->len);
        putch(s, '>');
        break;
    }
    case LS_T_INSTANCE: {
        ls_instance_t *in = (ls_instance_t *)v.u.ptr;
        putcstr(s, "#<");
        if (in->class_ && in->class_->name)
            putstr(s, in->class_->name->name->chars, in->class_->name->name->len);
        putch(s, '>');
        break;
    }
    case LS_T_GENERIC: {
        ls_generic_t *g = (ls_generic_t *)v.u.ptr;
        putcstr(s, "#<GENERIC-FUNCTION ");
        if (g->name) putstr(s, g->name->name->chars, g->name->name->len);
        putch(s, '>');
        break;
    }
    case LS_T_CONDITION: {
        ls_condition_t *c = (ls_condition_t *)v.u.ptr;
        putcstr(s, "#<CONDITION ");
        if (c->class_ && c->class_->name)
            putstr(s, c->class_->name->name->chars, c->class_->name->name->len);
        putch(s, '>');
        break;
    }
    default:
        snprintf(buf, sizeof buf, "#<OBJECT tag=%u>", v.tag);
        putcstr(s, buf);
    }
    return 0;
}

int ls_print_value(ls_state_t *L, ls_value_t v, ls_stream_t *s, int escape) {
    if (!s) s = L->stdout_;
    return print_rec(L, v, s, escape, 0);
}
/*** End: lsprinter.c ***/

/*** Begin: lseval.c ***/
/* lseval.c -- tree-walking evaluator for Litesrpent.
 *
 * This is the canonical interpreter; it implements every special form
 * defined by Common Lisp.  The bytecode compiler (in lscompiler.c) is
 * a *cache* on top of this -- functions defined with defun are compiled
 * lazily on first call into bytecode; the JIT then compiles hot
 * bytecode functions into native code.  But the source-level semantics
 * are anchored here.
 */

/* Forward decls (the compiler hooks in here too). */
ls_value_t ls_compile_lambda(ls_state_t *L, ls_value_t lambda_list,
                             ls_value_t body, ls_env_t *env, ls_symbol_t *name);
int ls_jit_function_value(ls_state_t *L, ls_value_t fn);

/* ---------- Lambda-list parameter binding ---------- *
 *
 * Common Lisp's lambda-list grammar:
 *   (required* [&optional ...] [&rest var] [&key ...] [&allow-other-keys] [&aux ...])
 *
 * We bind directly into env. */

typedef struct {
    ls_symbol_t *amp_optional;
    ls_symbol_t *amp_rest;
    ls_symbol_t *amp_key;
    ls_symbol_t *amp_aux;
    ls_symbol_t *amp_allow_other_keys;
    ls_symbol_t *amp_body;
    ls_symbol_t *amp_whole;
    ls_symbol_t *amp_environment;
} ll_marks_t;

static void init_marks(ls_state_t *L, ll_marks_t *m) {
    m->amp_optional = L->sym_ampersand_optional;
    m->amp_rest = L->sym_ampersand_rest;
    m->amp_key  = L->sym_ampersand_key;
    m->amp_aux  = L->sym_ampersand_aux;
    m->amp_allow_other_keys = L->sym_ampersand_allow_other_keys;
    m->amp_body = L->sym_ampersand_body;
    m->amp_whole= L->sym_ampersand_whole;
    m->amp_environment = L->sym_ampersand_environment;
}

static int sym_eq(ls_value_t v, ls_symbol_t *s) {
    return v.tag == LS_T_SYMBOL && (ls_symbol_t *)v.u.ptr == s;
}

static ls_value_t parse_default(ls_state_t *L, ls_value_t entry,
                                ls_symbol_t **name_out, ls_value_t *init_out,
                                ls_symbol_t **svar_out) {
    *svar_out = NULL;
    *init_out = ls_nil_v();
    if (entry.tag == LS_T_SYMBOL) {
        *name_out = (ls_symbol_t *)entry.u.ptr;
        return entry;
    }
    /* (name [init [supplied-p]]) */
    ls_value_t name_v = ls_car(entry);
    if (name_v.tag != LS_T_SYMBOL) { ls_error(L, "bad lambda-list entry"); *name_out = NULL; return entry; }
    *name_out = (ls_symbol_t *)name_v.u.ptr;
    ls_value_t rest = ls_cdr(entry);
    if (rest.tag == LS_T_CONS) {
        *init_out = ls_car(rest);
        rest = ls_cdr(rest);
        if (rest.tag == LS_T_CONS) {
            ls_value_t s = ls_car(rest);
            if (s.tag == LS_T_SYMBOL) *svar_out = (ls_symbol_t *)s.u.ptr;
        }
    }
    return entry;
}

static int bind_args(ls_state_t *L, ls_function_t *fn, int nargs, ls_value_t *args, ls_env_t *env) {
    ll_marks_t m; init_marks(L, &m);
    ls_value_t ll = fn->lambda_list;
    int phase = 0; /* 0=req, 1=opt, 2=rest, 3=key, 4=aux */
    int idx = 0;

    /* Pre-collect for &key processing later. */
    while (ll.tag == LS_T_CONS) {
        ls_value_t entry = ls_car(ll);
        ll = ls_cdr(ll);
        if (entry.tag == LS_T_SYMBOL) {
            ls_symbol_t *s = (ls_symbol_t *)entry.u.ptr;
            if (s == m.amp_optional) { phase = 1; continue; }
            if (s == m.amp_rest || s == m.amp_body) { phase = 2; continue; }
            if (s == m.amp_key)      { phase = 3; continue; }
            if (s == m.amp_aux)      { phase = 4; continue; }
            if (s == m.amp_allow_other_keys) continue;
        }
        switch (phase) {
        case 0: {
            if (idx >= nargs) { ls_arity_error(L, fn->name ? fn->name->name->chars : "lambda", nargs, fn->min_args, fn->max_args); return 0; }
            ls_symbol_t *name = (ls_symbol_t *)entry.u.ptr;
            ls_env_bind(L, env, name, args[idx++]);
            break;
        }
        case 1: {
            ls_symbol_t *name = NULL, *svar = NULL;
            ls_value_t init;
            parse_default(L, entry, &name, &init, &svar);
            if (idx < nargs) {
                ls_env_bind(L, env, name, args[idx++]);
                if (svar) ls_env_bind(L, env, svar, ls_t_v());
            } else {
                ls_value_t iv = init.tag == LS_T_NIL ? ls_nil_v() : ls_eval(L, init, env);
                ls_env_bind(L, env, name, iv);
                if (svar) ls_env_bind(L, env, svar, ls_nil_v());
            }
            break;
        }
        case 2: {
            ls_value_t rest_list = ls_nil_v();
            for (int j = nargs - 1; j >= idx; j--)
                rest_list = ls_cons(L, args[j], rest_list);
            ls_symbol_t *name = (ls_symbol_t *)entry.u.ptr;
            ls_env_bind(L, env, name, rest_list);
            idx = nargs;
            break;
        }
        case 3: {
            ls_symbol_t *name = NULL, *svar = NULL;
            ls_value_t init;
            parse_default(L, entry, &name, &init, &svar);
            if (!name) break;
            /* find :name in args[idx..nargs] */
            int found = -1;
            for (int j = idx; j + 1 < nargs; j += 2) {
                if (args[j].tag == LS_T_SYMBOL) {
                    ls_symbol_t *ks = (ls_symbol_t *)args[j].u.ptr;
                    if (ks->package == L->pkg_keyword &&
                        ks->name->len == name->name->len &&
                        memcmp(ks->name->chars, name->name->chars, name->name->len) == 0) {
                        found = j; break;
                    }
                }
            }
            if (found >= 0) {
                ls_env_bind(L, env, name, args[found + 1]);
                if (svar) ls_env_bind(L, env, svar, ls_t_v());
            } else {
                ls_value_t iv = init.tag == LS_T_NIL ? ls_nil_v() : ls_eval(L, init, env);
                ls_env_bind(L, env, name, iv);
                if (svar) ls_env_bind(L, env, svar, ls_nil_v());
            }
            break;
        }
        case 4: {
            ls_symbol_t *name = NULL, *svar = NULL;
            ls_value_t init;
            parse_default(L, entry, &name, &init, &svar);
            ls_value_t iv = init.tag == LS_T_NIL ? ls_nil_v() : ls_eval(L, init, env);
            ls_env_bind(L, env, name, iv);
            break;
        }
        }
    }
    return 1;
}

/* ---------- Special forms ---------- */

static ls_value_t eval_quote(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    (void)L; (void)env;
    return ls_car(args);
}

static ls_value_t eval_if(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t test = ls_car(args);
    ls_value_t then = ls_car(ls_cdr(args));
    ls_value_t else_ = ls_car(ls_cdr(ls_cdr(args)));
    ls_value_t tv = ls_eval(L, test, env);
    if (tv.tag != LS_T_NIL) return ls_eval(L, then, env);
    return ls_eval(L, else_, env);
}

ls_value_t ls_progn(ls_state_t *L, ls_value_t forms, ls_env_t *env) {
    ls_value_t v = ls_nil_v();
    while (forms.tag == LS_T_CONS) {
        v = ls_eval(L, ls_car(forms), env);
        forms = ls_cdr(forms);
    }
    return v;
}

static ls_value_t eval_setq(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t v = ls_nil_v();
    while (args.tag == LS_T_CONS) {
        ls_value_t sym = ls_car(args);
        args = ls_cdr(args);
        if (args.tag != LS_T_CONS) { ls_error(L, "odd args to setq"); break; }
        ls_value_t form = ls_car(args);
        args = ls_cdr(args);
        v = ls_eval(L, form, env);
        if (sym.tag != LS_T_SYMBOL) { ls_error(L, "setq target not a symbol"); break; }
        ls_symbol_t *s = (ls_symbol_t *)sym.u.ptr;
        if (!ls_env_set(env, s, v)) {
            s->value = v;
            s->sym_flags |= LS_SYM_HAS_VALUE;
        }
    }
    return v;
}

static ls_value_t eval_let(ls_state_t *L, ls_value_t args, ls_env_t *env, int starred) {
    ls_value_t binds = ls_car(args);
    ls_value_t body  = ls_cdr(args);
    ls_env_t *new_env = ls_env_new(L, env);
    ls_env_t *eval_env = starred ? new_env : env;
    while (binds.tag == LS_T_CONS) {
        ls_value_t b = ls_car(binds); binds = ls_cdr(binds);
        ls_symbol_t *s; ls_value_t v;
        if (b.tag == LS_T_SYMBOL) { s = (ls_symbol_t *)b.u.ptr; v = ls_nil_v(); }
        else {
            s = (ls_symbol_t *)ls_car(b).u.ptr;
            v = ls_eval(L, ls_car(ls_cdr(b)), eval_env);
        }
        ls_env_bind(L, new_env, s, v);
        if (starred) eval_env = new_env;
    }
    return ls_progn(L, body, new_env);
}

static ls_value_t eval_lambda(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t lambda_list = ls_car(args);
    ls_value_t body = ls_cdr(args);
    ls_value_t v = ls_make_obj(L, LS_T_FUNCTION, sizeof(ls_function_t));
    ls_function_t *f = (ls_function_t *)v.u.ptr;
    f->lambda_list = lambda_list;
    f->body = body;
    f->closure = env;
    /* compute min/max args naively */
    f->min_args = 0; f->max_args = 0;
    int phase = 0;
    ls_value_t ll = lambda_list;
    while (ll.tag == LS_T_CONS) {
        ls_value_t e = ls_car(ll); ll = ls_cdr(ll);
        if (e.tag == LS_T_SYMBOL) {
            ls_symbol_t *s = (ls_symbol_t *)e.u.ptr;
            if (s == L->sym_ampersand_optional) { phase = 1; continue; }
            if (s == L->sym_ampersand_rest || s == L->sym_ampersand_body) {
                f->fn_flags |= LS_FN_HAS_REST; f->max_args = 32767; continue;
            }
            if (s == L->sym_ampersand_key) { f->fn_flags |= LS_FN_HAS_KEY; f->max_args = 32767; continue; }
            if (s == L->sym_ampersand_aux) { phase = 4; continue; }
            if (s == L->sym_ampersand_allow_other_keys) continue;
        }
        if (phase == 0) f->min_args++;
        if (phase != 4) f->max_args++;
    }
    if (f->fn_flags & LS_FN_HAS_REST) f->max_args = 32767;
    if (f->fn_flags & LS_FN_HAS_KEY)  f->max_args = 32767;
    return v;
}

static ls_value_t eval_function(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t a = ls_car(args);
    if (a.tag == LS_T_SYMBOL) {
        ls_symbol_t *s = (ls_symbol_t *)a.u.ptr;
        /* First check the lexical environment for a flet/labels binding. */
        ls_value_t out;
        if (ls_env_lookup(env, s, &out) && ls_is_fn(out)) return out;
        if (s->sym_flags & LS_SYM_HAS_FN) return s->function;
        ls_undefined_function_error(L, s);
        return ls_nil_v();
    }
    if (a.tag == LS_T_CONS && ls_car(a).tag == LS_T_SYMBOL &&
        (ls_symbol_t *)ls_car(a).u.ptr == L->sym_lambda) {
        return eval_lambda(L, ls_cdr(a), env);
    }
    return ls_eval(L, a, env);
}

static ls_value_t eval_defun(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t name_v = ls_car(args);
    ls_value_t lambda_list = ls_car(ls_cdr(args));
    ls_value_t body = ls_cdr(ls_cdr(args));
    if (name_v.tag != LS_T_SYMBOL) { ls_error(L, "defun: name not symbol"); return ls_nil_v(); }
    ls_symbol_t *sn = (ls_symbol_t *)name_v.u.ptr;
    ls_value_t lam_args = ls_cons(L, lambda_list, body);
    ls_value_t fnv = eval_lambda(L, lam_args, env);
    ls_function_t *f = (ls_function_t *)fnv.u.ptr;
    f->name = sn;
    sn->function = fnv;
    sn->sym_flags |= LS_SYM_HAS_FN;
    return name_v;
}

static ls_value_t eval_defmacro(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t name_v = ls_car(args);
    ls_value_t lambda_list = ls_car(ls_cdr(args));
    ls_value_t body = ls_cdr(ls_cdr(args));
    ls_symbol_t *sn = (ls_symbol_t *)name_v.u.ptr;
    ls_value_t lam_args = ls_cons(L, lambda_list, body);
    ls_value_t fnv = eval_lambda(L, lam_args, env);
    ls_function_t *f = (ls_function_t *)fnv.u.ptr;
    f->name = sn;
    f->fn_flags |= LS_FN_MACRO;
    sn->function = fnv;
    sn->sym_flags |= LS_SYM_HAS_FN | LS_SYM_HAS_MACRO;
    return name_v;
}

static ls_value_t eval_defvar(ls_state_t *L, ls_value_t args, ls_env_t *env, int param) {
    ls_value_t name_v = ls_car(args);
    ls_value_t init   = ls_cdr(args).tag == LS_T_CONS ? ls_car(ls_cdr(args)) : ls_nil_v();
    ls_symbol_t *s = (ls_symbol_t *)name_v.u.ptr;
    s->sym_flags |= LS_SYM_SPECIAL;
    if (param || !(s->sym_flags & LS_SYM_HAS_VALUE)) {
        s->value = ls_eval(L, init, env);
        s->sym_flags |= LS_SYM_HAS_VALUE;
    }
    return name_v;
}

static ls_value_t eval_block(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t name = ls_car(args);
    ls_value_t body = ls_cdr(args);
    ls_escape_t e; memset(&e, 0, sizeof e);
    e.tag = name; e.kind = 0;
    e.next = L->esc_top; L->esc_top = &e;
    ls_value_t result;
    if (setjmp(e.buf) == 0) {
        result = ls_progn(L, body, env);
    } else {
        result = e.value;
    }
    L->esc_top = e.next;
    return result;
}

static ls_value_t eval_return_from(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t name = ls_car(args);
    ls_value_t val_form = ls_cdr(args).tag == LS_T_CONS ? ls_car(ls_cdr(args)) : ls_nil_v();
    ls_value_t val = ls_eval(L, val_form, env);
    /* find matching block */
    for (ls_escape_t *e = L->esc_top; e; e = e->next) {
        if (e->kind == 0 && e->tag.tag == LS_T_SYMBOL && e->tag.u.ptr == name.u.ptr) {
            e->value = val;
            longjmp(e->buf, 1);
        }
    }
    ls_error(L, "return-from: no matching block");
    return ls_nil_v();
}

static ls_value_t eval_catch(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t tag_form = ls_car(args);
    ls_value_t body = ls_cdr(args);
    ls_value_t tag = ls_eval(L, tag_form, env);
    ls_escape_t e; memset(&e, 0, sizeof e);
    e.tag = tag; e.kind = 1;
    e.next = L->esc_top; L->esc_top = &e;
    ls_value_t result;
    if (setjmp(e.buf) == 0) {
        result = ls_progn(L, body, env);
    } else {
        result = e.value;
    }
    L->esc_top = e.next;
    return result;
}

static ls_value_t eval_throw(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t tag = ls_eval(L, ls_car(args), env);
    ls_value_t val = ls_eval(L, ls_car(ls_cdr(args)), env);
    for (ls_escape_t *e = L->esc_top; e; e = e->next) {
        if (e->kind == 1 && ls_value_equal(e->tag, tag, LS_HASH_EQL)) {
            e->value = val;
            longjmp(e->buf, 1);
        }
    }
    ls_error(L, "throw: no matching catch");
    return ls_nil_v();
}

static ls_value_t eval_unwind_protect(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t prot = ls_car(args);
    ls_value_t cleanup = ls_cdr(args);
    /* This is simplified: we evaluate prot, then cleanup. If prot
     * non-locally exits, cleanup still runs because we install a
     * handler that re-throws after cleanup.  For a correct full
     * implementation we'd need to walk the escape chain. */
    ls_escape_t e; memset(&e, 0, sizeof e);
    e.kind = 99; /* sentinel, never matches */
    e.next = L->esc_top; L->esc_top = &e;
    ls_value_t result;
    int jumped = setjmp(e.buf);
    if (jumped == 0) {
        result = ls_eval(L, prot, env);
        L->esc_top = e.next;
        ls_progn(L, cleanup, env);
        return result;
    } else {
        L->esc_top = e.next;
        ls_progn(L, cleanup, env);
        /* Re-raise */
        if (L->esc_top) longjmp(L->esc_top->buf, 1);
        return ls_nil_v();
    }
}

/* ---------- return (shorthand for return-from nil) ---------- */

static ls_value_t eval_return(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    ls_value_t val_form = args.tag == LS_T_CONS ? ls_car(args) : ls_nil_v();
    ls_value_t val = ls_eval(L, val_form, env);
    /* find matching block with name NIL */
    for (ls_escape_t *e = L->esc_top; e; e = e->next) {
        if (e->kind == 0 && e->tag.tag == LS_T_NIL) {
            e->value = val;
            longjmp(e->buf, 1);
        }
    }
    ls_error(L, "return: no matching block NIL");
    return ls_nil_v();
}

/* ---------- tagbody / go ---------- */

static ls_value_t eval_tagbody(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* Tags are symbols or integers among the body forms.
     * (tagbody {tag | statement}*)
     * go transfers control to a tag via longjmp.
     */
    ls_escape_t esc;
    memset(&esc, 0, sizeof esc);
    esc.kind = 3; /* tagbody */
    esc.tag = ls_nil_v(); /* will hold the go-target tag */
    esc.next = L->esc_top;
    L->esc_top = &esc;

    /* On first entry or after a go, we scan from the matching tag. */
    ls_value_t forms = args;
    int resume;

    resume = setjmp(esc.buf);
    if (resume != 0) {
        /* esc.tag holds the symbol/integer the go jumped to.
         * Scan forms to find it. */
        ls_value_t scan = args;
        int found = 0;
        while (scan.tag == LS_T_CONS) {
            ls_value_t f = ls_car(scan);
            if ((f.tag == LS_T_SYMBOL || f.tag == LS_T_FIXNUM) &&
                ls_value_equal(f, esc.tag, LS_HASH_EQL)) {
                forms = ls_cdr(scan); /* execute after the tag */
                found = 1;
                break;
            }
            scan = ls_cdr(scan);
        }
        if (!found) {
            L->esc_top = esc.next;
            ls_error(L, "go: tag not found in tagbody");
            return ls_nil_v();
        }
    }

    /* Execute forms from current position. */
    while (forms.tag == LS_T_CONS) {
        ls_value_t f = ls_car(forms);
        forms = ls_cdr(forms);
        /* Skip tags (symbols and integers are tags, not forms). */
        if (f.tag == LS_T_SYMBOL || f.tag == LS_T_FIXNUM)
            continue;
        ls_eval(L, f, env);
    }

    L->esc_top = esc.next;
    return ls_nil_v(); /* tagbody always returns NIL */
}

static ls_value_t eval_go(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    (void)env;
    ls_value_t tag = ls_car(args);
    /* Find enclosing tagbody escape frame. */
    for (ls_escape_t *e = L->esc_top; e; e = e->next) {
        if (e->kind == 3) {
            e->tag = tag;
            longjmp(e->buf, 1);
        }
    }
    ls_error(L, "go: no enclosing tagbody");
    return ls_nil_v();
}

/* ---------- do / do* ---------- */

static ls_value_t eval_do_impl(ls_state_t *L, ls_value_t args, ls_env_t *env, int starred) {
    /* (do/do* ((var init step)...) (end-test result...) body...)
     * Wrapped in (block nil ...) to support (return ...). */
    ls_value_t var_clauses = ls_car(args);
    ls_value_t end_clause  = ls_car(ls_cdr(args));
    ls_value_t body        = ls_cdr(ls_cdr(args));

    /* Set up block NIL for (return ...) support. */
    ls_escape_t blk;
    memset(&blk, 0, sizeof blk);
    blk.tag = ls_nil_v();
    blk.kind = 0; /* block */
    blk.next = L->esc_top;
    L->esc_top = &blk;

    ls_value_t result;
    if (setjmp(blk.buf) != 0) {
        result = blk.value;
        L->esc_top = blk.next;
        return result;
    }

    /* Phase 1: bind variables with initial values. */
    ls_env_t *loop_env = ls_env_new(L, env);
    ls_env_t *init_env = starred ? loop_env : env;

    ls_value_t vc = var_clauses;
    while (vc.tag == LS_T_CONS) {
        ls_value_t clause = ls_car(vc); vc = ls_cdr(vc);
        ls_symbol_t *var;
        ls_value_t init_val = ls_nil_v();
        if (clause.tag == LS_T_SYMBOL) {
            var = (ls_symbol_t *)clause.u.ptr;
        } else {
            var = (ls_symbol_t *)ls_car(clause).u.ptr;
            ls_value_t init_rest = ls_cdr(clause);
            if (init_rest.tag == LS_T_CONS)
                init_val = ls_eval(L, ls_car(init_rest), init_env);
        }
        ls_env_bind(L, loop_env, var, init_val);
    }

    /* Phase 2: iterate. */
    ls_value_t end_test = ls_car(end_clause);
    ls_value_t result_forms = ls_cdr(end_clause);

    for (;;) {
        /* Test end condition. */
        ls_value_t tv = ls_eval(L, end_test, loop_env);
        if (tv.tag != LS_T_NIL) {
            /* End: evaluate result forms and return last value. */
            result = ls_progn(L, result_forms, loop_env);
            L->esc_top = blk.next;
            return result;
        }

        /* Execute body (with implicit tagbody around it). */
        ls_value_t b = body;
        while (b.tag == LS_T_CONS) {
            ls_value_t f = ls_car(b); b = ls_cdr(b);
            /* Skip tags in the body (tagbody-like behavior). */
            if (f.tag == LS_T_SYMBOL || f.tag == LS_T_FIXNUM)
                continue;
            ls_eval(L, f, loop_env);
        }

        /* Phase 3: step variables. */
        if (starred) {
            /* do*: step sequentially, each step sees prior updates. */
            vc = var_clauses;
            while (vc.tag == LS_T_CONS) {
                ls_value_t clause = ls_car(vc); vc = ls_cdr(vc);
                if (clause.tag == LS_T_SYMBOL) continue;
                ls_symbol_t *var = (ls_symbol_t *)ls_car(clause).u.ptr;
                ls_value_t rest = ls_cdr(clause);
                if (rest.tag == LS_T_CONS) {
                    rest = ls_cdr(rest); /* skip init, get step */
                    if (rest.tag == LS_T_CONS) {
                        ls_value_t step_val = ls_eval(L, ls_car(rest), loop_env);
                        ls_env_set(loop_env, var, step_val);
                    }
                }
            }
        } else {
            /* do: evaluate all step forms first, then update all at once. */
            ls_value_t step_vals[64];
            ls_symbol_t *step_vars[64];
            int n_steps = 0;

            vc = var_clauses;
            while (vc.tag == LS_T_CONS && n_steps < 64) {
                ls_value_t clause = ls_car(vc); vc = ls_cdr(vc);
                if (clause.tag == LS_T_SYMBOL) continue;
                ls_symbol_t *var = (ls_symbol_t *)ls_car(clause).u.ptr;
                ls_value_t rest = ls_cdr(clause);
                if (rest.tag == LS_T_CONS) {
                    rest = ls_cdr(rest); /* skip init, get step */
                    if (rest.tag == LS_T_CONS) {
                        step_vars[n_steps] = var;
                        step_vals[n_steps] = ls_eval(L, ls_car(rest), loop_env);
                        n_steps++;
                    }
                }
            }
            for (int i = 0; i < n_steps; i++)
                ls_env_set(loop_env, step_vars[i], step_vals[i]);
        }
    }
}

/* ---------- dotimes ---------- */

static ls_value_t eval_dotimes(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (dotimes (var count-form result-form) body...) */
    ls_value_t spec = ls_car(args);
    ls_value_t body = ls_cdr(args);

    ls_symbol_t *var = (ls_symbol_t *)ls_car(spec).u.ptr;
    ls_value_t count_form = ls_car(ls_cdr(spec));
    ls_value_t result_form = ls_cdr(ls_cdr(spec)).tag == LS_T_CONS
                             ? ls_car(ls_cdr(ls_cdr(spec))) : ls_nil_v();

    ls_value_t count_v = ls_eval(L, count_form, env);
    int64_t count = count_v.u.fixnum;

    /* Set up block NIL for (return ...) support. */
    ls_escape_t blk;
    memset(&blk, 0, sizeof blk);
    blk.tag = ls_nil_v();
    blk.kind = 0;
    blk.next = L->esc_top;
    L->esc_top = &blk;

    ls_value_t result;
    if (setjmp(blk.buf) != 0) {
        result = blk.value;
        L->esc_top = blk.next;
        return result;
    }

    ls_env_t *loop_env = ls_env_new(L, env);
    ls_env_bind(L, loop_env, var, ls_make_fixnum(0));

    for (int64_t i = 0; i < count; i++) {
        ls_env_set(loop_env, var, ls_make_fixnum(i));
        ls_progn(L, body, loop_env);
    }

    /* Set var to count for result form evaluation. */
    ls_env_set(loop_env, var, ls_make_fixnum(count));
    result = ls_eval(L, result_form, loop_env);
    L->esc_top = blk.next;
    return result;
}

/* ---------- dolist ---------- */

static ls_value_t eval_dolist(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (dolist (var list-form result-form) body...) */
    ls_value_t spec = ls_car(args);
    ls_value_t body = ls_cdr(args);

    ls_symbol_t *var = (ls_symbol_t *)ls_car(spec).u.ptr;
    ls_value_t list_form = ls_car(ls_cdr(spec));
    ls_value_t result_form = ls_cdr(ls_cdr(spec)).tag == LS_T_CONS
                             ? ls_car(ls_cdr(ls_cdr(spec))) : ls_nil_v();

    ls_value_t list_val = ls_eval(L, list_form, env);

    /* Set up block NIL for (return ...) support. */
    ls_escape_t blk;
    memset(&blk, 0, sizeof blk);
    blk.tag = ls_nil_v();
    blk.kind = 0;
    blk.next = L->esc_top;
    L->esc_top = &blk;

    ls_value_t result;
    if (setjmp(blk.buf) != 0) {
        result = blk.value;
        L->esc_top = blk.next;
        return result;
    }

    ls_env_t *loop_env = ls_env_new(L, env);
    ls_env_bind(L, loop_env, var, ls_nil_v());

    while (list_val.tag == LS_T_CONS) {
        ls_env_set(loop_env, var, ls_car(list_val));
        ls_progn(L, body, loop_env);
        list_val = ls_cdr(list_val);
    }

    /* Set var to NIL for result form evaluation (per spec). */
    ls_env_set(loop_env, var, ls_nil_v());
    result = ls_eval(L, result_form, loop_env);
    L->esc_top = blk.next;
    return result;
}

/* ---------- setf ---------- */

static ls_value_t eval_setf(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (setf place value [place value ...])
     * Handles: (setf var val), (setf (car x) val), (setf (cdr x) val),
     *          (setf (first x) val), (setf (rest x) val),
     *          (setf (nth n x) val), (setf (aref vec idx) val),
     *          (setf (gethash key ht) val),
     *          (setf (slot-value inst name) val),
     *          (setf (symbol-value sym) val),
     *          (setf (symbol-function sym) val).
     */
    ls_value_t v = ls_nil_v();
    while (args.tag == LS_T_CONS) {
        ls_value_t place = ls_car(args);
        args = ls_cdr(args);
        if (args.tag != LS_T_CONS) { ls_error(L, "odd args to setf"); break; }
        ls_value_t val_form = ls_car(args);
        args = ls_cdr(args);

        v = ls_eval(L, val_form, env);

        if (place.tag == LS_T_SYMBOL) {
            /* Simple variable setf = setq */
            ls_symbol_t *s = (ls_symbol_t *)place.u.ptr;
            if (!ls_env_set(env, s, v)) {
                s->value = v;
                s->sym_flags |= LS_SYM_HAS_VALUE;
            }
        } else if (place.tag == LS_T_CONS) {
            ls_value_t op = ls_car(place);
            if (op.tag != LS_T_SYMBOL) { ls_error(L, "setf: bad place"); break; }
            ls_symbol_t *place_op = (ls_symbol_t *)op.u.ptr;
            ls_value_t place_args = ls_cdr(place);

            if (place_op == L->sym_car || place_op == L->sym_first) {
                /* (setf (car x) v) => rplaca */
                ls_value_t target = ls_eval(L, ls_car(place_args), env);
                if (target.tag != LS_T_CONS) { ls_error(L, "setf car: not a cons"); break; }
                ((ls_cons_t *)target.u.ptr)->car = v;
            } else if (place_op == L->sym_cdr || place_op == L->sym_rest) {
                /* (setf (cdr x) v) => rplacd */
                ls_value_t target = ls_eval(L, ls_car(place_args), env);
                if (target.tag != LS_T_CONS) { ls_error(L, "setf cdr: not a cons"); break; }
                ((ls_cons_t *)target.u.ptr)->cdr = v;
            } else if (place_op == L->sym_nth) {
                /* (setf (nth n list) v) */
                ls_value_t idx_v = ls_eval(L, ls_car(place_args), env);
                ls_value_t lst = ls_eval(L, ls_car(ls_cdr(place_args)), env);
                int64_t n = idx_v.u.fixnum;
                for (int64_t i = 0; i < n && lst.tag == LS_T_CONS; i++)
                    lst = ls_cdr(lst);
                if (lst.tag == LS_T_CONS)
                    ((ls_cons_t *)lst.u.ptr)->car = v;
                else
                    ls_error(L, "setf nth: index out of range");
            } else if (place_op == L->sym_aref) {
                /* (setf (aref vec idx) v) */
                ls_value_t vec_v = ls_eval(L, ls_car(place_args), env);
                ls_value_t idx_v = ls_eval(L, ls_car(ls_cdr(place_args)), env);
                if (vec_v.tag != LS_T_VECTOR) { ls_error(L, "setf aref: not a vector"); break; }
                ls_vector_t *vec = (ls_vector_t *)vec_v.u.ptr;
                int64_t idx = idx_v.u.fixnum;
                if (idx < 0 || (size_t)idx >= vec->len) {
                    ls_error(L, "setf aref: index out of bounds");
                    break;
                }
                vec->data[idx] = v;
            } else if (place_op == L->sym_gethash) {
                /* (setf (gethash key ht) v) */
                ls_value_t key = ls_eval(L, ls_car(place_args), env);
                ls_value_t ht_v = ls_eval(L, ls_car(ls_cdr(place_args)), env);
                if (ht_v.tag != LS_T_HASHTABLE) { ls_error(L, "setf gethash: not a hash-table"); break; }
                ls_hashtable_t *ht = (ls_hashtable_t *)ht_v.u.ptr;
                ls_hash_put(L, ht, key, v);
            } else if (place_op == L->sym_slot_value) {
                /* (setf (slot-value inst slot-name) v) */
                ls_value_t inst_v = ls_eval(L, ls_car(place_args), env);
                ls_value_t sname = ls_eval(L, ls_car(ls_cdr(place_args)), env);
                if (inst_v.tag != LS_T_INSTANCE) { ls_error(L, "setf slot-value: not an instance"); break; }
                ls_instance_t *inst = (ls_instance_t *)inst_v.u.ptr;
                extern void ls_slot_set(ls_state_t *L, ls_instance_t *inst,
                                        ls_value_t slot_name, ls_value_t val);
                ls_slot_set(L, inst, sname, v);
            } else if (place_op == L->sym_symbol_value) {
                /* (setf (symbol-value sym) v) */
                ls_value_t sym_v = ls_eval(L, ls_car(place_args), env);
                if (sym_v.tag != LS_T_SYMBOL) { ls_error(L, "setf symbol-value: not a symbol"); break; }
                ls_symbol_t *s = (ls_symbol_t *)sym_v.u.ptr;
                s->value = v;
                s->sym_flags |= LS_SYM_HAS_VALUE;
            } else if (place_op == L->sym_symbol_function) {
                /* (setf (symbol-function sym) v) */
                ls_value_t sym_v = ls_eval(L, ls_car(place_args), env);
                if (sym_v.tag != LS_T_SYMBOL) { ls_error(L, "setf symbol-function: not a symbol"); break; }
                ls_symbol_t *s = (ls_symbol_t *)sym_v.u.ptr;
                s->function = v;
                s->sym_flags |= LS_SYM_HAS_FN;
            } else {
                /* Fallback: look up *setf-expanders* alist for this accessor.
                 * The variable is defined in the user package (where stdlib
                 * core.lisp runs), so look it up via the current package's
                 * search path. */
                int found_es;
                ls_value_t expanders_sym = ls_intern_sym(L, L->pkg_cl_user, "*SETF-EXPANDERS*", 16, &found_es);
                ls_symbol_t *es = (ls_symbol_t *)expanders_sym.u.ptr;
                int matched = 0;
                if (es->sym_flags & LS_SYM_HAS_VALUE) {
                    ls_value_t alist = es->value;
                    while (alist.tag == LS_T_CONS) {
                        ls_value_t entry = ls_car(alist);
                        if (entry.tag == LS_T_CONS) {
                            ls_value_t key = ls_car(entry);
                            if (key.tag == LS_T_SYMBOL && key.u.ptr == op.u.ptr) {
                                ls_value_t expander_fn = ls_cdr(entry);
                                /* Call (expander-fn place-args new-val); place-args is the
                                 * unevaluated arg list. The expander returns a form to evaluate. */
                                ls_value_t apply_args[2];
                                apply_args[0] = place_args; /* unevaluated */
                                apply_args[1] = v;          /* the new value */
                                ls_value_t expanded = ls_apply(L, expander_fn, 2, apply_args);
                                ls_eval(L, expanded, env);
                                matched = 1;
                                break;
                            }
                        }
                        alist = ls_cdr(alist);
                    }
                }
                if (!matched) {
                    /* Last resort: try (setf-ACCESSOR arg1 ... argn newval). */
                    char setf_name[256];
                    snprintf(setf_name, sizeof setf_name, "SETF-%s", place_op->name->chars);
                    ls_value_t setter_sym = ls_intern(L, "COMMON-LISP", setf_name);
                    ls_symbol_t *ss = (ls_symbol_t *)setter_sym.u.ptr;
                    if (ss->function.tag != LS_T_NIL) {
                        /* Evaluate place_args, then call (setter args... v) */
                        ls_value_t arr[32]; int an = 0;
                        ls_value_t pa = place_args;
                        while (pa.tag == LS_T_CONS && an < 31) {
                            arr[an++] = ls_eval(L, ls_car(pa), env);
                            pa = ls_cdr(pa);
                        }
                        arr[an++] = v;
                        ls_apply(L, ss->function, an, arr);
                    } else {
                        ls_error(L, "setf: unsupported place: (%s ...)", place_op->name->chars);
                        break;
                    }
                }
            }
        } else {
            ls_error(L, "setf: invalid place form");
            break;
        }
    }
    return v;
}

/* ---------- case ---------- */

static ls_value_t eval_case(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (case keyform (key body)... [(otherwise body) | (t body)]) */
    ls_value_t keyform = ls_car(args);
    ls_value_t clauses = ls_cdr(args);
    ls_value_t key = ls_eval(L, keyform, env);

    while (clauses.tag == LS_T_CONS) {
        ls_value_t clause = ls_car(clauses);
        clauses = ls_cdr(clauses);
        ls_value_t keys = ls_car(clause);
        ls_value_t body = ls_cdr(clause);

        /* Check for otherwise / t. */
        if (keys.tag == LS_T_SYMBOL) {
            ls_symbol_t *ks = (ls_symbol_t *)keys.u.ptr;
            if (ks == L->sym_otherwise || ks == L->sym_t) {
                return ls_progn(L, body, env);
            }
        }

        /* keys can be an atom (single key) or a list of keys. */
        if (keys.tag == LS_T_CONS) {
            /* List of keys: check each with eql. */
            ls_value_t kl = keys;
            while (kl.tag == LS_T_CONS) {
                if (ls_value_equal(key, ls_car(kl), LS_HASH_EQL))
                    return ls_progn(L, body, env);
                kl = ls_cdr(kl);
            }
        } else {
            /* Single key (atom): compare with eql. */
            if (ls_value_equal(key, keys, LS_HASH_EQL))
                return ls_progn(L, body, env);
        }
    }
    return ls_nil_v();
}

/* ---------- typecase ---------- */

static ls_value_t eval_typecase(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (typecase keyform (type body)... [(otherwise body) | (t body)]) */
    ls_value_t keyform = ls_car(args);
    ls_value_t clauses = ls_cdr(args);
    ls_value_t key = ls_eval(L, keyform, env);

    /* Get the class of the key value. */
    extern ls_value_t ls_class_of(ls_state_t *L, ls_value_t v);
    ls_value_t key_class_v = ls_class_of(L, key);
    ls_class_t *key_class = (ls_class_t *)key_class_v.u.ptr;

    while (clauses.tag == LS_T_CONS) {
        ls_value_t clause = ls_car(clauses);
        clauses = ls_cdr(clauses);
        ls_value_t type_spec = ls_car(clause);
        ls_value_t body = ls_cdr(clause);

        /* Check for otherwise / t. */
        if (type_spec.tag == LS_T_SYMBOL) {
            ls_symbol_t *ts = (ls_symbol_t *)type_spec.u.ptr;
            if (ts == L->sym_otherwise || ts == L->sym_t)
                return ls_progn(L, body, env);

            /* Look up the class for the type name. */
            if (ts->sym_flags & LS_SYM_HAS_VALUE) {
                ls_value_t cv = ts->value;
                if (cv.tag == LS_T_CLASS) {
                    ls_class_t *type_class = (ls_class_t *)cv.u.ptr;
                    /* Check if key_class is a subtype via CPL. */
                    ls_value_t cpl = key_class->precedence_list;
                    while (cpl.tag == LS_T_CONS) {
                        if (ls_car(cpl).u.ptr == (void *)type_class)
                            return ls_progn(L, body, env);
                        cpl = ls_cdr(cpl);
                    }
                }
            }
        } else if (type_spec.tag == LS_T_CLASS) {
            ls_class_t *type_class = (ls_class_t *)type_spec.u.ptr;
            ls_value_t cpl = key_class->precedence_list;
            while (cpl.tag == LS_T_CONS) {
                if (ls_car(cpl).u.ptr == (void *)type_class)
                    return ls_progn(L, body, env);
                cpl = ls_cdr(cpl);
            }
        }
    }
    return ls_nil_v();
}

/* ---------- multiple-value-bind ---------- */

static ls_value_t eval_multiple_value_bind(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (multiple-value-bind (var1 var2 ...) values-form body...) */
    ls_value_t vars = ls_car(args);
    ls_value_t values_form = ls_car(ls_cdr(args));
    ls_value_t body = ls_cdr(ls_cdr(args));

    /* Evaluate the values-form.  The primary value is the return value;
     * additional values are in L->mv. */
    ls_value_t primary = ls_eval(L, values_form, env);

    /* L->mv.v[0] = primary, L->mv.n = number of values */
    if (L->mv.n < 1) {
        L->mv.n = 1;
        L->mv.v[0] = primary;
    }

    ls_env_t *new_env = ls_env_new(L, env);
    int idx = 0;
    while (vars.tag == LS_T_CONS) {
        ls_symbol_t *var = (ls_symbol_t *)ls_car(vars).u.ptr;
        ls_value_t val = (idx < L->mv.n) ? L->mv.v[idx] : ls_nil_v();
        ls_env_bind(L, new_env, var, val);
        idx++;
        vars = ls_cdr(vars);
    }

    return ls_progn(L, body, new_env);
}

/* ---------- prog / prog* ---------- */

static ls_value_t eval_prog(ls_state_t *L, ls_value_t args, ls_env_t *env, int starred) {
    /* (prog/prog* ((var init)...) {declaration}* {tag | statement}*)
     * = let/let* bindings + block nil + tagbody.
     */
    ls_value_t bindings = ls_car(args);
    ls_value_t body = ls_cdr(args);

    /* Skip declarations at the start of body. */
    ls_value_t actual_body = body;
    while (actual_body.tag == LS_T_CONS) {
        ls_value_t f = ls_car(actual_body);
        if (f.tag == LS_T_CONS && ls_car(f).tag == LS_T_SYMBOL &&
            (ls_symbol_t *)ls_car(f).u.ptr == L->sym_declare)
            actual_body = ls_cdr(actual_body);
        else
            break;
    }

    /* Phase 1: bind variables (let or let*). */
    ls_env_t *prog_env = ls_env_new(L, env);
    ls_env_t *init_env = starred ? prog_env : env;
    ls_value_t bl = bindings;
    while (bl.tag == LS_T_CONS) {
        ls_value_t b = ls_car(bl); bl = ls_cdr(bl);
        ls_symbol_t *s; ls_value_t v;
        if (b.tag == LS_T_SYMBOL) { s = (ls_symbol_t *)b.u.ptr; v = ls_nil_v(); }
        else {
            s = (ls_symbol_t *)ls_car(b).u.ptr;
            v = ls_eval(L, ls_car(ls_cdr(b)), init_env);
        }
        ls_env_bind(L, prog_env, s, v);
    }

    /* Phase 2: establish block nil. */
    ls_escape_t blk;
    memset(&blk, 0, sizeof blk);
    blk.tag = ls_nil_v();
    blk.kind = 0; /* block */
    blk.next = L->esc_top;
    L->esc_top = &blk;

    ls_value_t result;
    if (setjmp(blk.buf) != 0) {
        result = blk.value;
        L->esc_top = blk.next;
        return result;
    }

    /* Phase 3: execute body as a tagbody.
     * We reuse the tagbody logic inline. */
    ls_escape_t tesc;
    memset(&tesc, 0, sizeof tesc);
    tesc.kind = 3; /* tagbody */
    tesc.tag = ls_nil_v();
    tesc.next = L->esc_top;
    L->esc_top = &tesc;

    ls_value_t forms = actual_body;
    int resume;

    resume = setjmp(tesc.buf);
    if (resume != 0) {
        /* Scan actual_body for the tag. */
        ls_value_t scan = actual_body;
        int found = 0;
        while (scan.tag == LS_T_CONS) {
            ls_value_t f = ls_car(scan);
            if ((f.tag == LS_T_SYMBOL || f.tag == LS_T_FIXNUM) &&
                ls_value_equal(f, tesc.tag, LS_HASH_EQL)) {
                forms = ls_cdr(scan);
                found = 1;
                break;
            }
            scan = ls_cdr(scan);
        }
        if (!found) {
            L->esc_top = tesc.next;
            /* Also pop block. */
            L->esc_top = blk.next;
            ls_error(L, "go: tag not found in prog");
            return ls_nil_v();
        }
    }

    while (forms.tag == LS_T_CONS) {
        ls_value_t f = ls_car(forms); forms = ls_cdr(forms);
        if (f.tag == LS_T_SYMBOL || f.tag == LS_T_FIXNUM)
            continue;
        ls_eval(L, f, prog_env);
    }

    L->esc_top = tesc.next;  /* pop tagbody */
    L->esc_top = blk.next;   /* pop block */
    return ls_nil_v(); /* prog returns NIL if no (return ...) was executed */
}

/* ---------- defclass / defgeneric / defmethod (special form dispatch) ---------- */

static ls_value_t eval_defclass(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (defclass name (supers...) ((slot-name :initarg :name ...)...))
     * We parse the special form and call %defclass with resolved data. */
    ls_value_t name_v = ls_car(args);
    ls_value_t supers_form = ls_car(ls_cdr(args));
    ls_value_t slot_specs = ls_cdr(ls_cdr(args)).tag == LS_T_CONS
                            ? ls_car(ls_cdr(ls_cdr(args))) : ls_nil_v();

    if (name_v.tag != LS_T_SYMBOL) {
        ls_error(L, "defclass: name must be a symbol");
        return ls_nil_v();
    }

    /* Build the slot-names list from slot-specs.
     * Each spec can be a symbol or (slot-name ...). */
    ls_value_t slot_names = ls_nil_v();
    ls_value_t slot_tail = ls_nil_v();
    ls_value_t ss = slot_specs;
    while (ss.tag == LS_T_CONS) {
        ls_value_t spec = ls_car(ss); ss = ls_cdr(ss);
        ls_value_t sname;
        if (spec.tag == LS_T_SYMBOL)
            sname = spec;
        else if (spec.tag == LS_T_CONS)
            sname = ls_car(spec);
        else
            continue;
        ls_value_t cell = ls_cons(L, sname, ls_nil_v());
        if (slot_names.tag == LS_T_NIL) slot_names = slot_tail = cell;
        else { ((ls_cons_t *)slot_tail.u.ptr)->cdr = cell; slot_tail = cell; }
    }

    /* Call %defclass(name, supers-list, slot-names-list). */
    ls_value_t call_args[3];
    call_args[0] = name_v;
    call_args[1] = supers_form;
    call_args[2] = slot_names;

    /* Look up %defclass. */
    ls_symbol_t *dc = (ls_symbol_t *)ls_intern(L, "COMMON-LISP", "%DEFCLASS").u.ptr;
    if (dc->sym_flags & LS_SYM_HAS_FN)
        return ls_apply(L, dc->function, 3, call_args);

    ls_error(L, "defclass: %%defclass not available");
    return ls_nil_v();
}

static ls_value_t eval_defgeneric(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (defgeneric name (lambda-list) [:documentation ...]) */
    ls_value_t name_v = ls_car(args);
    ls_value_t lambda_list = ls_car(ls_cdr(args));

    if (name_v.tag != LS_T_SYMBOL) {
        ls_error(L, "defgeneric: name must be a symbol");
        return ls_nil_v();
    }

    ls_value_t call_args[2];
    call_args[0] = name_v;
    call_args[1] = lambda_list;

    ls_symbol_t *dg = (ls_symbol_t *)ls_intern(L, "COMMON-LISP", "%DEFGENERIC").u.ptr;
    if (dg->sym_flags & LS_SYM_HAS_FN)
        return ls_apply(L, dg->function, 2, call_args);

    ls_error(L, "defgeneric: %%defgeneric not available");
    return ls_nil_v();
}

static ls_value_t eval_defmethod(ls_state_t *L, ls_value_t args, ls_env_t *env) {
    /* (defmethod name [qualifier] ((param specializer) ...) body...)
     *
     * We need to:
     * 1. Parse the name.
     * 2. Check for optional qualifier (:before :after :around).
     * 3. Parse the specialized lambda list to extract specializers.
     * 4. Build a lambda with the stripped lambda list.
     * 5. Call %defmethod(name, specializers, qualifiers, lambda).
     */
    ls_value_t name_v = ls_car(args);
    args = ls_cdr(args);

    if (name_v.tag != LS_T_SYMBOL) {
        ls_error(L, "defmethod: name must be a symbol");
        return ls_nil_v();
    }

    /* Check for qualifier keyword (:before, :after, :around). */
    ls_value_t qualifiers = ls_nil_v();
    if (args.tag == LS_T_CONS) {
        ls_value_t maybe_qual = ls_car(args);
        if (maybe_qual.tag == LS_T_SYMBOL) {
            ls_symbol_t *mqs = (ls_symbol_t *)maybe_qual.u.ptr;
            if (mqs->package == L->pkg_keyword) {
                /* It's a keyword qualifier. */
                qualifiers = ls_cons(L, maybe_qual, ls_nil_v());
                args = ls_cdr(args);
            }
        }
    }

    /* Next should be the specialized lambda list. */
    ls_value_t spec_ll = ls_car(args);
    ls_value_t body = ls_cdr(args);

    /* Parse specialized lambda list: each param can be a symbol or
     * (param-name class-name). Build both the plain lambda list
     * and the specializer list. */
    ls_value_t plain_ll = ls_nil_v(), plain_tail = ls_nil_v();
    ls_value_t specializers = ls_nil_v(), spec_tail = ls_nil_v();

    ls_value_t sl = spec_ll;
    while (sl.tag == LS_T_CONS) {
        ls_value_t entry = ls_car(sl); sl = ls_cdr(sl);

        /* Check for &-keywords: pass them through to the plain lambda list. */
        if (entry.tag == LS_T_SYMBOL) {
            ls_symbol_t *es = (ls_symbol_t *)entry.u.ptr;
            if (es == L->sym_ampersand_rest || es == L->sym_ampersand_optional ||
                es == L->sym_ampersand_key || es == L->sym_ampersand_aux ||
                es == L->sym_ampersand_body || es == L->sym_ampersand_allow_other_keys) {
                /* Append rest of sl as-is to plain_ll. */
                ls_value_t cell = ls_cons(L, entry, sl);
                if (plain_ll.tag == LS_T_NIL) plain_ll = cell;
                else ((ls_cons_t *)plain_tail.u.ptr)->cdr = cell;
                break;
            }
        }

        ls_value_t param_name;
        ls_value_t specializer;
        if (entry.tag == LS_T_CONS) {
            /* (param-name class-name) */
            param_name = ls_car(entry);
            specializer = ls_car(ls_cdr(entry));
        } else {
            /* Just a symbol -- specializer is T. */
            param_name = entry;
            specializer = ls_wrap(LS_T_SYMBOL, L->sym_t);
        }

        ls_value_t pcell = ls_cons(L, param_name, ls_nil_v());
        if (plain_ll.tag == LS_T_NIL) plain_ll = plain_tail = pcell;
        else { ((ls_cons_t *)plain_tail.u.ptr)->cdr = pcell; plain_tail = pcell; }

        ls_value_t scell = ls_cons(L, specializer, ls_nil_v());
        if (specializers.tag == LS_T_NIL) specializers = spec_tail = scell;
        else { ((ls_cons_t *)spec_tail.u.ptr)->cdr = scell; spec_tail = scell; }
    }

    /* Build the lambda from the plain lambda list and body. */
    ls_value_t lam_args = ls_cons(L, plain_ll, body);
    ls_value_t lambda_v = eval_lambda(L, lam_args, env);

    /* Call %defmethod(generic-name, specializers, qualifiers, lambda). */
    ls_value_t call_args[4];
    call_args[0] = name_v;
    call_args[1] = specializers;
    call_args[2] = qualifiers;
    call_args[3] = lambda_v;

    ls_symbol_t *dm = (ls_symbol_t *)ls_intern(L, "COMMON-LISP", "%DEFMETHOD").u.ptr;
    if (dm->sym_flags & LS_SYM_HAS_FN)
        return ls_apply(L, dm->function, 4, call_args);

    ls_error(L, "defmethod: %%defmethod not available");
    return ls_nil_v();
}

/* ---------- Macro expansion ---------- */

static ls_value_t apply_macro(ls_state_t *L, ls_function_t *m, ls_value_t form, ls_env_t *env) {
    /* macro arguments are the cdr of form (unevaluated) */
    ls_value_t args = ls_cdr(form);
    int n = (int)ls_list_length(args);
    ls_value_t arr[64]; if (n > 64) n = 64;
    int i = 0;
    while (args.tag == LS_T_CONS && i < 64) { arr[i++] = ls_car(args); args = ls_cdr(args); }
    ls_env_t *new_env = ls_env_new(L, m->closure);
    ls_function_t saved = *m;
    saved.fn_flags &= ~LS_FN_MACRO;
    bind_args(L, &saved, n, arr, new_env);
    ls_value_t expansion = ls_progn(L, m->body, new_env);
    return ls_eval(L, expansion, env);
}

ls_value_t ls_macroexpand(ls_state_t *L, ls_value_t form, ls_env_t *env) {
    while (form.tag == LS_T_CONS) {
        ls_value_t hd = ls_car(form);
        if (hd.tag != LS_T_SYMBOL) break;
        ls_symbol_t *s = (ls_symbol_t *)hd.u.ptr;
        if (!(s->sym_flags & LS_SYM_HAS_MACRO)) break;
        ls_function_t *m = ls_function_p(s->function);
        if (!m) break;
        /* run macro and continue expanding */
        ls_value_t args = ls_cdr(form);
        int n = (int)ls_list_length(args);
        ls_value_t arr[64]; if (n > 64) n = 64;
        int i = 0;
        while (args.tag == LS_T_CONS && i < 64) { arr[i++] = ls_car(args); args = ls_cdr(args); }
        ls_env_t *ne = ls_env_new(L, m->closure);
        ls_function_t saved = *m;
        saved.fn_flags &= ~LS_FN_MACRO;
        bind_args(L, &saved, n, arr, ne);
        form = ls_progn(L, m->body, ne);
        (void)env;
    }
    return form;
}

/* ---------- Quasiquote expansion ---------- */
static ls_value_t expand_qq(ls_state_t *L, ls_value_t form, ls_env_t *env);

static ls_value_t qq_list(ls_state_t *L, ls_value_t form, ls_env_t *env) {
    if (form.tag != LS_T_CONS) return expand_qq(L, form, env);
    ls_value_t hd = ls_car(form);
    if (hd.tag == LS_T_SYMBOL) {
        ls_symbol_t *s = (ls_symbol_t *)hd.u.ptr;
        if (s == L->sym_unquote) return ls_eval(L, ls_car(ls_cdr(form)), env);
    }
    /* Walk the list, splicing where needed. */
    ls_value_t out = ls_nil_v(), tail = ls_nil_v();
    while (form.tag == LS_T_CONS) {
        ls_value_t x = ls_car(form);
        form = ls_cdr(form);
        int spliced = 0;
        if (x.tag == LS_T_CONS && ls_car(x).tag == LS_T_SYMBOL &&
            (ls_symbol_t *)ls_car(x).u.ptr == L->sym_unquote_splicing) {
            ls_value_t spl = ls_eval(L, ls_car(ls_cdr(x)), env);
            while (spl.tag == LS_T_CONS) {
                ls_value_t cell = ls_cons(L, ls_car(spl), ls_nil_v());
                if (out.tag == LS_T_NIL) out = tail = cell;
                else { ((ls_cons_t*)tail.u.ptr)->cdr = cell; tail = cell; }
                spl = ls_cdr(spl);
            }
            spliced = 1;
        }
        if (!spliced) {
            ls_value_t v = qq_list(L, x, env);
            ls_value_t cell = ls_cons(L, v, ls_nil_v());
            if (out.tag == LS_T_NIL) out = tail = cell;
            else { ((ls_cons_t*)tail.u.ptr)->cdr = cell; tail = cell; }
        }
    }
    if (form.tag != LS_T_NIL) {
        if (tail.tag == LS_T_CONS) ((ls_cons_t*)tail.u.ptr)->cdr = expand_qq(L, form, env);
        else out = expand_qq(L, form, env);
    }
    return out;
}

static ls_value_t expand_qq(ls_state_t *L, ls_value_t form, ls_env_t *env) {
    if (form.tag != LS_T_CONS) return form;
    return qq_list(L, form, env);
}

/* ---------- The evaluator ---------- */

static ls_value_t apply_function(ls_state_t *L, ls_function_t *f, int n, ls_value_t *args) {
    ls_env_t *env = ls_env_new(L, f->closure);
    if (!bind_args(L, f, n, args, env)) return ls_nil_v();
    return ls_progn(L, f->body, env);
}

ls_value_t ls_apply(ls_state_t *L, ls_value_t fn, int nargs, ls_value_t *args) {
    L->mv.n = 1;
    switch (fn.tag) {
    case LS_T_NATIVE: {
        ls_native_t *n = (ls_native_t *)fn.u.ptr;
        if (n->min_args >= 0 && nargs < n->min_args) {
            ls_arity_error(L, n->name, nargs, n->min_args, n->max_args);
            return ls_nil_v();
        }
        if (n->max_args >= 0 && nargs > n->max_args) {
            ls_arity_error(L, n->name, nargs, n->min_args, n->max_args);
            return ls_nil_v();
        }
        ls_value_t r = n->fn(L, nargs, args);
        if (L->mv.n < 1) { L->mv.n = 1; L->mv.v[0] = r; }
        return r;
    }
    case LS_T_FUNCTION:
        return apply_function(L, (ls_function_t *)fn.u.ptr, nargs, args);
    case LS_T_BYTECODE: {
        extern ls_value_t ls_vm_run(ls_state_t *L, ls_bytecode_fn_t *f, int n, ls_value_t *a);
        ls_bytecode_fn_t *bf = (ls_bytecode_fn_t *)fn.u.ptr;
        if (bf->jit_entry) {
            typedef ls_value_t (*jit_fn)(ls_state_t *, int, ls_value_t *);
            return ((jit_fn)bf->jit_entry)(L, nargs, args);
        }
        return ls_vm_run(L, bf, nargs, args);
    }
    case LS_T_GENERIC: {
        extern ls_value_t ls_dispatch_generic(ls_state_t *L, ls_generic_t *g, int n, ls_value_t *a);
        return ls_dispatch_generic(L, (ls_generic_t *)fn.u.ptr, nargs, args);
    }
    case LS_T_SYMBOL: {
        ls_symbol_t *s = (ls_symbol_t *)fn.u.ptr;
        if (s->sym_flags & LS_SYM_HAS_FN) return ls_apply(L, s->function, nargs, args);
        ls_undefined_function_error(L, s);
        return ls_nil_v();
    }
    default:
        ls_error(L, "not callable");
        return ls_nil_v();
    }
}

ls_value_t ls_eval(ls_state_t *L, ls_value_t form, ls_env_t *env) {
    ls_value_t out;
    /* Self-evaluating */
    switch (form.tag) {
    case LS_T_NIL: case LS_T_T: case LS_T_FIXNUM: case LS_T_FLONUM:
    case LS_T_CHAR: case LS_T_STRING: case LS_T_VECTOR:
    case LS_T_HASHTABLE:
        return form;
    case LS_T_SYMBOL: {
        ls_symbol_t *s = (ls_symbol_t *)form.u.ptr;
        if (s->package == L->pkg_keyword) return form;
        if (s == L->sym_t) return ls_t_v();
        if (ls_env_lookup(env, s, &out)) return out;
        if (s->sym_flags & LS_SYM_HAS_VALUE) return s->value;
        ls_unbound_variable_error(L, s);
        return ls_nil_v();
    }
    case LS_T_CONS: break;
    default:
        return form;
    }

    ls_value_t hd = ls_car(form);
    ls_value_t args = ls_cdr(form);

    if (hd.tag == LS_T_SYMBOL) {
        ls_symbol_t *op = (ls_symbol_t *)hd.u.ptr;

        /* Special forms first. */
        if (op == L->sym_quote)   return eval_quote(L, args, env);
        if (op == L->sym_if)      return eval_if(L, args, env);
        if (op == L->sym_progn)   return ls_progn(L, args, env);
        if (op == L->sym_setq)    return eval_setq(L, args, env);
        if (op == L->sym_let)     return eval_let(L, args, env, 0);
        if (op == L->sym_letstar) return eval_let(L, args, env, 1);
        if (op == L->sym_lambda)  return eval_lambda(L, args, env);
        if (op == L->sym_function)return eval_function(L, args, env);
        if (op == L->sym_defun)   return eval_defun(L, args, env);
        if (op == L->sym_defmacro)return eval_defmacro(L, args, env);
        if (op == L->sym_defvar)  return eval_defvar(L, args, env, 0);
        if (op == L->sym_defparameter) return eval_defvar(L, args, env, 1);
        if (op == L->sym_defconstant)  return eval_defvar(L, args, env, 1);
        if (op == L->sym_block)   return eval_block(L, args, env);
        if (op == L->sym_return_from) return eval_return_from(L, args, env);
        if (op == L->sym_catch)   return eval_catch(L, args, env);
        if (op == L->sym_throw)   return eval_throw(L, args, env);
        if (op == L->sym_unwind_protect) return eval_unwind_protect(L, args, env);
        if (op == L->sym_quasiquote) return expand_qq(L, ls_car(args), env);
        if (op == L->sym_and) {
            ls_value_t v = ls_t_v();
            while (args.tag == LS_T_CONS) {
                v = ls_eval(L, ls_car(args), env);
                if (v.tag == LS_T_NIL) return v;
                args = ls_cdr(args);
            }
            return v;
        }
        if (op == L->sym_or) {
            while (args.tag == LS_T_CONS) {
                ls_value_t v = ls_eval(L, ls_car(args), env);
                if (v.tag != LS_T_NIL) return v;
                args = ls_cdr(args);
            }
            return ls_nil_v();
        }
        if (op == L->sym_when) {
            ls_value_t test = ls_eval(L, ls_car(args), env);
            if (test.tag != LS_T_NIL) return ls_progn(L, ls_cdr(args), env);
            return ls_nil_v();
        }
        if (op == L->sym_unless) {
            ls_value_t test = ls_eval(L, ls_car(args), env);
            if (test.tag == LS_T_NIL) return ls_progn(L, ls_cdr(args), env);
            return ls_nil_v();
        }
        if (op == L->sym_cond) {
            while (args.tag == LS_T_CONS) {
                ls_value_t clause = ls_car(args); args = ls_cdr(args);
                ls_value_t test = ls_eval(L, ls_car(clause), env);
                if (test.tag != LS_T_NIL) {
                    if (ls_cdr(clause).tag == LS_T_NIL) return test;
                    return ls_progn(L, ls_cdr(clause), env);
                }
            }
            return ls_nil_v();
        }
        if (op == L->sym_eval_when) {
            /* simplified: always evaluate */
            ls_value_t situation = ls_car(args); (void)situation;
            return ls_progn(L, ls_cdr(args), env);
        }
        if (op == L->sym_locally) return ls_progn(L, args, env);
        if (op == L->sym_the) {
            /* (the type form) -- ignore type assertion */
            return ls_eval(L, ls_car(ls_cdr(args)), env);
        }
        if (op == L->sym_declare) return ls_nil_v();
        if (op == L->sym_flet || op == L->sym_labels) {
            ls_value_t binds = ls_car(args);
            ls_value_t body = ls_cdr(args);
            ls_env_t *ne = ls_env_new(L, env);
            ls_env_t *def_env = (op == L->sym_labels) ? ne : env;
            while (binds.tag == LS_T_CONS) {
                ls_value_t b = ls_car(binds); binds = ls_cdr(binds);
                ls_symbol_t *name = (ls_symbol_t *)ls_car(b).u.ptr;
                ls_value_t lam = eval_lambda(L, ls_cdr(b), def_env);
                ((ls_function_t*)lam.u.ptr)->name = name;
                ls_env_bind(L, ne, name, lam);
            }
            /* shadow function slot via env binding only */
            return ls_progn(L, body, ne);
        }
        if (op == L->sym_return)  return eval_return(L, args, env);
        if (op == L->sym_tagbody)return eval_tagbody(L, args, env);
        if (op == L->sym_go)     return eval_go(L, args, env);
        if (op == L->sym_do)     return eval_do_impl(L, args, env, 0);
        if (op == L->sym_dostar) return eval_do_impl(L, args, env, 1);
        if (op == L->sym_dotimes)return eval_dotimes(L, args, env);
        if (op == L->sym_dolist) return eval_dolist(L, args, env);
        if (op == L->sym_setf)   return eval_setf(L, args, env);
        if (op == L->sym_case)   return eval_case(L, args, env);
        if (op == L->sym_typecase) return eval_typecase(L, args, env);
        if (op == L->sym_multiple_value_bind) return eval_multiple_value_bind(L, args, env);
        if (op == L->sym_prog)   return eval_prog(L, args, env, 0);
        if (op == L->sym_progstar) return eval_prog(L, args, env, 1);
        if (op == L->sym_defclass)   return eval_defclass(L, args, env);
        if (op == L->sym_defgeneric) return eval_defgeneric(L, args, env);
        if (op == L->sym_defmethod)  return eval_defmethod(L, args, env);

        /* Macro? */
        if (op->sym_flags & LS_SYM_HAS_MACRO) {
            return apply_macro(L, ls_function_p(op->function), form, env);
        }

        /* Function call. */
        if (op->sym_flags & LS_SYM_HAS_FN) {
            ls_value_t arr[32]; int n = 0;
            while (args.tag == LS_T_CONS && n < 32) {
                arr[n++] = ls_eval(L, ls_car(args), env);
                args = ls_cdr(args);
            }
            return ls_apply(L, op->function, n, arr);
        }
        /* check env for shadowed function */
        if (ls_env_lookup(env, op, &out) && ls_is_fn(out)) {
            ls_value_t arr[32]; int n = 0;
            while (args.tag == LS_T_CONS && n < 32) {
                arr[n++] = ls_eval(L, ls_car(args), env);
                args = ls_cdr(args);
            }
            return ls_apply(L, out, n, arr);
        }
        ls_undefined_function_error(L, op);
        return ls_nil_v();
    }

    /* ((lambda ...) ...) etc. */
    if (hd.tag == LS_T_CONS) {
        ls_value_t fn = ls_eval(L, hd, env);
        ls_value_t arr[32]; int n = 0;
        while (args.tag == LS_T_CONS && n < 32) {
            arr[n++] = ls_eval(L, ls_car(args), env);
            args = ls_cdr(args);
        }
        return ls_apply(L, fn, n, arr);
    }

    ls_error(L, "cannot evaluate");
    return ls_nil_v();
}
/*** End: lseval.c ***/

/*** Begin: lsbuiltins.c ***/
/* lsbuiltins.c -- Common Lisp builtin functions: arithmetic, cons,
 * sequence, string, hashtable, I/O, type predicates, control flow,
 * format, and system utilities.
 *
 * Each builtin is a static C function with signature:
 *   ls_value_t fn(ls_state_t *L, int nargs, ls_value_t *args);
 *
 * Registration happens in ls_register_builtins() called from ls_new(). */

/* ============================================================
 *  Helpers
 * ============================================================ */
#define A(i) a[i]
#define ARGN(name, cnt) if (n < cnt) { ls_arity_error(L, name, n, cnt, cnt); return ls_nil_v(); }

/* Parse common sequence keyword args :test, :test-not, :key starting from index `start`. */
typedef struct { ls_value_t test_fn; ls_value_t key_fn; int test_not; int from_end; int start; int end; } seqkw_t;
static void parse_seqkw(int n, ls_value_t *a, int start, seqkw_t *k) {
    k->test_fn = ls_nil_v(); k->key_fn = ls_nil_v();
    k->test_not = 0; k->from_end = 0; k->start = 0; k->end = -1;
    for (int i = start; i + 1 < n; i += 2) {
        ls_symbol_t *kw = ls_symbol_p(a[i]);
        if (!kw) continue;
        const char *kn = kw->name->chars;
        if      (!strcmp(kn,"TEST"))      k->test_fn  = a[i+1];
        else if (!strcmp(kn,"TEST-NOT"))  { k->test_fn = a[i+1]; k->test_not = 1; }
        else if (!strcmp(kn,"KEY"))       k->key_fn   = a[i+1];
        else if (!strcmp(kn,"FROM-END"))  k->from_end = (a[i+1].tag != LS_T_NIL);
        else if (!strcmp(kn,"START") && a[i+1].tag == LS_T_FIXNUM) k->start = (int)a[i+1].u.fixnum;
        else if (!strcmp(kn,"END")   && a[i+1].tag == LS_T_FIXNUM) k->end   = (int)a[i+1].u.fixnum;
    }
}
static int seqkw_match(ls_state_t *L, seqkw_t *k, ls_value_t item, ls_value_t elem) {
    ls_value_t probe = elem;
    if (k->key_fn.tag != LS_T_NIL) probe = ls_apply(L, k->key_fn, 1, &elem);
    int matched;
    if (k->test_fn.tag != LS_T_NIL) {
        ls_value_t args[2]; args[0] = item; args[1] = probe;
        ls_value_t r = ls_apply(L, k->test_fn, 2, args);
        matched = (r.tag != LS_T_NIL);
    } else {
        matched = ls_value_equal(item, probe, LS_HASH_EQL);
    }
    if (k->test_not) matched = !matched;
    return matched;
}
static double num_as_f(ls_value_t v) {
    if (v.tag == LS_T_FIXNUM) return (double)v.u.fixnum;
    if (v.tag == LS_T_FLONUM) return v.u.flonum;
    return 0.0;
}
static int is_num(ls_value_t v) { return v.tag == LS_T_FIXNUM || v.tag == LS_T_FLONUM; }

/* Promote: if both fixnums, stay fixnum; else float. */
static ls_value_t num_result(int64_t i, double f, int as_float) {
    return as_float ? ls_make_flonum(f) : ls_make_fixnum(i);
}

/* ============================================================
 *  ARITHMETIC
 * ============================================================ */
static ls_value_t bi_add(ls_state_t *L, int n, ls_value_t *a) {
    (void)L;
    int has_float = 0; int64_t si = 0; double sf = 0.0;
    for (int i = 0; i < n; i++) {
        if (a[i].tag == LS_T_FLONUM) { has_float = 1; sf += a[i].u.flonum; }
        else if (a[i].tag == LS_T_FIXNUM) { si += a[i].u.fixnum; sf += (double)a[i].u.fixnum; }
    }
    return has_float ? ls_make_flonum(sf) : ls_make_fixnum(si);
}
static ls_value_t bi_sub(ls_state_t *L, int n, ls_value_t *a) {
    (void)L;
    if (n == 0) return ls_make_fixnum(0);
    int has_float = (a[0].tag == LS_T_FLONUM);
    int64_t si = a[0].tag == LS_T_FIXNUM ? a[0].u.fixnum : 0;
    double sf = num_as_f(a[0]);
    if (n == 1) return has_float ? ls_make_flonum(-sf) : ls_make_fixnum(-si);
    for (int i = 1; i < n; i++) {
        if (a[i].tag == LS_T_FLONUM) { has_float = 1; sf -= a[i].u.flonum; }
        else if (a[i].tag == LS_T_FIXNUM) { si -= a[i].u.fixnum; sf -= (double)a[i].u.fixnum; }
    }
    return has_float ? ls_make_flonum(sf) : ls_make_fixnum(si);
}
static ls_value_t bi_mul(ls_state_t *L, int n, ls_value_t *a) {
    (void)L;
    int has_float = 0; int64_t si = 1; double sf = 1.0;
    for (int i = 0; i < n; i++) {
        if (a[i].tag == LS_T_FLONUM) { has_float = 1; sf *= a[i].u.flonum; }
        else if (a[i].tag == LS_T_FIXNUM) { si *= a[i].u.fixnum; sf *= (double)a[i].u.fixnum; }
    }
    return has_float ? ls_make_flonum(sf) : ls_make_fixnum(si);
}
static ls_value_t bi_div(ls_state_t *L, int n, ls_value_t *a) {
    if (n < 1) { ls_error(L, "/: need >= 1 arg"); return ls_nil_v(); }
    double v = num_as_f(a[0]);
    if (n == 1) { if (v == 0.0) { ls_error(L, "division by zero"); return ls_nil_v(); } return ls_make_flonum(1.0/v); }
    for (int i = 1; i < n; i++) {
        double d = num_as_f(a[i]);
        if (d == 0.0) { ls_error(L, "division by zero"); return ls_nil_v(); }
        v /= d;
    }
    if (a[0].tag == LS_T_FIXNUM) {
        /* Check if exact integer division */
        int all_int = 1;
        for (int i = 0; i < n; i++) if (a[i].tag != LS_T_FIXNUM) all_int = 0;
        if (all_int) {
            int64_t num = a[0].u.fixnum;
            for (int i = 1; i < n; i++) num /= a[i].u.fixnum;
            double check = num_as_f(a[0]);
            for (int i = 1; i < n; i++) check /= num_as_f(a[i]);
            if ((double)num == check) return ls_make_fixnum(num);
        }
    }
    return ls_make_flonum(v);
}
static ls_value_t bi_mod(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("mod", 2);
    if (a[1].tag == LS_T_FIXNUM && a[1].u.fixnum == 0) { ls_error(L, "mod by zero"); return ls_nil_v(); }
    if (a[0].tag == LS_T_FIXNUM && a[1].tag == LS_T_FIXNUM)
        return ls_make_fixnum(a[0].u.fixnum % a[1].u.fixnum);
    return ls_make_flonum(fmod(num_as_f(a[0]), num_as_f(a[1])));
}
static ls_value_t bi_rem(ls_state_t *L, int n, ls_value_t *a) { return bi_mod(L, n, a); }
static ls_value_t bi_abs(ls_state_t *L, int n, ls_value_t *a) {
    (void)L; ARGN("abs", 1);
    if (a[0].tag == LS_T_FIXNUM) return ls_make_fixnum(a[0].u.fixnum < 0 ? -a[0].u.fixnum : a[0].u.fixnum);
    return ls_make_flonum(fabs(num_as_f(a[0])));
}
/* helper: produce two values (quotient remainder) using L->mv */
static ls_value_t division_two_values(ls_state_t *L, int64_t q, double r_double, int int_inputs, int64_t r_int) {
    ls_value_t qv = ls_make_fixnum(q);
    ls_value_t rv = int_inputs ? ls_make_fixnum(r_int) : ls_make_flonum(r_double);
    L->mv.n = 2;
    L->mv.v[0] = qv;
    L->mv.v[1] = rv;
    return qv;
}
static ls_value_t bi_floor(ls_state_t *L, int n, ls_value_t *a) {
    if (n < 1 || n > 2) ls_error(L, "floor: 1 or 2 args required");
    double x = num_as_f(a[0]);
    double y = (n == 2) ? num_as_f(a[1]) : 1.0;
    if (y == 0.0) ls_error(L, "floor: division by zero");
    int int_in = (a[0].tag == LS_T_FIXNUM) && (n < 2 || a[1].tag == LS_T_FIXNUM);
    int64_t q = (int64_t)floor(x / y);
    if (int_in) {
        int64_t yi = (n==2) ? a[1].u.fixnum : 1;
        int64_t r = a[0].u.fixnum - q * yi;
        return division_two_values(L, q, 0, 1, r);
    }
    return division_two_values(L, q, x - q*y, 0, 0);
}
static ls_value_t bi_ceiling(ls_state_t *L, int n, ls_value_t *a) {
    if (n < 1 || n > 2) ls_error(L, "ceiling: 1 or 2 args required");
    double x = num_as_f(a[0]);
    double y = (n == 2) ? num_as_f(a[1]) : 1.0;
    if (y == 0.0) ls_error(L, "ceiling: division by zero");
    int int_in = (a[0].tag == LS_T_FIXNUM) && (n < 2 || a[1].tag == LS_T_FIXNUM);
    int64_t q = (int64_t)ceil(x / y);
    if (int_in) {
        int64_t yi = (n==2) ? a[1].u.fixnum : 1;
        int64_t r = a[0].u.fixnum - q * yi;
        return division_two_values(L, q, 0, 1, r);
    }
    return division_two_values(L, q, x - q*y, 0, 0);
}
static ls_value_t bi_round(ls_state_t *L, int n, ls_value_t *a) {
    if (n < 1 || n > 2) ls_error(L, "round: 1 or 2 args required");
    double x = num_as_f(a[0]);
    double y = (n == 2) ? num_as_f(a[1]) : 1.0;
    if (y == 0.0) ls_error(L, "round: division by zero");
    int int_in = (a[0].tag == LS_T_FIXNUM) && (n < 2 || a[1].tag == LS_T_FIXNUM);
    int64_t q = (int64_t)round(x / y);
    if (int_in) {
        int64_t yi = (n==2) ? a[1].u.fixnum : 1;
        int64_t r = a[0].u.fixnum - q * yi;
        return division_two_values(L, q, 0, 1, r);
    }
    return division_two_values(L, q, x - q*y, 0, 0);
}
static ls_value_t bi_truncate(ls_state_t *L, int n, ls_value_t *a) {
    if (n < 1 || n > 2) ls_error(L, "truncate: 1 or 2 args required");
    double x = num_as_f(a[0]);
    double y = (n == 2) ? num_as_f(a[1]) : 1.0;
    if (y == 0.0) ls_error(L, "truncate: division by zero");
    int int_in = (a[0].tag == LS_T_FIXNUM) && (n < 2 || a[1].tag == LS_T_FIXNUM);
    int64_t q = (int64_t)(x / y);  /* truncate toward zero */
    if (int_in) {
        int64_t yi = (n==2) ? a[1].u.fixnum : 1;
        int64_t r = a[0].u.fixnum - q * yi;
        return division_two_values(L, q, 0, 1, r);
    }
    return division_two_values(L, q, x - q*y, 0, 0);
}
static ls_value_t bi_max(ls_state_t *L, int n, ls_value_t *a) { (void)L; double m = num_as_f(a[0]); int fi = (a[0].tag==LS_T_FIXNUM); for(int i=1;i<n;i++){double v=num_as_f(a[i]); if(v>m){m=v;fi=(a[i].tag==LS_T_FIXNUM);}} return fi?ls_make_fixnum((int64_t)m):ls_make_flonum(m); }
static ls_value_t bi_min(ls_state_t *L, int n, ls_value_t *a) { (void)L; double m = num_as_f(a[0]); int fi = (a[0].tag==LS_T_FIXNUM); for(int i=1;i<n;i++){double v=num_as_f(a[i]); if(v<m){m=v;fi=(a[i].tag==LS_T_FIXNUM);}} return fi?ls_make_fixnum((int64_t)m):ls_make_flonum(m); }
static ls_value_t bi_expt(ls_state_t *L, int n, ls_value_t *a) {
    (void)L; ARGN("expt",2);
    /* Integer base + non-negative integer exponent => fixnum result */
    if (a[0].tag == LS_T_FIXNUM && a[1].tag == LS_T_FIXNUM && a[1].u.fixnum >= 0) {
        int64_t base = a[0].u.fixnum;
        int64_t exp = a[1].u.fixnum;
        int64_t r = 1;
        int overflow = 0;
        while (exp > 0) {
            if (exp & 1) {
                int64_t old = r;
                r *= base;
                if (base != 0 && r / base != old) { overflow = 1; break; }
            }
            exp >>= 1;
            if (exp > 0) {
                int64_t nb = base * base;
                if (base != 0 && nb / base != base) { overflow = 1; break; }
                base = nb;
            }
        }
        if (!overflow) return ls_make_fixnum(r);
    }
    return ls_make_flonum(pow(num_as_f(a[0]),num_as_f(a[1])));
}
static ls_value_t bi_sqrt(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("sqrt",1); return ls_make_flonum(sqrt(num_as_f(a[0]))); }
static ls_value_t bi_sin(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("sin",1); return ls_make_flonum(sin(num_as_f(a[0]))); }
static ls_value_t bi_cos(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("cos",1); return ls_make_flonum(cos(num_as_f(a[0]))); }
static ls_value_t bi_tan(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("tan",1); return ls_make_flonum(tan(num_as_f(a[0]))); }
static ls_value_t bi_asin(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("asin",1); return ls_make_flonum(asin(num_as_f(a[0]))); }
static ls_value_t bi_acos(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("acos",1); return ls_make_flonum(acos(num_as_f(a[0]))); }
static ls_value_t bi_atan(ls_state_t *L, int n, ls_value_t *a) { (void)L; if(n>=2)return ls_make_flonum(atan2(num_as_f(a[0]),num_as_f(a[1]))); return ls_make_flonum(atan(num_as_f(a[0]))); }
static ls_value_t bi_log(ls_state_t *L, int n, ls_value_t *a) { (void)L; if(n>=2)return ls_make_flonum(log(num_as_f(a[0]))/log(num_as_f(a[1]))); return ls_make_flonum(log(num_as_f(a[0]))); }
static ls_value_t bi_exp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("exp",1); return ls_make_flonum(exp(num_as_f(a[0]))); }

/* Numeric comparisons */
static ls_value_t bi_numeq(ls_state_t *L, int n, ls_value_t *a) { (void)L; for(int i=1;i<n;i++) if(num_as_f(a[i-1])!=num_as_f(a[i])) return ls_nil_v(); return ls_t_v(); }
static ls_value_t bi_numlt(ls_state_t *L, int n, ls_value_t *a) { (void)L; for(int i=1;i<n;i++) if(!(num_as_f(a[i-1])<num_as_f(a[i]))) return ls_nil_v(); return ls_t_v(); }
static ls_value_t bi_numle(ls_state_t *L, int n, ls_value_t *a) { (void)L; for(int i=1;i<n;i++) if(!(num_as_f(a[i-1])<=num_as_f(a[i]))) return ls_nil_v(); return ls_t_v(); }
static ls_value_t bi_numgt(ls_state_t *L, int n, ls_value_t *a) { (void)L; for(int i=1;i<n;i++) if(!(num_as_f(a[i-1])>num_as_f(a[i]))) return ls_nil_v(); return ls_t_v(); }
static ls_value_t bi_numge(ls_state_t *L, int n, ls_value_t *a) { (void)L; for(int i=1;i<n;i++) if(!(num_as_f(a[i-1])>=num_as_f(a[i]))) return ls_nil_v(); return ls_t_v(); }
static ls_value_t bi_zerop(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("zerop",1); return num_as_f(a[0])==0.0 ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_plusp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("plusp",1); return num_as_f(a[0])>0.0 ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_minusp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("minusp",1); return num_as_f(a[0])<0.0 ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_numberp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("numberp",1); return is_num(a[0]) ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_integerp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("integerp",1); return a[0].tag==LS_T_FIXNUM ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_floatp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("floatp",1); return a[0].tag==LS_T_FLONUM ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_evenp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("evenp",1); return (a[0].tag==LS_T_FIXNUM && a[0].u.fixnum%2==0) ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_oddp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("oddp",1); return (a[0].tag==LS_T_FIXNUM && a[0].u.fixnum%2!=0) ? ls_t_v() : ls_nil_v(); }
static ls_value_t bi_1plus(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("1+",1); if(a[0].tag==LS_T_FIXNUM) return ls_make_fixnum(a[0].u.fixnum+1); return ls_make_flonum(num_as_f(a[0])+1.0); }
static ls_value_t bi_1minus(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("1-",1); if(a[0].tag==LS_T_FIXNUM) return ls_make_fixnum(a[0].u.fixnum-1); return ls_make_flonum(num_as_f(a[0])-1.0); }

/* Bitwise */
static ls_value_t bi_logand(ls_state_t *L, int n, ls_value_t *a) { (void)L; int64_t r = ~(int64_t)0; for(int i=0;i<n;i++) r &= a[i].u.fixnum; return ls_make_fixnum(r); }
static ls_value_t bi_logior(ls_state_t *L, int n, ls_value_t *a) { (void)L; int64_t r = 0; for(int i=0;i<n;i++) r |= a[i].u.fixnum; return ls_make_fixnum(r); }
static ls_value_t bi_logxor(ls_state_t *L, int n, ls_value_t *a) { (void)L; int64_t r = 0; for(int i=0;i<n;i++) r ^= a[i].u.fixnum; return ls_make_fixnum(r); }
static ls_value_t bi_lognot(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("lognot",1); return ls_make_fixnum(~a[0].u.fixnum); }
static ls_value_t bi_ash(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("ash",2); int64_t v=a[0].u.fixnum; int64_t s=a[1].u.fixnum; return ls_make_fixnum(s>=0?(v<<s):(v>>(-s))); }

/* ============================================================
 *  CONS / LIST
 * ============================================================ */
static ls_value_t bi_cons(ls_state_t *L, int n, ls_value_t *a) { ARGN("cons",2); return ls_cons(L, a[0], a[1]); }
static ls_value_t bi_car(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("car",1); return ls_car(a[0]); }
static ls_value_t bi_cdr(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("cdr",1); return ls_cdr(a[0]); }
static ls_value_t bi_caar(ls_state_t *L,int n,ls_value_t *a) { (void)L; ARGN("caar",1); return ls_car(ls_car(a[0])); }
static ls_value_t bi_cadr(ls_state_t *L,int n,ls_value_t *a) { (void)L; ARGN("cadr",1); return ls_car(ls_cdr(a[0])); }
static ls_value_t bi_cddr(ls_state_t *L,int n,ls_value_t *a) { (void)L; ARGN("cddr",1); return ls_cdr(ls_cdr(a[0])); }
static ls_value_t bi_cdar(ls_state_t *L,int n,ls_value_t *a) { (void)L; ARGN("cdar",1); return ls_cdr(ls_car(a[0])); }
static ls_value_t bi_caddr(ls_state_t *L,int n,ls_value_t *a) { (void)L; ARGN("caddr",1); return ls_car(ls_cdr(ls_cdr(a[0]))); }
static ls_value_t bi_rplaca(ls_state_t *L, int n, ls_value_t *a) { ARGN("rplaca",2); if(a[0].tag!=LS_T_CONS) { ls_type_error(L,"cons",a[0]); return ls_nil_v(); } ((ls_cons_t*)a[0].u.ptr)->car = a[1]; return a[0]; }
static ls_value_t bi_rplacd(ls_state_t *L, int n, ls_value_t *a) { ARGN("rplacd",2); if(a[0].tag!=LS_T_CONS) { ls_type_error(L,"cons",a[0]); return ls_nil_v(); } ((ls_cons_t*)a[0].u.ptr)->cdr = a[1]; return a[0]; }
static ls_value_t bi_list(ls_state_t *L, int n, ls_value_t *a) {
    ls_value_t r = ls_nil_v();
    for (int i = n-1; i >= 0; i--) r = ls_cons(L, a[i], r);
    return r;
}
static ls_value_t bi_liststar(ls_state_t *L, int n, ls_value_t *a) {
    if (n == 0) return ls_nil_v();
    ls_value_t r = a[n-1];
    for (int i = n-2; i >= 0; i--) r = ls_cons(L, a[i], r);
    return r;
}
static ls_value_t bi_length(ls_state_t *L, int n, ls_value_t *a) {
    (void)L; ARGN("length",1);
    if (a[0].tag == LS_T_NIL) return ls_make_fixnum(0);
    if (a[0].tag == LS_T_CONS) return ls_make_fixnum((int64_t)ls_list_length(a[0]));
    if (a[0].tag == LS_T_STRING) return ls_make_fixnum((int64_t)((ls_string_t*)a[0].u.ptr)->len);
    if (a[0].tag == LS_T_VECTOR) return ls_make_fixnum((int64_t)((ls_vector_t*)a[0].u.ptr)->len);
    return ls_make_fixnum(0);
}
static ls_value_t bi_append(ls_state_t *L, int n, ls_value_t *a) {
    ls_value_t r = ls_nil_v();
    for (int i = n-1; i >= 0; i--) r = ls_list_append(L, a[i], r);
    return r;
}
static ls_value_t bi_reverse(ls_state_t *L, int n, ls_value_t *a) { ARGN("reverse",1); return ls_list_reverse(L, a[0]); }
static ls_value_t bi_nth(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("nth",2); return ls_list_nth(a[1], (size_t)a[0].u.fixnum); }
static ls_value_t bi_nthcdr(ls_state_t *L, int n, ls_value_t *a) {
    (void)L; ARGN("nthcdr",2); ls_value_t v = a[1];
    for (int64_t i = 0; i < a[0].u.fixnum && v.tag == LS_T_CONS; i++) v = ls_cdr(v);
    return v;
}
static ls_value_t bi_last(ls_state_t *L, int n, ls_value_t *a) {
    (void)L; ARGN("last",1); ls_value_t v = a[0];
    while (v.tag == LS_T_CONS && ls_cdr(v).tag == LS_T_CONS) v = ls_cdr(v);
    return v;
}
static ls_value_t bi_copy_list(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("copy-list",1);
    ls_value_t h = ls_nil_v(), t = ls_nil_v();
    ls_value_t v = a[0];
    while (v.tag == LS_T_CONS) {
        ls_value_t c = ls_cons(L, ls_car(v), ls_nil_v());
        if (h.tag == LS_T_NIL) h = t = c;
        else { ((ls_cons_t*)t.u.ptr)->cdr = c; t = c; }
        v = ls_cdr(v);
    }
    if (t.tag == LS_T_CONS && v.tag != LS_T_NIL) ((ls_cons_t*)t.u.ptr)->cdr = v;
    return h;
}

static ls_value_t bi_member(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("member",2);
    /* Parse keyword args: :test FN, :key FN, :test-not FN */
    ls_value_t test_fn = ls_nil_v();
    ls_value_t key_fn  = ls_nil_v();
    int test_not = 0;
    for (int i = 2; i + 1 < n; i += 2) {
        ls_symbol_t *kw = ls_symbol_p(a[i]);
        if (!kw) continue;
        const char *kn = kw->name->chars;
        if (strcmp(kn, "TEST") == 0) test_fn = a[i+1];
        else if (strcmp(kn, "KEY") == 0) key_fn = a[i+1];
        else if (strcmp(kn, "TEST-NOT") == 0) { test_fn = a[i+1]; test_not = 1; }
    }
    ls_value_t v = a[1];
    while (v.tag == LS_T_CONS) {
        ls_value_t elem = ls_car(v);
        ls_value_t probe = elem;
        if (key_fn.tag != LS_T_NIL) probe = ls_apply(L, key_fn, 1, &elem);
        int matched;
        if (test_fn.tag != LS_T_NIL) {
            ls_value_t args2[2]; args2[0] = a[0]; args2[1] = probe;
            ls_value_t r = ls_apply(L, test_fn, 2, args2);
            matched = (r.tag != LS_T_NIL);
        } else {
            matched = ls_value_equal(a[0], probe, LS_HASH_EQL);
        }
        if (test_not) matched = !matched;
        if (matched) return v;
        v = ls_cdr(v);
    }
    return ls_nil_v();
}
static ls_value_t bi_assoc(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("assoc",2);
    seqkw_t k; parse_seqkw(n, a, 2, &k);
    ls_value_t v = a[1];
    while (v.tag == LS_T_CONS) {
        ls_value_t entry = ls_car(v);
        if (entry.tag == LS_T_CONS && seqkw_match(L, &k, a[0], ls_car(entry))) return entry;
        v = ls_cdr(v);
    }
    return ls_nil_v();
}
static ls_value_t bi_mapcar(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("mapcar",2);
    ls_value_t fn = a[0], list = a[1];
    ls_value_t h = ls_nil_v(), t = ls_nil_v();
    while (list.tag == LS_T_CONS) {
        ls_value_t x = ls_car(list);
        ls_value_t r = ls_apply(L, fn, 1, &x);
        ls_value_t c = ls_cons(L, r, ls_nil_v());
        if (h.tag == LS_T_NIL) h = t = c;
        else { ((ls_cons_t*)t.u.ptr)->cdr = c; t = c; }
        list = ls_cdr(list);
    }
    return h;
}
static ls_value_t bi_mapc(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("mapc",2);
    ls_value_t fn = a[0], list = a[1], orig = list;
    while (list.tag == LS_T_CONS) {
        ls_value_t x = ls_car(list);
        ls_apply(L, fn, 1, &x);
        list = ls_cdr(list);
    }
    return orig;
}
static ls_value_t bi_reduce(ls_state_t *L, int n, ls_value_t *a) {
    if (n < 2) ls_error(L, "reduce: too few arguments");
    ls_value_t fn = a[0], list = a[1];
    /* Parse keyword args: :initial-value, :from-end, :key, :start, :end */
    int has_initial = 0;
    ls_value_t initial = ls_nil_v();
    ls_value_t key_fn = ls_nil_v();
    int from_end = 0;
    int kstart = 0, kend = -1;
    for (int i = 2; i + 1 < n; i += 2) {
        if (a[i].tag != LS_T_SYMBOL) continue;
        ls_symbol_t *kw = (ls_symbol_t *)a[i].u.ptr;
        const char *nm = kw->name->chars;
        if      (!strcmp(nm,"INITIAL-VALUE")) { initial = a[i+1]; has_initial = 1; }
        else if (!strcmp(nm,"FROM-END"))      from_end = (a[i+1].tag != LS_T_NIL);
        else if (!strcmp(nm,"KEY"))           key_fn = a[i+1];
        else if (!strcmp(nm,"START")) { if (a[i+1].tag == LS_T_FIXNUM) kstart = (int)a[i+1].u.fixnum; }
        else if (!strcmp(nm,"END"))   { if (a[i+1].tag == LS_T_FIXNUM) kend = (int)a[i+1].u.fixnum; }
    }
    /* Convert sequence to a fresh array for [start,end) slice */
    int total = 0;
    if (list.tag == LS_T_VECTOR) {
        ls_vector_t *v = (ls_vector_t *)list.u.ptr;
        total = (int)v->len;
    } else {
        ls_value_t p = list;
        while (p.tag == LS_T_CONS) { total++; p = ls_cdr(p); }
    }
    if (kend < 0 || kend > total) kend = total;
    if (kstart < 0) kstart = 0;
    int slen = kend - kstart;
    if (slen < 0) slen = 0;
    ls_value_t *items = NULL;
    if (slen > 0) {
        items = (ls_value_t *)malloc(sizeof(ls_value_t) * (size_t)slen);
        if (!items) ls_error(L, "reduce: out of memory");
    }
    if (list.tag == LS_T_VECTOR) {
        ls_vector_t *v = (ls_vector_t *)list.u.ptr;
        for (int i = 0; i < slen; i++) items[i] = v->data[kstart + i];
    } else {
        ls_value_t p = list;
        for (int i = 0; i < kstart && p.tag == LS_T_CONS; i++) p = ls_cdr(p);
        for (int i = 0; i < slen && p.tag == LS_T_CONS; i++) {
            items[i] = ls_car(p); p = ls_cdr(p);
        }
    }
    /* Apply :key */
    if (key_fn.tag != LS_T_NIL) {
        for (int i = 0; i < slen; i++)
            items[i] = ls_apply(L, key_fn, 1, &items[i]);
    }
    /* Empty sequence */
    if (slen == 0) {
        ls_value_t r = has_initial ? initial : ls_apply(L, fn, 0, NULL);
        if (items) free(items);
        return r;
    }
    ls_value_t acc;
    if (from_end) {
        if (has_initial) {
            acc = initial;
            for (int i = slen - 1; i >= 0; i--) {
                ls_value_t x[2]; x[0] = items[i]; x[1] = acc;
                acc = ls_apply(L, fn, 2, x);
            }
        } else {
            acc = items[slen - 1];
            for (int i = slen - 2; i >= 0; i--) {
                ls_value_t x[2]; x[0] = items[i]; x[1] = acc;
                acc = ls_apply(L, fn, 2, x);
            }
        }
    } else {
        int start_i;
        if (has_initial) { acc = initial; start_i = 0; }
        else             { acc = items[0]; start_i = 1; }
        for (int i = start_i; i < slen; i++) {
            ls_value_t x[2]; x[0] = acc; x[1] = items[i];
            acc = ls_apply(L, fn, 2, x);
        }
    }
    if (items) free(items);
    return acc;
}
static ls_value_t bi_remove_if(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("remove-if",2);
    ls_value_t fn = a[0], list = a[1];
    ls_value_t h = ls_nil_v(), t = ls_nil_v();
    while (list.tag == LS_T_CONS) {
        ls_value_t x = ls_car(list);
        ls_value_t r = ls_apply(L, fn, 1, &x);
        if (r.tag == LS_T_NIL) {
            ls_value_t c = ls_cons(L, x, ls_nil_v());
            if (h.tag == LS_T_NIL) h = t = c;
            else { ((ls_cons_t*)t.u.ptr)->cdr = c; t = c; }
        }
        list = ls_cdr(list);
    }
    return h;
}
static ls_value_t bi_remove_if_not(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("remove-if-not",2);
    ls_value_t fn = a[0], list = a[1];
    ls_value_t h = ls_nil_v(), t = ls_nil_v();
    while (list.tag == LS_T_CONS) {
        ls_value_t x = ls_car(list);
        ls_value_t r = ls_apply(L, fn, 1, &x);
        if (r.tag != LS_T_NIL) {
            ls_value_t c = ls_cons(L, x, ls_nil_v());
            if (h.tag == LS_T_NIL) h = t = c;
            else { ((ls_cons_t*)t.u.ptr)->cdr = c; t = c; }
        }
        list = ls_cdr(list);
    }
    return h;
}
static ls_value_t bi_some(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("some",2);
    ls_value_t fn = a[0], list = a[1];
    while (list.tag == LS_T_CONS) { ls_value_t x = ls_car(list); ls_value_t r = ls_apply(L, fn, 1, &x); if (r.tag != LS_T_NIL) return r; list = ls_cdr(list); }
    return ls_nil_v();
}
static ls_value_t bi_every(ls_state_t *L, int n, ls_value_t *a) {
    ARGN("every",2);
    ls_value_t fn = a[0], list = a[1]; ls_value_t r = ls_t_v();
    while (list.tag == LS_T_CONS) { ls_value_t x = ls_car(list); r = ls_apply(L, fn, 1, &x); if (r.tag == LS_T_NIL) return r; list = ls_cdr(list); }
    return r;
}

/* ============================================================
 *  TYPE PREDICATES
 * ============================================================ */
static ls_value_t bi_consp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("consp",1); return a[0].tag==LS_T_CONS?ls_t_v():ls_nil_v(); }
static ls_value_t bi_listp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("listp",1); return (a[0].tag==LS_T_CONS||a[0].tag==LS_T_NIL)?ls_t_v():ls_nil_v(); }
static ls_value_t bi_atom(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("atom",1); return a[0].tag!=LS_T_CONS?ls_t_v():ls_nil_v(); }
static ls_value_t bi_null(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("null",1); return a[0].tag==LS_T_NIL?ls_t_v():ls_nil_v(); }
static ls_value_t bi_symbolp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("symbolp",1); return a[0].tag==LS_T_SYMBOL?ls_t_v():ls_nil_v(); }
static ls_value_t bi_stringp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("stringp",1); return a[0].tag==LS_T_STRING?ls_t_v():ls_nil_v(); }
static ls_value_t bi_vectorp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("vectorp",1); return a[0].tag==LS_T_VECTOR?ls_t_v():ls_nil_v(); }
static ls_value_t bi_functionp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("functionp",1); return ls_is_fn(a[0])?ls_t_v():ls_nil_v(); }
static ls_value_t bi_characterp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("characterp",1); return a[0].tag==LS_T_CHAR?ls_t_v():ls_nil_v(); }
static ls_value_t bi_keywordp(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("keywordp",1); return (a[0].tag==LS_T_SYMBOL && ((ls_symbol_t*)a[0].u.ptr)->sym_flags & LS_SYM_KEYWORD)?ls_t_v():ls_nil_v(); }
static ls_value_t bi_hash_table_p(ls_state_t *L, int n, ls_value_t *a) { (void)L; ARGN("hash-table-p",1); return a[0].tag==LS_T_HASHTABLE?ls_t_v():ls_nil_v(); }

