/*** Begin: lsclos.c ***/
/* lsclos.c -- CLOS (Common Lisp Object System) and condition system.
 *
 * Implements:  class hierarchy, class-of, make-instance, slot-value,
 *   defclass (C3 linearization), defgeneric, defmethod, method dispatch,
 *   and the condition/restart system (signal, handler-bind, handler-case,
 *   restart-case, invoke-restart, find-restart).
 *
 * Each builtin is a static C function with signature:
 *   ls_value_t fn(ls_state_t *L, int nargs, ls_value_t *args);
 *
 * Registration happens in ls_init_clos() called from ls_new(). */

/* ============================================================
 *  Helpers
 * ============================================================ */
#undef A
#define A(i)  args[i]

/* ls_nil_v / ls_t_v are declared in lscore.h and defined in lscore.c */

/* Intern a symbol in the CL package for convenience. */
static ls_symbol_t *intern_cl(ls_state_t *L, const char *name) {
    ls_value_t sv = ls_intern(L, "COMMON-LISP", name);
    return ls_symbol_p(sv);
}

/* Intern a keyword. */
static ls_symbol_t *intern_kw(ls_state_t *L, const char *name) {
    ls_value_t sv = ls_intern(L, "KEYWORD", name);
    return ls_symbol_p(sv);
}

/* Make a one-element list. */
static ls_value_t list1(ls_state_t *L, ls_value_t a) {
    return ls_cons(L, a, ls_nil_v());
}

/* Check if val is in a list (pointer identity on class pointers). */
static int list_memq(ls_value_t list, ls_value_t item) {
    while (LS_CONSP(list)) {
        if (LS_CAR(list).u.ptr == item.u.ptr) return 1;
        list = LS_CDR(list);
    }
    return 0;
}

/* ============================================================
 *  CLASS-OF  --  return the class metaobject for any value
 * ============================================================ */
ls_value_t ls_class_of(ls_state_t *L, ls_value_t v) {
    switch (v.tag) {
    case LS_T_NIL:       return ls_wrap(LS_T_CLASS, L->class_symbol);
    case LS_T_T:         return ls_wrap(LS_T_CLASS, L->class_symbol);
    case LS_T_FIXNUM:    return ls_wrap(LS_T_CLASS, L->class_fixnum);
    case LS_T_FLONUM:    return ls_wrap(LS_T_CLASS, L->class_float);
    case LS_T_SYMBOL:    return ls_wrap(LS_T_CLASS, L->class_symbol);
    case LS_T_STRING:    return ls_wrap(LS_T_CLASS, L->class_string);
    case LS_T_CONS:      return ls_wrap(LS_T_CLASS, L->class_cons);
    case LS_T_VECTOR:    return ls_wrap(LS_T_CLASS, L->class_vector);
    case LS_T_HASHTABLE: return ls_wrap(LS_T_CLASS, L->class_hashtable);
    case LS_T_FUNCTION:
    case LS_T_BYTECODE:
    case LS_T_NATIVE:    return ls_wrap(LS_T_CLASS, L->class_function);
    case LS_T_CLASS:     return ls_wrap(LS_T_CLASS, L->class_t);
    case LS_T_INSTANCE:  {
        ls_instance_t *inst = ls_instance_p(v);
        return ls_wrap(LS_T_CLASS, inst->class_);
    }
    case LS_T_CONDITION: {
        ls_condition_t *c = (ls_condition_t *)v.u.ptr;
        return ls_wrap(LS_T_CLASS, c->class_);
    }
    default: return ls_wrap(LS_T_CLASS, L->class_t);
    }
}

/* ============================================================
 *  C3 LINEARIZATION  --  compute class precedence list
 * ============================================================ */

/* Merge step: pick the class that appears at the head of some list
 * and does not appear in the tail of any other list. */
static ls_value_t c3_head_candidate(ls_state_t *L, ls_value_t seqs) {
    /* seqs is a list of lists. */
    ls_value_t s = seqs;
    while (LS_CONSP(s)) {
        ls_value_t seq = LS_CAR(s);
        if (LS_CONSP(seq)) {
            ls_value_t candidate = LS_CAR(seq);
            /* Check candidate is not in the tail of any other list. */
            int blocked = 0;
            ls_value_t s2 = seqs;
            while (LS_CONSP(s2)) {
                ls_value_t other = LS_CAR(s2);
                if (LS_CONSP(other)) {
                    ls_value_t tail = LS_CDR(other);
                    if (list_memq(tail, candidate)) { blocked = 1; break; }
                }
                s2 = LS_CDR(s2);
            }
            if (!blocked) return candidate;
        }
        s = LS_CDR(s);
    }
    return ls_nil_v();  /* should not happen for well-formed hierarchies */
}

/* Remove a class from the head of every sub-list, drop empty lists. */
static ls_value_t c3_remove_head(ls_state_t *L, ls_value_t seqs, ls_value_t cls) {
    ls_value_t result = ls_nil_v();
    ls_gc_push_root(L, &result);
    ls_value_t s = seqs;
    while (LS_CONSP(s)) {
        ls_value_t seq = LS_CAR(s);
        if (LS_CONSP(seq) && LS_CAR(seq).u.ptr == cls.u.ptr)
            seq = LS_CDR(seq);
        if (LS_CONSP(seq))
            result = ls_cons(L, seq, result);
        s = LS_CDR(s);
    }
    ls_gc_pop_root(L);
    return ls_list_reverse(L, result);
}

/* All sub-lists empty? */
static int c3_all_empty(ls_value_t seqs) {
    while (LS_CONSP(seqs)) {
        if (LS_CONSP(LS_CAR(seqs))) return 0;
        seqs = LS_CDR(seqs);
    }
    return 1;
}

/* Compute C3 linearization for a class given its direct supers. */
static ls_value_t c3_linearize(ls_state_t *L, ls_class_t *cls) {
    ls_value_t result = ls_nil_v();
    ls_gc_push_root(L, &result);

    /* Build initial sequence list:
     * for each direct super, its CPL; then the direct-supers list itself. */
    ls_value_t seqs = ls_nil_v();
    ls_gc_push_root(L, &seqs);

    ls_value_t supers = cls->direct_supers;
    ls_value_t s = supers;
    while (LS_CONSP(s)) {
        ls_class_t *sup = ls_class_p(LS_CAR(s));
        if (LS_CONSP(sup->precedence_list))
            seqs = ls_cons(L, sup->precedence_list, seqs);
        s = LS_CDR(s);
    }
    /* Add the direct-supers list itself as the last constraint. */
    if (LS_CONSP(supers))
        seqs = ls_cons(L, supers, seqs);
    seqs = ls_list_reverse(L, seqs);

    /* Start result with the class itself. */
    result = list1(L, ls_wrap(LS_T_CLASS, cls));

    /* Merge loop. */
    while (!c3_all_empty(seqs)) {
        ls_value_t candidate = c3_head_candidate(L, seqs);
        if (LS_NILP(candidate)) {
            ls_error(L, "inconsistent class hierarchy for %s",
                     cls->name ? cls->name->name->chars : "<anon>");
            break;
        }
        result = ls_cons(L, candidate, result);
        seqs = c3_remove_head(L, seqs, candidate);
    }

    ls_gc_pop_root(L);  /* seqs */
    ls_gc_pop_root(L);  /* result */
    return ls_list_reverse(L, result);
}

/* ============================================================
 *  EFFECTIVE SLOTS  --  collect slots from CPL
 * ============================================================ */
static ls_value_t compute_effective_slots(ls_state_t *L, ls_class_t *cls) {
    ls_value_t result = ls_nil_v();
    ls_gc_push_root(L, &result);
    ls_hashtable_t *seen = ls_hash_new(L, LS_HASH_EQ, 16);
    ls_value_t seen_v = ls_wrap(LS_T_HASHTABLE, seen);
    ls_gc_push_root(L, &seen_v);

    ls_value_t cpl = cls->precedence_list;
    while (LS_CONSP(cpl)) {
        ls_class_t *c = ls_class_p(LS_CAR(cpl));
        ls_value_t slots = c->direct_slots;
        while (LS_CONSP(slots)) {
            ls_value_t slot_name = LS_CAR(slots);
            ls_value_t dummy;
            if (!ls_hash_get_sv(seen, slot_name, &dummy)) {
                ls_hash_put(L, seen, slot_name, ls_t_v());
                result = ls_cons(L, slot_name, result);
            }
            slots = LS_CDR(slots);
        }
        cpl = LS_CDR(cpl);
    }
    ls_gc_pop_root(L);  /* seen_v */
    ls_gc_pop_root(L);  /* result */
    return ls_list_reverse(L, result);
}

/* Build the slot-name -> index hashtable. */
static void build_slot_index(ls_state_t *L, ls_class_t *cls) {
    cls->slot_index = ls_hash_new(L, LS_HASH_EQ, cls->n_slots < 4 ? 8 : cls->n_slots * 2);
    ls_value_t slots = cls->effective_slots;
    uint32_t idx = 0;
    while (LS_CONSP(slots)) {
        ls_hash_put(L, cls->slot_index, LS_CAR(slots), ls_make_fixnum((int64_t)idx));
        idx++;
        slots = LS_CDR(slots);
    }
}

/* ============================================================
 *  FINALIZE-CLASS  --  compute CPL, effective slots, slot-index
 * ============================================================ */
static void finalize_class(ls_state_t *L, ls_class_t *cls) {
    if (cls->finalized) return;

    /* Ensure all supers are finalized first. */
    ls_value_t s = cls->direct_supers;
    while (LS_CONSP(s)) {
        ls_class_t *sup = ls_class_p(LS_CAR(s));
        if (!sup->finalized) finalize_class(L, sup);
        s = LS_CDR(s);
    }

    cls->precedence_list = c3_linearize(L, cls);
    cls->effective_slots = compute_effective_slots(L, cls);
    cls->n_slots = (uint32_t)ls_list_length(cls->effective_slots);
    cls->instance_size = (uint32_t)(sizeof(ls_instance_t) + cls->n_slots * sizeof(ls_value_t));
    build_slot_index(L, cls);
    cls->finalized = 1;
}

/* ============================================================
 *  ALLOCATE A NEW CLASS OBJECT
 * ============================================================ */
static ls_class_t *make_class(ls_state_t *L, const char *name,
                              ls_value_t supers, ls_value_t slots) {
    ls_value_t cv = ls_make_obj(L, LS_T_CLASS, sizeof(ls_class_t));
    ls_class_t *cls = ls_class_p(cv);
    cls->name = intern_cl(L, name);
    cls->direct_supers = supers;
    cls->direct_slots = slots;
    cls->precedence_list = ls_nil_v();
    cls->effective_slots = ls_nil_v();
    cls->metaclass = ls_nil_v();
    cls->instance_size = 0;
    cls->n_slots = 0;
    cls->finalized = 0;
    cls->slot_index = NULL;
    return cls;
}

/* Public: define a class from C. */
ls_class_t *ls_define_class(ls_state_t *L, const char *name,
                            ls_value_t supers, ls_value_t slots) {
    ls_class_t *cls = make_class(L, name, supers, slots);
    finalize_class(L, cls);
    /* Bind the class as the symbol's value. */
    ls_symbol_t *sym = cls->name;
    sym->value = ls_wrap(LS_T_CLASS, cls);
    sym->sym_flags |= LS_SYM_HAS_VALUE;
    return cls;
}

/* ============================================================
 *  SLOT ACCESS
 * ============================================================ */

/* Return the integer slot index for a slot name, or -1. */
static int slot_index_of(ls_class_t *cls, ls_value_t slot_name) {
    if (!cls->slot_index) return -1;
    ls_value_t idx;
    if (ls_hash_get_sv(cls->slot_index, slot_name, &idx))
        return (int)idx.u.fixnum;
    return -1;
}

/* Get the value of a slot by name.  Signals an error if unbound. */
ls_value_t ls_slot_value(ls_state_t *L, ls_instance_t *inst, ls_value_t slot_name) {
    int idx = slot_index_of(inst->class_, slot_name);
    if (idx < 0)
        ls_error(L, "slot %s not found in class %s",
                 ls_symbol_p(slot_name)->name->chars,
                 inst->class_->name->name->chars);
    return inst->slots[idx];
}

/* Set the value of a slot by name. */
void ls_slot_set(ls_state_t *L, ls_instance_t *inst, ls_value_t slot_name, ls_value_t val) {
    int idx = slot_index_of(inst->class_, slot_name);
    if (idx < 0)
        ls_error(L, "slot %s not found in class %s",
                 ls_symbol_p(slot_name)->name->chars,
                 inst->class_->name->name->chars);
    inst->slots[idx] = val;
}

/* ============================================================
 *  MAKE-INSTANCE
 * ============================================================ */
static ls_value_t make_instance(ls_state_t *L, ls_class_t *cls,
                                int nargs, ls_value_t *args) {
    if (!cls->finalized) finalize_class(L, cls);

    ls_value_t iv = ls_make_obj(L, LS_T_INSTANCE, sizeof(ls_instance_t));
    ls_instance_t *inst = ls_instance_p(iv);
    inst->class_ = cls;

    /* Allocate slot storage. */
    uint32_t ns = cls->n_slots;
    if (ns > 0) {
        inst->slots = (ls_value_t *)malloc(ns * sizeof(ls_value_t));
        for (uint32_t i = 0; i < ns; i++)
            inst->slots[i] = ls_nil_v();  /* unbound sentinel */
    } else {
        inst->slots = NULL;
    }

    /* Process initargs (keyword arguments: :slot-name value ...) */
    for (int i = 0; i + 1 < nargs; i += 2) {
        ls_value_t key = args[i];
        ls_value_t val = args[i + 1];
        /* A keyword argument :FOO should set slot FOO. */
        ls_symbol_t *ks = ls_symbol_p(key);
        if (!ks) continue;
        /* Find slot with matching name (strip keyword package). */
        const char *sn = ks->name->chars;
        ls_value_t slot_sym = ls_intern(L, "COMMON-LISP", sn);
        int idx = slot_index_of(cls, slot_sym);
        if (idx >= 0)
            inst->slots[idx] = val;
    }
    return iv;
}

/* ============================================================
 *  GENERIC FUNCTIONS AND METHODS
 * ============================================================ */

/* Create a generic function object. */
ls_generic_t *ls_define_generic(ls_state_t *L, const char *name,
                                ls_value_t lambda_list) {
    ls_value_t gv = ls_make_obj(L, LS_T_GENERIC, sizeof(ls_generic_t));
    ls_generic_t *gf = (ls_generic_t *)gv.u.ptr;
    gf->name = intern_cl(L, name);
    gf->lambda_list = lambda_list;
    gf->methods = ls_nil_v();
    gf->combination = ls_nil_v(); /* :standard */
    /* Count required parameters (before &optional, &rest, &key). */
    uint32_t n = 0;
    ls_value_t ll = lambda_list;
    while (LS_CONSP(ll)) {
        ls_value_t p = LS_CAR(ll);
        if (LS_IS(p, LS_T_SYMBOL)) {
            ls_symbol_t *ps = ls_symbol_p(p);
            if (ps == L->sym_ampersand_rest ||
                ps == L->sym_ampersand_optional ||
                ps == L->sym_ampersand_key)
                break;
        }
        n++;
        ll = LS_CDR(ll);
    }
    gf->n_required = n;

    /* Bind to symbol's function slot. */
    gf->name->function = gv;
    gf->name->sym_flags |= LS_SYM_HAS_FN;
    return gf;
}

/* Add a method to a generic function. */
ls_method_t *ls_add_method(ls_state_t *L, ls_generic_t *gf,
                           ls_value_t specializers, ls_value_t qualifiers,
                           ls_value_t fn) {
    ls_value_t mv = ls_make_obj(L, LS_T_METHOD, sizeof(ls_method_t));
    ls_method_t *m = (ls_method_t *)mv.u.ptr;
    m->specializers = specializers;
    m->qualifiers = qualifiers;
    m->lambda = fn;
    m->generic = ls_wrap(LS_T_GENERIC, gf);

    /* Remove any existing method with identical specializers and qualifiers. */
    ls_value_t prev = ls_nil_v();
    ls_value_t cur = gf->methods;
    while (LS_CONSP(cur)) {
        ls_method_t *em = (ls_method_t *)LS_CAR(cur).u.ptr;
        /* Compare specializers pairwise. */
        int same = 1;
        ls_value_t sa = em->specializers, sb = specializers;
        while (LS_CONSP(sa) && LS_CONSP(sb)) {
            if (LS_CAR(sa).u.ptr != LS_CAR(sb).u.ptr) { same = 0; break; }
            sa = LS_CDR(sa); sb = LS_CDR(sb);
        }
        if (same && LS_NILP(sa) && LS_NILP(sb)) {
            /* Also check qualifiers match. */
            ls_value_t qa = em->qualifiers, qb = qualifiers;
            while (LS_CONSP(qa) && LS_CONSP(qb)) {
                if (LS_CAR(qa).u.ptr != LS_CAR(qb).u.ptr) { same = 0; break; }
                qa = LS_CDR(qa); qb = LS_CDR(qb);
            }
            if (same && LS_NILP(qa) && LS_NILP(qb)) {
                /* Replace: splice out old method. */
                if (LS_CONSP(prev))
                    ((ls_cons_t *)prev.u.ptr)->cdr = LS_CDR(cur);
                else
                    gf->methods = LS_CDR(cur);
                break;
            }
        }
        prev = cur;
        cur = LS_CDR(cur);
    }

    /* Prepend new method. */
    gf->methods = ls_cons(L, mv, gf->methods);
    return m;
}

/* ============================================================
 *  METHOD DISPATCH
 * ============================================================ */

/* Check if class A is a subtype of class B (B appears in A's CPL). */
static int subclassp(ls_class_t *a, ls_class_t *b) {
    if (a == b) return 1;
    ls_value_t cpl = a->precedence_list;
    while (LS_CONSP(cpl)) {
        if (LS_CAR(cpl).u.ptr == (void *)b) return 1;
        cpl = LS_CDR(cpl);
    }
    return 0;
}

/* Check if a single method is applicable to the given arguments. */
static int method_applicable(ls_state_t *L, ls_method_t *m,
                             int nargs, ls_value_t *args) {
    ls_value_t specs = m->specializers;
    for (int i = 0; i < nargs && LS_CONSP(specs); i++) {
        ls_class_t *spec = ls_class_p(LS_CAR(specs));
        ls_value_t arg_class = ls_class_of(L, args[i]);
        ls_class_t *ac = ls_class_p(arg_class);
        if (!subclassp(ac, spec)) return 0;
        specs = LS_CDR(specs);
    }
    return 1;
}

/* Position of class C in the CPL of class CLS. Returns a large number
 * if not found (should not happen for well-formed hierarchies). */
static int cpl_position(ls_class_t *cls, ls_class_t *target) {
    int pos = 0;
    ls_value_t cpl = cls->precedence_list;
    while (LS_CONSP(cpl)) {
        if (LS_CAR(cpl).u.ptr == (void *)target) return pos;
        pos++;
        cpl = LS_CDR(cpl);
    }
    return 99999;
}

/* Compare two methods for specificity given the argument classes.
 * Returns negative if a is more specific, positive if b is, 0 if equal. */
static int method_specificity_cmp(ls_state_t *L, ls_method_t *a, ls_method_t *b,
                                  int nargs, ls_value_t *args) {
    ls_value_t sa = a->specializers, sb = b->specializers;
    for (int i = 0; i < nargs && LS_CONSP(sa) && LS_CONSP(sb); i++) {
        ls_class_t *ca = ls_class_p(LS_CAR(sa));
        ls_class_t *cb = ls_class_p(LS_CAR(sb));
        if (ca != cb) {
            /* The more specific is the one whose specializer appears
             * earlier in the CPL of the argument's actual class. */
            ls_value_t arg_class = ls_class_of(L, args[i]);
            ls_class_t *ac = ls_class_p(arg_class);
            int pa = cpl_position(ac, ca);
            int pb = cpl_position(ac, cb);
            if (pa != pb) return pa - pb;
        }
        sa = LS_CDR(sa);
        sb = LS_CDR(sb);
    }
    return 0;
}

/* Sort applicable methods by specificity (insertion sort -- method
 * lists are typically small). */
static void sort_methods(ls_state_t *L, ls_method_t **arr, int n,
                         int nargs, ls_value_t *args) {
    for (int i = 1; i < n; i++) {
        ls_method_t *key = arr[i];
        int j = i - 1;
        while (j >= 0 && method_specificity_cmp(L, arr[j], key, nargs, args) > 0) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

/* Filter methods by qualifier (nil for primary, :before, :after, :around). */
static int qualifier_match(ls_method_t *m, ls_value_t qual) {
    if (LS_NILP(qual))
        return LS_NILP(m->qualifiers);
    if (LS_CONSP(m->qualifiers) && LS_CAR(m->qualifiers).u.ptr == qual.u.ptr)
        return 1;
    return 0;
}

/* Context for call-next-method support. */
typedef struct ls_cnm_ctx {
    ls_state_t *L;
    ls_generic_t *gf;
    ls_method_t **methods;
    int n_methods;
    int current;
    int nargs;
    ls_value_t *args;
} ls_cnm_ctx_t;

/* Thread-local (or state-local) CNM context.  We use a simple stack
 * so nested generic calls work correctly. */
#define CNM_STACK_MAX 64
static ls_cnm_ctx_t cnm_stack[CNM_STACK_MAX];
static int cnm_depth = 0;

static ls_value_t call_method_fn(ls_state_t *L, ls_method_t *m,
                                 int nargs, ls_value_t *args) {
    return ls_apply(L, m->lambda, nargs, args);
}

/* Builtin: call-next-method */
static ls_value_t bi_call_next_method(ls_state_t *L, int nargs, ls_value_t *args) {
    (void)nargs; (void)args;
    if (cnm_depth <= 0)
        ls_error(L, "call-next-method called outside method dispatch");
    ls_cnm_ctx_t *ctx = &cnm_stack[cnm_depth - 1];
    ctx->current++;
    if (ctx->current >= ctx->n_methods) {
        ls_error(L, "no next method for generic function %s",
                 ctx->gf->name->name->chars);
    }
    return call_method_fn(L, ctx->methods[ctx->current],
                          ctx->nargs, ctx->args);
}

/* Builtin: next-method-p */
static ls_value_t bi_next_method_p(ls_state_t *L, int nargs, ls_value_t *args) {
    (void)L; (void)nargs; (void)args;
    if (cnm_depth <= 0) return ls_nil_v();
    ls_cnm_ctx_t *ctx = &cnm_stack[cnm_depth - 1];
    return (ctx->current + 1 < ctx->n_methods) ? ls_t_v() : ls_nil_v();
}

/* Main dispatch entry point.  Implements standard method combination:
 *   1. Run :around methods (most to least specific), each can
 *      call-next-method to chain.
 *   2. Run :before methods (most to least specific).
 *   3. Run primary methods (most specific, can call-next-method).
 *   4. Run :after methods (least to most specific).
 *   5. Return value from step 3. */
ls_value_t ls_dispatch_generic(ls_state_t *L, ls_generic_t *gf,
                               int nargs, ls_value_t *args) {
    if ((uint32_t)nargs < gf->n_required) {
        ls_error(L, "generic function %s requires %u args, got %d",
                 gf->name->name->chars, gf->n_required, nargs);
    }

    /* Collect applicable methods. */
    ls_method_t *applicable[256];
    int n_applicable = 0;
    ls_value_t ml = gf->methods;
    while (LS_CONSP(ml) && n_applicable < 256) {
        ls_method_t *m = (ls_method_t *)LS_CAR(ml).u.ptr;
        if (method_applicable(L, m, nargs, args))
            applicable[n_applicable++] = m;
        ml = LS_CDR(ml);
    }

    if (n_applicable == 0) {
        ls_error(L, "no applicable method for generic function %s",
                 gf->name->name->chars);
    }

    /* Sort by specificity. */
    sort_methods(L, applicable, n_applicable, nargs, args);

    /* Partition by qualifier. */
    ls_method_t *around[64]; int n_around = 0;
    ls_method_t *before[64]; int n_before = 0;
    ls_method_t *primary[64]; int n_primary = 0;
    ls_method_t *after[64]; int n_after = 0;

    ls_value_t kw_before = ls_intern(L, "KEYWORD", "BEFORE");
    ls_value_t kw_after = ls_intern(L, "KEYWORD", "AFTER");
    ls_value_t kw_around = ls_intern(L, "KEYWORD", "AROUND");

    for (int i = 0; i < n_applicable; i++) {
        ls_method_t *m = applicable[i];
        if (qualifier_match(m, ls_nil_v())) {
            if (n_primary < 64) primary[n_primary++] = m;
        } else if (qualifier_match(m, kw_before)) {
            if (n_before < 64) before[n_before++] = m;
        } else if (qualifier_match(m, kw_after)) {
            if (n_after < 64) after[n_after++] = m;
        } else if (qualifier_match(m, kw_around)) {
            if (n_around < 64) around[n_around++] = m;
        }
    }

    if (n_primary == 0) {
        ls_error(L, "no primary method for generic function %s",
                 gf->name->name->chars);
    }

    /* Push CNM context for primary methods (or around if present). */
    if (cnm_depth >= CNM_STACK_MAX)
        ls_error(L, "generic function call stack overflow");

    ls_value_t result;

    if (n_around > 0) {
        /* Around methods: the outermost around method wraps everything.
         * When it calls call-next-method, it invokes the next around
         * method, or if no more around methods, runs the standard
         * before/primary/after sequence. */

        /* Build a combined chain: around methods + a synthetic entry
         * that runs before/primary/after.  For simplicity, we set up
         * around methods in the CNM stack and handle the transition
         * to the effective method ourselves. */
        ls_cnm_ctx_t *ctx = &cnm_stack[cnm_depth++];
        ctx->L = L;
        ctx->gf = gf;
        ctx->methods = around;
        ctx->n_methods = n_around;
        ctx->current = 0;
        ctx->nargs = nargs;
        ctx->args = args;
        result = call_method_fn(L, around[0], nargs, args);
        cnm_depth--;
    } else {
        /* Run :before methods (most to least specific). */
        for (int i = 0; i < n_before; i++)
            call_method_fn(L, before[i], nargs, args);

        /* Run primary methods with call-next-method support. */
        ls_cnm_ctx_t *ctx = &cnm_stack[cnm_depth++];
        ctx->L = L;
        ctx->gf = gf;
        ctx->methods = primary;
        ctx->n_methods = n_primary;
        ctx->current = 0;
        ctx->nargs = nargs;
        ctx->args = args;

        result = call_method_fn(L, primary[0], nargs, args);
        cnm_depth--;

        /* Run :after methods (least to most specific = reverse order). */
        for (int i = n_after - 1; i >= 0; i--)
            call_method_fn(L, after[i], nargs, args);
    }

    return result;
}

/* ============================================================
 *  CONDITION SYSTEM  --  signal, handler-bind, handler-case,
 *  restart-case, restart-bind, invoke-restart, find-restart
 * ============================================================ */

/* Create a condition object. */
ls_value_t ls_make_condition(ls_state_t *L, ls_class_t *cls,
                             ls_value_t initargs) {
    ls_value_t cv = ls_make_obj(L, LS_T_CONDITION, sizeof(ls_condition_t));
    ls_condition_t *c = (ls_condition_t *)cv.u.ptr;
    c->class_ = cls;
    c->initargs = initargs;
    c->format_control = ls_nil_v();
    c->format_arguments = ls_nil_v();

    /* Extract :format-control and :format-arguments from initargs. */
    ls_value_t ia = initargs;
    ls_symbol_t *kw_fc = intern_kw(L, "FORMAT-CONTROL");
    ls_symbol_t *kw_fa = intern_kw(L, "FORMAT-ARGUMENTS");
    while (LS_CONSP(ia) && LS_CONSP(LS_CDR(ia))) {
        ls_symbol_t *k = ls_symbol_p(LS_CAR(ia));
        ls_value_t v = LS_CAR(LS_CDR(ia));
        if (k == kw_fc) c->format_control = v;
        else if (k == kw_fa) c->format_arguments = v;
        ia = LS_CDR(LS_CDR(ia));
    }
    return cv;
}

/* Signal a condition: walk the handler stack from top to bottom.
 * If a handler matches (its type is a superclass of the condition's
 * class), call it.  The handler can:
 *   - return normally (handler-bind semantics: keep searching)
 *   - do a non-local exit (handler-case semantics: unwind)
 *
 * Returns 1 if handled (non-locally), 0 if all handlers declined. */
int ls_signal_condition(ls_state_t *L, ls_value_t condition) {
    ls_condition_t *cond = (ls_condition_t *)condition.u.ptr;
    ls_class_t *cond_class = cond->class_;

    ls_handler_t *h = L->hnd_top;
    while (h) {
        if (subclassp(cond_class, h->type)) {
            /* Call the handler function with the condition. */
            ls_value_t hfn = h->fn;
            ls_value_t carg = condition;
            ls_apply(L, hfn, 1, &carg);
            /* If handler returned normally (handler-bind semantics),
             * continue searching. */
        }
        h = h->next;
    }
    return 0;  /* no handler performed a non-local exit */
}

/* Push a handler frame onto the handler stack. */
void ls_push_handler(ls_state_t *L, ls_class_t *type, ls_value_t fn) {
    ls_handler_t *h = (ls_handler_t *)malloc(sizeof(ls_handler_t));
    h->type = type;
    h->fn = fn;
    h->next = L->hnd_top;
    L->hnd_top = h;
}

/* Pop a handler frame. */
void ls_pop_handler(ls_state_t *L) {
    if (L->hnd_top) {
        ls_handler_t *h = L->hnd_top;
        L->hnd_top = h->next;
        free(h);
    }
}

/* Create a restart object. */
static ls_restart_t *make_restart(ls_state_t *L, const char *name,
                                  ls_value_t invoke_fn) {
    ls_value_t rv = ls_make_obj(L, LS_T_RESTART, sizeof(ls_restart_t));
    ls_restart_t *r = (ls_restart_t *)rv.u.ptr;
    r->name = name ? intern_cl(L, name) : NULL;
    r->invoke_fn = invoke_fn;
    r->test_fn = ls_nil_v();
    r->report_fn = ls_nil_v();
    r->interactive_fn = ls_nil_v();
    r->active = 1;
    return r;
}

/* Push a restart frame. */
void ls_push_restart(ls_state_t *L, ls_restart_t *r) {
    ls_restart_frame_t *f = (ls_restart_frame_t *)malloc(sizeof(ls_restart_frame_t));
    f->restart = r;
    f->next = L->restart_top;
    L->restart_top = f;
}

/* Pop a restart frame. */
void ls_pop_restart(ls_state_t *L) {
    if (L->restart_top) {
        ls_restart_frame_t *f = L->restart_top;
        L->restart_top = f->next;
        free(f);
    }
}

/* Find a restart by name.  Returns NULL if not found. */
ls_restart_t *ls_find_restart(ls_state_t *L, ls_symbol_t *name) {
    ls_restart_frame_t *f = L->restart_top;
    while (f) {
        if (f->restart->active && f->restart->name == name)
            return f->restart;
        f = f->next;
    }
    return NULL;
}

/* Invoke a restart.  Calls the restart's invoke-fn with the given args. */
ls_value_t ls_invoke_restart(ls_state_t *L, ls_restart_t *r,
                             int nargs, ls_value_t *args) {
    if (!r->active)
        ls_error(L, "attempt to invoke inactive restart");
    return ls_apply(L, r->invoke_fn, nargs, args);
}

/* Collect all active restarts into a list. */
ls_value_t ls_compute_restarts(ls_state_t *L) {
    ls_value_t result = ls_nil_v();
    ls_gc_push_root(L, &result);
    ls_restart_frame_t *f = L->restart_top;
    while (f) {
        if (f->restart->active)
            result = ls_cons(L, ls_wrap(LS_T_RESTART, f->restart), result);
        f = f->next;
    }
    ls_gc_pop_root(L);
    return ls_list_reverse(L, result);
}

/* ============================================================
 *  LISP-CALLABLE BUILTINS
 * ============================================================ */

/* (class-of obj) => class */
static ls_value_t bi_class_of(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "class-of", nargs, 1, 1); return ls_nil_v(); }
    return ls_class_of(L, A(0));
}

/* (find-class 'name) => class */
static ls_value_t bi_find_class(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "find-class", nargs, 1, 1); return ls_nil_v(); }
    ls_symbol_t *sym = ls_symbol_p(A(0));
    if (!sym) { ls_type_error(L, "symbol", A(0)); return ls_nil_v(); }
    if (sym->sym_flags & LS_SYM_HAS_VALUE) {
        ls_value_t v = sym->value;
        if (LS_IS(v, LS_T_CLASS)) return v;
    }
    ls_error(L, "no class named %s", sym->name->chars);
    return ls_nil_v();
}

/* (make-instance 'class-name &rest initargs) */
static ls_value_t bi_make_instance(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "make-instance", nargs, 1, -1); return ls_nil_v(); }
    ls_class_t *cls = NULL;
    if (LS_IS(A(0), LS_T_SYMBOL)) {
        ls_symbol_t *sym = ls_symbol_p(A(0));
        if (sym->sym_flags & LS_SYM_HAS_VALUE) {
            ls_value_t v = sym->value;
            if (LS_IS(v, LS_T_CLASS))
                cls = ls_class_p(v);
        }
        if (!cls)
            ls_error(L, "make-instance: %s does not name a class", sym->name->chars);
    } else if (LS_IS(A(0), LS_T_CLASS)) {
        cls = ls_class_p(A(0));
    } else {
        ls_type_error(L, "class or symbol", A(0));
        return ls_nil_v();
    }
    return make_instance(L, cls, nargs - 1, args + 1);
}

/* (slot-value instance slot-name) */
static ls_value_t bi_slot_value(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "slot-value", nargs, 2, 2); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_INSTANCE)) { ls_type_error(L, "instance", A(0)); return ls_nil_v(); }
    ls_instance_t *inst = ls_instance_p(A(0));
    return ls_slot_value(L, inst, A(1));
}

/* (set-slot-value instance slot-name value) -- backing for (setf slot-value) */
static ls_value_t bi_set_slot_value(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 3) { ls_arity_error(L, "set-slot-value", nargs, 3, 3); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_INSTANCE)) { ls_type_error(L, "instance", A(0)); return ls_nil_v(); }
    ls_instance_t *inst = ls_instance_p(A(0));
    ls_slot_set(L, inst, A(1), A(2));
    return A(2);
}

/* (slot-boundp instance slot-name) */
static ls_value_t bi_slot_boundp(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "slot-boundp", nargs, 2, 2); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_INSTANCE)) { ls_type_error(L, "instance", A(0)); return ls_nil_v(); }
    ls_instance_t *inst = ls_instance_p(A(0));
    int idx = slot_index_of(inst->class_, A(1));
    if (idx < 0) return ls_nil_v();
    /* We use nil as the unbound marker, which is admittedly a simplification. */
    return LS_NILP(inst->slots[idx]) ? ls_nil_v() : ls_t_v();
}

/* (typep obj type-name) */
static ls_value_t bi_typep(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "typep", nargs, 2, 2); return ls_nil_v(); }
    ls_class_t *type_class = NULL;
    if (LS_IS(A(1), LS_T_CLASS)) {
        type_class = ls_class_p(A(1));
    } else if (LS_IS(A(1), LS_T_SYMBOL)) {
        ls_symbol_t *sym = ls_symbol_p(A(1));
        if (sym->sym_flags & LS_SYM_HAS_VALUE) {
            ls_value_t cv = sym->value;
            if (LS_IS(cv, LS_T_CLASS)) type_class = ls_class_p(cv);
        }
    }
    if (!type_class) return ls_nil_v();

    ls_value_t oc = ls_class_of(L, A(0));
    ls_class_t *obj_class = ls_class_p(oc);
    return subclassp(obj_class, type_class) ? ls_t_v() : ls_nil_v();
}

/* (subtypep type1 type2) */
static ls_value_t bi_subtypep(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "subtypep", nargs, 2, 2); return ls_nil_v(); }
    ls_class_t *a = NULL, *b = NULL;
    if (LS_IS(A(0), LS_T_CLASS)) a = ls_class_p(A(0));
    else if (LS_IS(A(0), LS_T_SYMBOL)) {
        ls_symbol_t *s = ls_symbol_p(A(0));
        if (s->sym_flags & LS_SYM_HAS_VALUE && LS_IS(s->value, LS_T_CLASS))
            a = ls_class_p(s->value);
    }
    if (LS_IS(A(1), LS_T_CLASS)) b = ls_class_p(A(1));
    else if (LS_IS(A(1), LS_T_SYMBOL)) {
        ls_symbol_t *s = ls_symbol_p(A(1));
        if (s->sym_flags & LS_SYM_HAS_VALUE && LS_IS(s->value, LS_T_CLASS))
            b = ls_class_p(s->value);
    }
    if (!a || !b) return ls_nil_v();
    return subclassp(a, b) ? ls_t_v() : ls_nil_v();
}

/* (class-name class) */
static ls_value_t bi_class_name(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "class-name", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_CLASS)) { ls_type_error(L, "class", A(0)); return ls_nil_v(); }
    ls_class_t *c = ls_class_p(A(0));
    return ls_wrap(LS_T_SYMBOL, c->name);
}

/* (class-precedence-list class) */
static ls_value_t bi_class_cpl(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "class-precedence-list", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_CLASS)) { ls_type_error(L, "class", A(0)); return ls_nil_v(); }
    ls_class_t *c = ls_class_p(A(0));
    return c->precedence_list;
}

/* (class-direct-superclasses class) */
static ls_value_t bi_class_direct_supers(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "class-direct-superclasses", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_CLASS)) { ls_type_error(L, "class", A(0)); return ls_nil_v(); }
    return ls_class_p(A(0))->direct_supers;
}

/* (class-slots class) */
static ls_value_t bi_class_slots(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "class-slots", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_CLASS)) { ls_type_error(L, "class", A(0)); return ls_nil_v(); }
    return ls_class_p(A(0))->effective_slots;
}

/* (signal condition) or (signal 'type :key val ...) */
static ls_value_t bi_signal(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "signal", nargs, 1, -1); return ls_nil_v(); }
    ls_value_t cond;
    if (LS_IS(A(0), LS_T_CONDITION)) {
        cond = A(0);
    } else if (LS_IS(A(0), LS_T_SYMBOL) || LS_IS(A(0), LS_T_CLASS)) {
        /* Make a condition from a type specifier and initargs. */
        ls_class_t *cls = NULL;
        if (LS_IS(A(0), LS_T_CLASS)) {
            cls = ls_class_p(A(0));
        } else {
            ls_symbol_t *sym = ls_symbol_p(A(0));
            if (sym->sym_flags & LS_SYM_HAS_VALUE && LS_IS(sym->value, LS_T_CLASS))
                cls = ls_class_p(sym->value);
        }
        if (!cls) cls = L->class_simple_error;
        /* Build initargs plist from remaining args. */
        ls_value_t ia = ls_nil_v();
        ls_gc_push_root(L, &ia);
        for (int i = nargs - 1; i >= 1; i--)
            ia = ls_cons(L, args[i], ia);
        ls_gc_pop_root(L);
        cond = ls_make_condition(L, cls, ia);
    } else {
        /* String message: wrap in simple-error. */
        ls_value_t ia = ls_nil_v();
        ls_gc_push_root(L, &ia);
        ls_value_t kfc = ls_intern(L, "KEYWORD", "FORMAT-CONTROL");
        ia = ls_cons(L, A(0), ls_nil_v());
        ia = ls_cons(L, kfc, ia);
        ls_gc_pop_root(L);
        cond = ls_make_condition(L, L->class_simple_error, ia);
    }
    ls_signal_condition(L, cond);
    return ls_nil_v();
}

/* (error ...) -- like signal but enters the debugger / calls ls_error
 * if no handler takes a non-local exit. */
static ls_value_t bi_cerror(ls_state_t *L, int nargs, ls_value_t *args) {
    /* First try signaling like signal does. */
    bi_signal(L, nargs, args);
    /* If we get here, no handler handled it. */
    if (nargs >= 1 && LS_IS(A(0), LS_T_STRING)) {
        ls_string_t *s = ls_string_p(A(0));
        ls_error(L, "%s", s->chars);
    } else {
        ls_error(L, "unhandled error condition");
    }
    return ls_nil_v();
}

/* (handler-bind ((type handler-fn) ...) &body body)
 * This is a special form; the builtin version takes a handler alist
 * and a thunk:
 * (%handler-bind handlers-list body-thunk) */
static ls_value_t bi_handler_bind(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "%handler-bind", nargs, 2, 2); return ls_nil_v(); }
    ls_value_t handlers = A(0);
    ls_value_t body_thunk = A(1);

    /* Push handlers. */
    int n_pushed = 0;
    ls_value_t hl = handlers;
    while (LS_CONSP(hl)) {
        ls_value_t entry = LS_CAR(hl);
        /* entry is (type-class . handler-fn) */
        if (LS_CONSP(entry)) {
            ls_class_t *type_cls = NULL;
            ls_value_t type_v = LS_CAR(entry);
            if (LS_IS(type_v, LS_T_CLASS))
                type_cls = ls_class_p(type_v);
            else if (LS_IS(type_v, LS_T_SYMBOL)) {
                ls_symbol_t *s = ls_symbol_p(type_v);
                if (s->sym_flags & LS_SYM_HAS_VALUE && LS_IS(s->value, LS_T_CLASS))
                    type_cls = ls_class_p(s->value);
            }
            if (type_cls) {
                ls_push_handler(L, type_cls, LS_CDR(entry));
                n_pushed++;
            }
        }
        hl = LS_CDR(hl);
    }

    /* Call body thunk. */
    ls_value_t result = ls_apply(L, body_thunk, 0, NULL);

    /* Pop handlers. */
    for (int i = 0; i < n_pushed; i++)
        ls_pop_handler(L);

    return result;
}

/* (%handler-case type-class body-thunk handler-fn)
 * Runs body-thunk; if a condition of type-class is signaled,
 * unwinds and calls handler-fn with the condition. */
static ls_value_t bi_handler_case(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 3) { ls_arity_error(L, "%handler-case", nargs, 3, 3); return ls_nil_v(); }

    ls_class_t *type_cls = NULL;
    if (LS_IS(A(0), LS_T_CLASS))
        type_cls = ls_class_p(A(0));
    else if (LS_IS(A(0), LS_T_SYMBOL)) {
        ls_symbol_t *s = ls_symbol_p(A(0));
        if (s->sym_flags & LS_SYM_HAS_VALUE && LS_IS(s->value, LS_T_CLASS))
            type_cls = ls_class_p(s->value);
    }
    if (!type_cls) { ls_error(L, "handler-case: invalid type specifier"); return ls_nil_v(); }

    ls_value_t body_thunk = A(1);
    ls_value_t handler_fn = A(2);

    /* Set up an escape frame for the non-local exit. */
    ls_escape_t esc;
    esc.kind = 2;  /* condition */
    esc.tag = ls_nil_v();
    esc.value = ls_nil_v();
    esc.next = L->esc_top;
    L->esc_top = &esc;

    if (setjmp(esc.buf) == 0) {
        /* Install a handler that performs a non-local exit. */
        /* We create a tiny native function wrapper that longjmps.
         * Instead, we use the escape frame: push a handler whose fn
         * stores the condition in esc.value and longjmps. */

        /* We cannot create a closure here easily, so we use a
         * handler-bind approach: install a handler, and if it fires,
         * we store the condition and longjmp. */

        /* Push the handler with a special sentinel function.
         * When the signal code calls this handler, we do the longjmp. */
        ls_handler_t hframe;
        hframe.type = type_cls;
        hframe.fn = ls_nil_v();  /* sentinel: will be checked below */
        hframe.next = L->hnd_top;
        L->hnd_top = &hframe;

        /* We override ls_signal_condition behavior by checking for
         * handler_case-style handlers.  But since we control the
         * stack, we do this directly: replace the signal call path
         * with a setjmp-based approach. */

        /* Actually, let's use a simpler approach: install a real handler
         * that performs a non-local exit via longjmp. */
        L->hnd_top = hframe.next;  /* undo */

        /* Use a condition-catching approach: wrap the body with
         * our own signal intercept. */

        /* Strategy: we temporarily set up a handler that stores the
         * condition in the escape frame and longjmps. We implement
         * this by directly manipulating the handler stack with a
         * custom handler that has a special pointer we recognize. */

        /* Simplest correct approach for a minimal CLOS: use the native
         * handler stack. The handler function will be a special value
         * that our signal machinery recognizes as "longjmp to escape". */

        /* For the minimal implementation, we use the escape frame's
         * tag to hold the type_cls pointer and the signal function
         * checks for handler_case escape frames first. */
        esc.tag = ls_wrap(LS_T_CLASS, type_cls);

        ls_value_t result = ls_apply(L, body_thunk, 0, NULL);
        L->esc_top = esc.next;
        return result;
    } else {
        /* Landed here via longjmp -- the condition is in esc.value. */
        L->esc_top = esc.next;
        /* Call the handler function with the condition. */
        ls_value_t cond_val = esc.value;
        return ls_apply(L, handler_fn, 1, &cond_val);
    }
}

/* Enhanced signal that checks for handler-case escape frames. */
int ls_signal_condition_full(ls_state_t *L, ls_value_t condition) {
    ls_condition_t *cond = (ls_condition_t *)condition.u.ptr;
    ls_class_t *cond_class = cond->class_;

    /* First check for handler-case escape frames. */
    ls_escape_t *esc = L->esc_top;
    while (esc) {
        if (esc->kind == 2 && LS_IS(esc->tag, LS_T_CLASS)) {
            ls_class_t *handler_type = ls_class_p(esc->tag);
            if (subclassp(cond_class, handler_type)) {
                esc->value = condition;
                longjmp(esc->buf, 1);
            }
        }
        esc = esc->next;
    }

    /* Then walk the handler-bind stack. */
    ls_handler_t *h = L->hnd_top;
    while (h) {
        if (subclassp(cond_class, h->type)) {
            ls_value_t hfn = h->fn;
            if (!LS_NILP(hfn)) {
                ls_value_t carg = condition;
                ls_apply(L, hfn, 1, &carg);
            }
        }
        h = h->next;
    }
    return 0;
}

/* (%restart-case restart-specs body-thunk)
 * restart-specs is a list of (name invoke-fn &key test report interactive).
 * Establishes restarts, runs body-thunk, then tears down restarts. */
static ls_value_t bi_restart_case(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "%restart-case", nargs, 2, 2); return ls_nil_v(); }
    ls_value_t specs = A(0);
    ls_value_t body_thunk = A(1);

    /* Push restarts. */
    int n_pushed = 0;
    ls_value_t sl = specs;
    while (LS_CONSP(sl)) {
        ls_value_t spec = LS_CAR(sl);
        if (LS_CONSP(spec)) {
            ls_value_t name_v = LS_CAR(spec);
            ls_value_t invoke_fn = LS_CONSP(LS_CDR(spec)) ? LS_CAR(LS_CDR(spec)) : ls_nil_v();
            const char *rname = NULL;
            if (LS_IS(name_v, LS_T_SYMBOL))
                rname = ls_symbol_p(name_v)->name->chars;
            ls_restart_t *r = make_restart(L, rname, invoke_fn);

            /* Parse optional :test, :report, :interactive from rest. */
            ls_value_t rest = LS_CONSP(LS_CDR(spec)) ? LS_CDR(LS_CDR(spec)) : ls_nil_v();
            while (LS_CONSP(rest) && LS_CONSP(LS_CDR(rest))) {
                ls_value_t key = LS_CAR(rest);
                ls_value_t val = LS_CAR(LS_CDR(rest));
                if (LS_IS(key, LS_T_SYMBOL)) {
                    ls_symbol_t *ks = ls_symbol_p(key);
                    if (ks == intern_kw(L, "TEST")) r->test_fn = val;
                    else if (ks == intern_kw(L, "REPORT")) r->report_fn = val;
                    else if (ks == intern_kw(L, "INTERACTIVE")) r->interactive_fn = val;
                }
                rest = LS_CDR(LS_CDR(rest));
            }
            ls_push_restart(L, r);
            n_pushed++;
        }
        sl = LS_CDR(sl);
    }

    /* Set up escape frame so that invoke-restart can longjmp back here. */
    ls_escape_t esc;
    esc.kind = 2;
    esc.tag = ls_nil_v();  /* no class tag -- this is for restarts */
    esc.value = ls_nil_v();
    esc.next = L->esc_top;
    L->esc_top = &esc;

    ls_value_t result;
    if (setjmp(esc.buf) == 0) {
        result = ls_apply(L, body_thunk, 0, NULL);
    } else {
        result = esc.value;
    }

    L->esc_top = esc.next;
    for (int i = 0; i < n_pushed; i++)
        ls_pop_restart(L);
    return result;
}

/* (%restart-bind restart-specs body-thunk) -- like restart-case but
 * does not establish a non-local exit boundary. */
static ls_value_t bi_restart_bind(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "%restart-bind", nargs, 2, 2); return ls_nil_v(); }
    ls_value_t specs = A(0);
    ls_value_t body_thunk = A(1);

    int n_pushed = 0;
    ls_value_t sl = specs;
    while (LS_CONSP(sl)) {
        ls_value_t spec = LS_CAR(sl);
        if (LS_CONSP(spec)) {
            ls_value_t name_v = LS_CAR(spec);
            ls_value_t invoke_fn = LS_CONSP(LS_CDR(spec)) ? LS_CAR(LS_CDR(spec)) : ls_nil_v();
            const char *rname = NULL;
            if (LS_IS(name_v, LS_T_SYMBOL))
                rname = ls_symbol_p(name_v)->name->chars;
            ls_restart_t *r = make_restart(L, rname, invoke_fn);
            ls_push_restart(L, r);
            n_pushed++;
        }
        sl = LS_CDR(sl);
    }

    ls_value_t result = ls_apply(L, body_thunk, 0, NULL);

    for (int i = 0; i < n_pushed; i++)
        ls_pop_restart(L);
    return result;
}

/* (find-restart name) */
static ls_value_t bi_find_restart(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "find-restart", nargs, 1, 1); return ls_nil_v(); }
    ls_symbol_t *name = ls_symbol_p(A(0));
    if (!name) { ls_type_error(L, "symbol", A(0)); return ls_nil_v(); }
    ls_restart_t *r = ls_find_restart(L, name);
    if (!r) return ls_nil_v();
    return ls_wrap(LS_T_RESTART, r);
}

/* (invoke-restart name &rest args) */
static ls_value_t bi_invoke_restart(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "invoke-restart", nargs, 1, -1); return ls_nil_v(); }
    ls_restart_t *r = NULL;
    if (LS_IS(A(0), LS_T_RESTART)) {
        r = (ls_restart_t *)A(0).u.ptr;
    } else if (LS_IS(A(0), LS_T_SYMBOL)) {
        r = ls_find_restart(L, ls_symbol_p(A(0)));
    }
    if (!r) {
        ls_error(L, "invoke-restart: restart not found");
        return ls_nil_v();
    }
    return ls_invoke_restart(L, r, nargs - 1, args + 1);
}

/* (compute-restarts) */
static ls_value_t bi_compute_restarts(ls_state_t *L, int nargs, ls_value_t *args) {
    (void)nargs; (void)args;
    return ls_compute_restarts(L);
}

/* (restart-name restart) */
static ls_value_t bi_restart_name(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "restart-name", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_RESTART)) { ls_type_error(L, "restart", A(0)); return ls_nil_v(); }
    ls_restart_t *r = (ls_restart_t *)A(0).u.ptr;
    if (r->name) return ls_wrap(LS_T_SYMBOL, r->name);
    return ls_nil_v();
}

/* (make-condition type &rest initargs) */
static ls_value_t bi_make_condition(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "make-condition", nargs, 1, -1); return ls_nil_v(); }
    ls_class_t *cls = NULL;
    if (LS_IS(A(0), LS_T_CLASS)) cls = ls_class_p(A(0));
    else if (LS_IS(A(0), LS_T_SYMBOL)) {
        ls_symbol_t *s = ls_symbol_p(A(0));
        if (s->sym_flags & LS_SYM_HAS_VALUE && LS_IS(s->value, LS_T_CLASS))
            cls = ls_class_p(s->value);
    }
    if (!cls) { ls_error(L, "make-condition: not a condition class"); return ls_nil_v(); }

    ls_value_t ia = ls_nil_v();
    ls_gc_push_root(L, &ia);
    for (int i = nargs - 1; i >= 1; i--)
        ia = ls_cons(L, args[i], ia);
    ls_gc_pop_root(L);
    return ls_make_condition(L, cls, ia);
}

/* (condition-format-control cond) */
static ls_value_t bi_condition_format_control(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "condition-format-control", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_CONDITION)) { ls_type_error(L, "condition", A(0)); return ls_nil_v(); }
    ls_condition_t *c = (ls_condition_t *)A(0).u.ptr;
    return c->format_control;
}

/* (condition-format-arguments cond) */
static ls_value_t bi_condition_format_args(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "condition-format-arguments", nargs, 1, 1); return ls_nil_v(); }
    if (!LS_IS(A(0), LS_T_CONDITION)) { ls_type_error(L, "condition", A(0)); return ls_nil_v(); }
    ls_condition_t *c = (ls_condition_t *)A(0).u.ptr;
    return c->format_arguments;
}

/* (%defclass name supers slots) -- C-level defclass.
 * supers is a list of class-name symbols, slots is a list of slot-name symbols. */
static ls_value_t bi_defclass(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 3) { ls_arity_error(L, "%defclass", nargs, 3, 3); return ls_nil_v(); }
    ls_symbol_t *name_sym = ls_symbol_p(A(0));
    if (!name_sym) { ls_type_error(L, "symbol", A(0)); return ls_nil_v(); }

    /* Resolve super class symbols to class objects. */
    ls_value_t supers = ls_nil_v();
    ls_gc_push_root(L, &supers);
    ls_value_t sl = A(1);
    while (LS_CONSP(sl)) {
        ls_symbol_t *ss = ls_symbol_p(LS_CAR(sl));
        if (!ss) { ls_gc_pop_root(L); ls_type_error(L, "symbol", LS_CAR(sl)); return ls_nil_v(); }
        if (!(ss->sym_flags & LS_SYM_HAS_VALUE) || !LS_IS(ss->value, LS_T_CLASS)) {
            ls_gc_pop_root(L);
            ls_error(L, "defclass: %s is not a class", ss->name->chars);
            return ls_nil_v();
        }
        supers = ls_cons(L, ss->value, supers);
        sl = LS_CDR(sl);
    }
    supers = ls_list_reverse(L, supers);

    /* If no supers given, default to standard-object. */
    if (LS_NILP(supers) && L->class_standard_object)
        supers = list1(L, ls_wrap(LS_T_CLASS, L->class_standard_object));

    ls_class_t *cls = ls_define_class(L, name_sym->name->chars, supers, A(2));
    ls_gc_pop_root(L);
    return ls_wrap(LS_T_CLASS, cls);
}

/* (%defgeneric name lambda-list) */
static ls_value_t bi_defgeneric(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 2) { ls_arity_error(L, "%defgeneric", nargs, 2, 2); return ls_nil_v(); }
    ls_symbol_t *name_sym = ls_symbol_p(A(0));
    if (!name_sym) { ls_type_error(L, "symbol", A(0)); return ls_nil_v(); }
    ls_generic_t *gf = ls_define_generic(L, name_sym->name->chars, A(1));
    return ls_wrap(LS_T_GENERIC, gf);
}

/* (%defmethod generic-name specializers qualifiers lambda) */
static ls_value_t bi_defmethod(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 4) { ls_arity_error(L, "%defmethod", nargs, 4, 4); return ls_nil_v(); }

    /* Find or error on the generic function. */
    ls_generic_t *gf = NULL;
    if (LS_IS(A(0), LS_T_GENERIC)) {
        gf = (ls_generic_t *)A(0).u.ptr;
    } else if (LS_IS(A(0), LS_T_SYMBOL)) {
        ls_symbol_t *gs = ls_symbol_p(A(0));
        if (gs->sym_flags & LS_SYM_HAS_FN && LS_IS(gs->function, LS_T_GENERIC))
            gf = (ls_generic_t *)gs->function.u.ptr;
    }
    if (!gf) { ls_error(L, "defmethod: no generic function found"); return ls_nil_v(); }

    /* Resolve specializer symbols to classes. */
    ls_value_t specs = ls_nil_v();
    ls_gc_push_root(L, &specs);
    ls_value_t sl = A(1);
    while (LS_CONSP(sl)) {
        ls_value_t sv = LS_CAR(sl);
        ls_class_t *spec = NULL;
        if (LS_IS(sv, LS_T_CLASS)) {
            spec = ls_class_p(sv);
        } else if (LS_IS(sv, LS_T_SYMBOL)) {
            ls_symbol_t *ss = ls_symbol_p(sv);
            if (ss->sym_flags & LS_SYM_HAS_VALUE && LS_IS(ss->value, LS_T_CLASS))
                spec = ls_class_p(ss->value);
            /* T symbol means "any type". */
            if (!spec && ss == L->sym_t)
                spec = L->class_t;
        }
        if (!spec) {
            ls_gc_pop_root(L);
            ls_error(L, "defmethod: invalid specializer");
            return ls_nil_v();
        }
        specs = ls_cons(L, ls_wrap(LS_T_CLASS, spec), specs);
        sl = LS_CDR(sl);
    }
    specs = ls_list_reverse(L, specs);
    ls_gc_pop_root(L);

    ls_method_t *m = ls_add_method(L, gf, specs, A(2), A(3));
    return ls_wrap(LS_T_METHOD, m);
}

/* (%call-generic gf &rest args) -- explicit generic dispatch. */
static ls_value_t bi_call_generic(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) { ls_arity_error(L, "%call-generic", nargs, 1, -1); return ls_nil_v(); }
    ls_generic_t *gf = NULL;
    if (LS_IS(A(0), LS_T_GENERIC)) gf = (ls_generic_t *)A(0).u.ptr;
    else if (LS_IS(A(0), LS_T_SYMBOL)) {
        ls_symbol_t *s = ls_symbol_p(A(0));
        if (s->sym_flags & LS_SYM_HAS_FN && LS_IS(s->function, LS_T_GENERIC))
            gf = (ls_generic_t *)s->function.u.ptr;
    }
    if (!gf) { ls_error(L, "not a generic function"); return ls_nil_v(); }
    return ls_dispatch_generic(L, gf, nargs - 1, args + 1);
}

/* ============================================================
 *  BUILT-IN CLASS HIERARCHY INITIALIZATION
 * ============================================================ */

/* Helper: create a builtin class with given supers, no user slots.
 * The class is finalized and bound to its symbol. */
static ls_class_t *bootstrap_class(ls_state_t *L, const char *name,
                                   ls_value_t supers) {
    ls_class_t *cls = make_class(L, name, supers, ls_nil_v());
    /* Manually set CPL for bootstrap classes that have no supers yet.
     * For T, which has no supers, CPL is just (T). */
    if (LS_NILP(supers)) {
        cls->precedence_list = list1(L, ls_wrap(LS_T_CLASS, cls));
        cls->effective_slots = ls_nil_v();
        cls->n_slots = 0;
        cls->instance_size = (uint32_t)sizeof(ls_instance_t);
        cls->slot_index = ls_hash_new(L, LS_HASH_EQ, 4);
        cls->finalized = 1;
    } else {
        finalize_class(L, cls);
    }
    /* Bind to symbol. */
    cls->name->value = ls_wrap(LS_T_CLASS, cls);
    cls->name->sym_flags |= LS_SYM_HAS_VALUE;
    return cls;
}

/* Create the entire built-in class hierarchy and register all CLOS
 * and condition system builtins. */
void ls_init_clos(ls_state_t *L) {
    /* ---- Phase 1: bootstrap the root classes ---- */

    /* T is the root of the type hierarchy. */
    L->class_t = bootstrap_class(L, "T", ls_nil_v());

    ls_value_t t_list = list1(L, ls_wrap(LS_T_CLASS, L->class_t));
    ls_gc_push_root(L, &t_list);

    /* STANDARD-OBJECT inherits from T. */
    L->class_standard_object = bootstrap_class(L, "STANDARD-OBJECT", t_list);

    ls_value_t so_list = list1(L, ls_wrap(LS_T_CLASS, L->class_standard_object));
    ls_gc_push_root(L, &so_list);

    /* ---- Phase 2: numeric tower ---- */
    L->class_number = bootstrap_class(L, "NUMBER", t_list);

    ls_value_t num_list = list1(L, ls_wrap(LS_T_CLASS, L->class_number));
    ls_gc_push_root(L, &num_list);

    /* REAL inherits NUMBER.  We don't store this on L-> but it is in
     * the class hierarchy for completeness. */
    ls_class_t *class_real = bootstrap_class(L, "REAL", num_list);

    ls_value_t real_list = list1(L, ls_wrap(LS_T_CLASS, class_real));
    ls_gc_push_root(L, &real_list);

    /* RATIONAL inherits REAL. */
    ls_class_t *class_rational = bootstrap_class(L, "RATIONAL", real_list);

    ls_value_t rat_list = list1(L, ls_wrap(LS_T_CLASS, class_rational));
    ls_gc_push_root(L, &rat_list);

    L->class_integer = bootstrap_class(L, "INTEGER", rat_list);

    ls_value_t int_list = list1(L, ls_wrap(LS_T_CLASS, L->class_integer));
    ls_gc_push_root(L, &int_list);

    L->class_fixnum = bootstrap_class(L, "FIXNUM", int_list);
    L->class_float = bootstrap_class(L, "FLOAT", real_list);

    /* ---- Phase 3: standard data types ---- */
    L->class_cons = bootstrap_class(L, "CONS", t_list);
    L->class_symbol = bootstrap_class(L, "SYMBOL", t_list);
    L->class_string = bootstrap_class(L, "STRING", t_list);
    L->class_vector = bootstrap_class(L, "VECTOR", t_list);
    L->class_hashtable = bootstrap_class(L, "HASH-TABLE", t_list);
    L->class_function = bootstrap_class(L, "FUNCTION", t_list);

    /* Additional types in the hierarchy. */
    bootstrap_class(L, "SEQUENCE", t_list);
    bootstrap_class(L, "LIST", t_list);
    bootstrap_class(L, "ARRAY", t_list);
    bootstrap_class(L, "CHARACTER", t_list);
    bootstrap_class(L, "STREAM", t_list);
    bootstrap_class(L, "PACKAGE", t_list);
    bootstrap_class(L, "PATHNAME", t_list);

    /* ---- Phase 4: condition hierarchy ---- */
    L->class_condition = bootstrap_class(L, "CONDITION", so_list);

    ls_value_t cond_list = list1(L, ls_wrap(LS_T_CLASS, L->class_condition));
    ls_gc_push_root(L, &cond_list);

    /* WARNING and SERIOUS-CONDITION. */
    ls_class_t *class_warning = bootstrap_class(L, "WARNING", cond_list);
    ls_class_t *class_serious = bootstrap_class(L, "SERIOUS-CONDITION", cond_list);
    (void)class_warning;

    ls_value_t serious_list = list1(L, ls_wrap(LS_T_CLASS, class_serious));
    ls_gc_push_root(L, &serious_list);

    L->class_error = bootstrap_class(L, "ERROR", serious_list);

    ls_value_t err_list = list1(L, ls_wrap(LS_T_CLASS, L->class_error));
    ls_gc_push_root(L, &err_list);

    L->class_simple_error = bootstrap_class(L, "SIMPLE-ERROR", err_list);
    L->class_type_error = bootstrap_class(L, "TYPE-ERROR", err_list);
    L->class_arith_error = bootstrap_class(L, "ARITHMETIC-ERROR", err_list);
    L->class_undefined_function = bootstrap_class(L, "UNDEFINED-FUNCTION", err_list);
    L->class_unbound_variable = bootstrap_class(L, "UNBOUND-VARIABLE", err_list);

    /* Additional standard condition types. */
    bootstrap_class(L, "SIMPLE-CONDITION", cond_list);
    bootstrap_class(L, "SIMPLE-WARNING",
                    ls_cons(L, ls_wrap(LS_T_CLASS, class_warning), ls_nil_v()));
    bootstrap_class(L, "CELL-ERROR", err_list);
    bootstrap_class(L, "CONTROL-ERROR", err_list);
    bootstrap_class(L, "PROGRAM-ERROR", err_list);
    bootstrap_class(L, "PARSE-ERROR", err_list);
    bootstrap_class(L, "STREAM-ERROR", err_list);
    bootstrap_class(L, "FILE-ERROR", err_list);
    bootstrap_class(L, "PACKAGE-ERROR", err_list);
    bootstrap_class(L, "PRINT-NOT-READABLE", err_list);
    bootstrap_class(L, "DIVISION-BY-ZERO",
                    ls_cons(L, ls_wrap(LS_T_CLASS, L->class_arith_error), ls_nil_v()));
    bootstrap_class(L, "FLOATING-POINT-OVERFLOW",
                    ls_cons(L, ls_wrap(LS_T_CLASS, L->class_arith_error), ls_nil_v()));
    bootstrap_class(L, "FLOATING-POINT-UNDERFLOW",
                    ls_cons(L, ls_wrap(LS_T_CLASS, L->class_arith_error), ls_nil_v()));
    bootstrap_class(L, "END-OF-FILE",
                    ls_cons(L, ls_wrap(LS_T_CLASS, L->class_error), ls_nil_v()));
    bootstrap_class(L, "STORAGE-CONDITION",
                    ls_cons(L, ls_wrap(LS_T_CLASS, class_serious), ls_nil_v()));

    /* Pop GC roots (in reverse order). */
    ls_gc_pop_root(L);  /* err_list */
    ls_gc_pop_root(L);  /* serious_list */
    ls_gc_pop_root(L);  /* cond_list */
    ls_gc_pop_root(L);  /* int_list */
    ls_gc_pop_root(L);  /* rat_list */
    ls_gc_pop_root(L);  /* real_list */
    ls_gc_pop_root(L);  /* num_list */
    ls_gc_pop_root(L);  /* so_list */
    ls_gc_pop_root(L);  /* t_list */

    /* ---- Phase 5: register all builtins ---- */
    const char *cl = "COMMON-LISP";

    /* CLOS fundamentals. */
    ls_defun(L, cl, "class-of",           bi_class_of, 1, 1);
    ls_defun(L, cl, "find-class",         bi_find_class, 1, 2);
    ls_defun(L, cl, "make-instance",      bi_make_instance, 1, -1);
    ls_defun(L, cl, "slot-value",         bi_slot_value, 2, 2);
    ls_defun(L, cl, "set-slot-value",     bi_set_slot_value, 3, 3);
    ls_defun(L, cl, "slot-boundp",        bi_slot_boundp, 2, 2);
    ls_defun(L, cl, "typep",              bi_typep, 2, 2);
    ls_defun(L, cl, "subtypep",           bi_subtypep, 2, 2);
    ls_defun(L, cl, "class-name",         bi_class_name, 1, 1);
    ls_defun(L, cl, "class-precedence-list", bi_class_cpl, 1, 1);
    ls_defun(L, cl, "class-direct-superclasses", bi_class_direct_supers, 1, 1);
    ls_defun(L, cl, "class-slots",        bi_class_slots, 1, 1);

    /* Defclass / defgeneric / defmethod. */
    ls_defun(L, cl, "%defclass",          bi_defclass, 3, 3);
    ls_defun(L, cl, "%defgeneric",        bi_defgeneric, 2, 2);
    ls_defun(L, cl, "%defmethod",         bi_defmethod, 4, 4);
    ls_defun(L, cl, "%call-generic",      bi_call_generic, 1, -1);

    /* Call-next-method support. */
    ls_defun(L, cl, "call-next-method",   bi_call_next_method, 0, -1);
    ls_defun(L, cl, "next-method-p",      bi_next_method_p, 0, 0);

    /* Condition system. */
    ls_defun(L, cl, "signal",             bi_signal, 1, -1);
    ls_defun(L, cl, "cerror",             bi_cerror, 1, -1);
    ls_defun(L, cl, "make-condition",     bi_make_condition, 1, -1);
    ls_defun(L, cl, "condition-format-control",   bi_condition_format_control, 1, 1);
    ls_defun(L, cl, "condition-format-arguments", bi_condition_format_args, 1, 1);

    /* Handler / restart machinery. */
    ls_defun(L, cl, "%handler-bind",      bi_handler_bind, 2, 2);
    ls_defun(L, cl, "%handler-case",      bi_handler_case, 3, 3);
    ls_defun(L, cl, "%restart-case",      bi_restart_case, 2, 2);
    ls_defun(L, cl, "%restart-bind",      bi_restart_bind, 2, 2);
    ls_defun(L, cl, "find-restart",       bi_find_restart, 1, 1);
    ls_defun(L, cl, "invoke-restart",     bi_invoke_restart, 1, -1);
    ls_defun(L, cl, "compute-restarts",   bi_compute_restarts, 0, 0);
    ls_defun(L, cl, "restart-name",       bi_restart_name, 1, 1);
}
/*** End: lsclos.c ***/

/*** Begin: lsvm.c ***/
/* lsvm.c -- bytecode compiler + stack-based virtual machine for Litesrpent.
 *
 * The compiler walks an S-expression and emits a flat array of 32-bit
 * instructions into an ls_proto_t.  The VM executes those instructions
 * with a simple value stack.
 *
 * Special forms handled directly by the compiler:
 *   quote, if, progn, let, let*, setq, lambda, and, or,
 *   when, unless, cond, function
 *
 * Everything else is compiled as a function call.
 */

/* ================================================================
 *  Compiler state
 * ================================================================ */

/* A local variable binding known at compile time. */
typedef struct {
    ls_symbol_t *sym;
    int          slot;      /* index into the locals array */
} ls_local_t;

/* An upvalue reference (captured from an enclosing scope). */
typedef struct {
    ls_symbol_t *sym;
    int          index;     /* index into upvals array at runtime */
    int          is_local;  /* 1 = captured from direct parent's locals */
    int          parent_slot; /* slot in parent locals/upvals */
} ls_upval_desc_t;

/* Maximum limits for a single compilation unit. */
#define COMP_MAX_CODE   4096
#define COMP_MAX_CONSTS 512
#define COMP_MAX_LOCALS 256
#define COMP_MAX_UPVALS 64
#define COMP_MAX_INNER  64

typedef struct ls_compiler ls_compiler_t;

struct ls_compiler {
    ls_state_t    *L;
    ls_compiler_t *parent;           /* enclosing compiler (for upvals) */

    uint32_t       code[COMP_MAX_CODE];
    int            code_len;

    ls_value_t     consts[COMP_MAX_CONSTS];
    int            n_consts;

    ls_local_t     locals[COMP_MAX_LOCALS];
    int            n_locals;
    int            scope_base;       /* first local of current scope */

    ls_upval_desc_t upvals[COMP_MAX_UPVALS];
    int            n_upvals;

    /* Nested lambda protos compiled inside this one. */
    ls_proto_t    *inner_protos[COMP_MAX_INNER];
    int            n_inner;

    int            n_args;           /* parameter count (for this lambda) */
    int            n_opt;
    int            has_rest;
    ls_symbol_t   *name;
};

/* ------------------------------------------------------------------ */
/*  Compiler helpers                                                   */
/* ------------------------------------------------------------------ */

static void emit(ls_compiler_t *c, uint32_t instr) {
    if (c->code_len >= COMP_MAX_CODE)
        ls_error(c->L, "bytecode compiler: code buffer overflow");
    c->code[c->code_len++] = instr;
}

static int emit_placeholder(ls_compiler_t *c) {
    int pos = c->code_len;
    emit(c, OP_MAKE(OP_NOP, 0));
    return pos;
}

static void patch_jump(ls_compiler_t *c, int pos, ls_opcode_t op) {
    int offset = c->code_len - pos - 1;
    c->code[pos] = OP_MAKE(op, (uint32_t)(offset & 0x00FFFFFF));
}

static void patch_jump_to(ls_compiler_t *c, int pos, ls_opcode_t op, int target) {
    int offset = target - pos - 1;
    c->code[pos] = OP_MAKE(op, (uint32_t)(offset & 0x00FFFFFF));
}

static int add_const(ls_compiler_t *c, ls_value_t v) {
    /* Deduplicate fixnums and symbols. */
    for (int i = 0; i < c->n_consts; i++) {
        if (c->consts[i].tag == v.tag && c->consts[i].u.ptr == v.u.ptr &&
            (v.tag == LS_T_SYMBOL || v.tag == LS_T_FIXNUM || v.tag == LS_T_NIL || v.tag == LS_T_T))
            return i;
    }
    if (c->n_consts >= COMP_MAX_CONSTS)
        ls_error(c->L, "bytecode compiler: constant pool overflow");
    c->consts[c->n_consts] = v;
    return c->n_consts++;
}

static int add_local(ls_compiler_t *c, ls_symbol_t *sym) {
    if (c->n_locals >= COMP_MAX_LOCALS)
        ls_error(c->L, "bytecode compiler: too many locals");
    int slot = c->n_locals;
    c->locals[c->n_locals].sym  = sym;
    c->locals[c->n_locals].slot = slot;
    c->n_locals++;
    return slot;
}

static int find_local(ls_compiler_t *c, ls_symbol_t *sym) {
    for (int i = c->n_locals - 1; i >= 0; i--) {
        if (c->locals[i].sym == sym)
            return c->locals[i].slot;
    }
    return -1;
}

/* Resolve or create an upvalue reference for sym.  Returns the upval
 * index or -1 if the symbol is not reachable lexically. */
static int resolve_upval(ls_compiler_t *c, ls_symbol_t *sym) {
    /* Already captured? */
    for (int i = 0; i < c->n_upvals; i++) {
        if (c->upvals[i].sym == sym)
            return i;
    }
    if (!c->parent) return -1;

    /* Try parent's locals first. */
    int pslot = find_local(c->parent, sym);
    if (pslot >= 0) {
        if (c->n_upvals >= COMP_MAX_UPVALS)
            ls_error(c->L, "bytecode compiler: too many upvalues");
        int idx = c->n_upvals++;
        c->upvals[idx].sym         = sym;
        c->upvals[idx].index       = idx;
        c->upvals[idx].is_local    = 1;
        c->upvals[idx].parent_slot = pslot;
        return idx;
    }

    /* Try parent's upvals (transitive capture). */
    int pidx = resolve_upval(c->parent, sym);
    if (pidx >= 0) {
        if (c->n_upvals >= COMP_MAX_UPVALS)
            ls_error(c->L, "bytecode compiler: too many upvalues");
        int idx = c->n_upvals++;
        c->upvals[idx].sym         = sym;
        c->upvals[idx].index       = idx;
        c->upvals[idx].is_local    = 0;
        c->upvals[idx].parent_slot = pidx;
        return idx;
    }
    return -1;
}

/* ------------------------------------------------------------------ */
/*  Forward declaration                                                */
/* ------------------------------------------------------------------ */
static void compile_form(ls_compiler_t *c, ls_value_t form, int tail);

/* ------------------------------------------------------------------ */
/*  Compile atoms                                                      */
/* ------------------------------------------------------------------ */

static void compile_atom(ls_compiler_t *c, ls_value_t form) {
    switch (form.tag) {
    case LS_T_NIL:
        emit(c, OP_MAKE(OP_NIL, 0));
        return;
    case LS_T_T:
        emit(c, OP_MAKE(OP_T, 0));
        return;
    case LS_T_FIXNUM: {
        int64_t val = form.u.fixnum;
        if (val >= -8388608 && val <= 8388607) {
            emit(c, OP_MAKE(OP_FIXNUM, (uint32_t)((int32_t)val & 0x00FFFFFF)));
        } else {
            int ci = add_const(c, form);
            emit(c, OP_MAKE(OP_CONST, ci));
        }
        return;
    }
    case LS_T_FLONUM:
    case LS_T_STRING:
    case LS_T_CHAR: {
        int ci = add_const(c, form);
        emit(c, OP_MAKE(OP_CONST, ci));
        return;
    }
    case LS_T_SYMBOL: {
        ls_symbol_t *sym = (ls_symbol_t *)form.u.ptr;
        /* Is it a keyword?  Keywords evaluate to themselves. */
        if (sym->sym_flags & LS_SYM_KEYWORD) {
            int ci = add_const(c, form);
            emit(c, OP_MAKE(OP_CONST, ci));
            return;
        }
        /* Local? */
        int slot = find_local(c, sym);
        if (slot >= 0) {
            emit(c, OP_MAKE(OP_LOAD_LOCAL, slot));
            return;
        }
        /* Upvalue? */
        int uv = resolve_upval(c, sym);
        if (uv >= 0) {
            emit(c, OP_MAKE(OP_LOAD_UPVAL, uv));
            return;
        }
        /* Global. */
        int ci = add_const(c, form);
        emit(c, OP_MAKE(OP_LOAD_GLOBAL, ci));
        return;
    }
    default:
        /* Unknown atom -- shove it into the constant pool. */
        {
            int ci = add_const(c, form);
            emit(c, OP_MAKE(OP_CONST, ci));
        }
        return;
    }
}

/* ------------------------------------------------------------------ */
/*  Compile special forms                                              */
/* ------------------------------------------------------------------ */

/* (quote datum) */
static void compile_quote(ls_compiler_t *c, ls_value_t args) {
    if (args.tag != LS_T_CONS)
        ls_error(c->L, "quote: need exactly 1 argument");
    ls_value_t datum = LS_CAR(args);
    if (datum.tag == LS_T_NIL)
        emit(c, OP_MAKE(OP_NIL, 0));
    else if (datum.tag == LS_T_T)
        emit(c, OP_MAKE(OP_T, 0));
    else {
        int ci = add_const(c, datum);
        emit(c, OP_MAKE(OP_CONST, ci));
    }
}

/* (if test then [else]) */
static void compile_if(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "if: need test");
    ls_value_t test = LS_CAR(args);
    ls_value_t rest = LS_CDR(args);
    if (rest.tag != LS_T_CONS) ls_error(c->L, "if: need then");
    ls_value_t then_form = LS_CAR(rest);
    ls_value_t else_tail = LS_CDR(rest);
    int has_else = (else_tail.tag == LS_T_CONS);

    compile_form(c, test, 0);
    int jmp_else = emit_placeholder(c);  /* JUMP_IF_NIL -> else */

    compile_form(c, then_form, tail);
    int jmp_end = -1;
    if (has_else) {
        jmp_end = emit_placeholder(c);   /* JUMP -> end */
    }

    patch_jump(c, jmp_else, OP_JUMP_IF_NIL);

    if (has_else) {
        compile_form(c, LS_CAR(else_tail), tail);
        patch_jump(c, jmp_end, OP_JUMP);
    } else {
        emit(c, OP_MAKE(OP_NIL, 0));     /* no else => nil */
    }
}

/* (progn form*) */
static void compile_progn(ls_compiler_t *c, ls_value_t forms, int tail) {
    if (forms.tag == LS_T_NIL) {
        emit(c, OP_MAKE(OP_NIL, 0));
        return;
    }
    while (forms.tag == LS_T_CONS) {
        ls_value_t form = LS_CAR(forms);
        ls_value_t rest = LS_CDR(forms);
        int is_last = (rest.tag != LS_T_CONS);
        compile_form(c, form, tail && is_last);
        if (!is_last) emit(c, OP_MAKE(OP_POP, 0));
        forms = rest;
    }
}

/* (let ((var init)...) body...) */
static void compile_let(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "let: missing bindings");
    ls_value_t bindings = LS_CAR(args);
    ls_value_t body     = LS_CDR(args);

    int saved_n_locals = c->n_locals;
    int saved_scope    = c->scope_base;
    c->scope_base = c->n_locals;

    /* Evaluate all inits, then bind all at once (parallel let). */
    int count = 0;
    ls_value_t b = bindings;
    while (b.tag == LS_T_CONS) {
        ls_value_t entry = LS_CAR(b);
        if (entry.tag == LS_T_SYMBOL) {
            /* (let ((x) ...) ...) - var bound to nil */
            emit(c, OP_MAKE(OP_NIL, 0));
        } else if (entry.tag == LS_T_CONS) {
            ls_value_t init_tail = LS_CDR(entry);
            if (init_tail.tag == LS_T_CONS)
                compile_form(c, LS_CAR(init_tail), 0);
            else
                emit(c, OP_MAKE(OP_NIL, 0));
        } else {
            ls_error(c->L, "let: bad binding form");
        }
        count++;
        b = LS_CDR(b);
    }

    /* Now create slots and store (in reverse order off the stack). */
    int *slots = (int *)alloca(count * sizeof(int));
    b = bindings;
    for (int i = 0; i < count; i++) {
        ls_value_t entry = LS_CAR(b);
        ls_symbol_t *sym;
        if (entry.tag == LS_T_SYMBOL)
            sym = (ls_symbol_t *)entry.u.ptr;
        else
            sym = (ls_symbol_t *)(LS_CAR(entry)).u.ptr;
        slots[i] = add_local(c, sym);
        b = LS_CDR(b);
    }
    /* Values are on the stack in order slots[0]..slots[count-1]; store
     * them from bottom to top so the first pushed value goes to slots[0]. */
    for (int i = count - 1; i >= 0; i--)
        emit(c, OP_MAKE(OP_STORE_LOCAL, slots[i]));

    compile_progn(c, body, tail);

    c->n_locals   = saved_n_locals;
    c->scope_base = saved_scope;
}

/* (let* ((var init)...) body...) -- sequential binding */
static void compile_letstar(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "let*: missing bindings");
    ls_value_t bindings = LS_CAR(args);
    ls_value_t body     = LS_CDR(args);

    int saved_n_locals = c->n_locals;
    int saved_scope    = c->scope_base;
    c->scope_base = c->n_locals;

    ls_value_t b = bindings;
    while (b.tag == LS_T_CONS) {
        ls_value_t entry = LS_CAR(b);
        ls_symbol_t *sym;
        ls_value_t init = ls_nil_v();
        if (entry.tag == LS_T_SYMBOL) {
            sym = (ls_symbol_t *)entry.u.ptr;
        } else if (entry.tag == LS_T_CONS) {
            sym = (ls_symbol_t *)(LS_CAR(entry)).u.ptr;
            ls_value_t init_tail = LS_CDR(entry);
            if (init_tail.tag == LS_T_CONS)
                init = LS_CAR(init_tail);
        } else {
            ls_error(c->L, "let*: bad binding form");
            return;
        }
        compile_form(c, init, 0);
        int slot = add_local(c, sym);
        emit(c, OP_MAKE(OP_STORE_LOCAL, slot));
        b = LS_CDR(b);
    }

    compile_progn(c, body, tail);

    c->n_locals   = saved_n_locals;
    c->scope_base = saved_scope;
}

/* (setq var val [var val ...]) */
static void compile_setq(ls_compiler_t *c, ls_value_t args) {
    while (args.tag == LS_T_CONS) {
        ls_value_t var_v = LS_CAR(args);
        args = LS_CDR(args);
        if (var_v.tag != LS_T_SYMBOL)
            ls_error(c->L, "setq: not a symbol");
        ls_symbol_t *sym = (ls_symbol_t *)var_v.u.ptr;

        if (args.tag != LS_T_CONS)
            ls_error(c->L, "setq: odd number of arguments");
        ls_value_t val = LS_CAR(args);
        args = LS_CDR(args);

        compile_form(c, val, 0);
        emit(c, OP_MAKE(OP_DUP, 0));   /* setq returns the value */

        int slot = find_local(c, sym);
        if (slot >= 0) {
            emit(c, OP_MAKE(OP_STORE_LOCAL, slot));
        } else {
            int uv = resolve_upval(c, sym);
            if (uv >= 0) {
                emit(c, OP_MAKE(OP_STORE_UPVAL, uv));
            } else {
                int ci = add_const(c, var_v);
                emit(c, OP_MAKE(OP_STORE_GLOBAL, ci));
            }
        }

        /* If there are more pairs, pop the intermediate result. */
        if (args.tag == LS_T_CONS)
            emit(c, OP_MAKE(OP_POP, 0));
    }
}

/* (and form*) -- short-circuit: returns nil on first nil, last value
 * otherwise. */
static void compile_and(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag == LS_T_NIL) {
        emit(c, OP_MAKE(OP_T, 0));     /* (and) => t */
        return;
    }
    int patch_slots[256];
    int n_patches = 0;

    while (args.tag == LS_T_CONS) {
        ls_value_t form = LS_CAR(args);
        ls_value_t rest = LS_CDR(args);
        int is_last = (rest.tag != LS_T_CONS);

        compile_form(c, form, tail && is_last);

        if (!is_last) {
            emit(c, OP_MAKE(OP_DUP, 0));
            patch_slots[n_patches++] = emit_placeholder(c); /* JUMP_IF_NIL -> end */
            emit(c, OP_MAKE(OP_POP, 0));
        }
        args = rest;
    }
    for (int i = 0; i < n_patches; i++)
        patch_jump(c, patch_slots[i], OP_JUMP_IF_NIL);
}

/* (or form*) -- short-circuit: returns first non-nil, else nil. */
static void compile_or(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag == LS_T_NIL) {
        emit(c, OP_MAKE(OP_NIL, 0));   /* (or) => nil */
        return;
    }
    int patch_slots[256];
    int n_patches = 0;

    while (args.tag == LS_T_CONS) {
        ls_value_t form = LS_CAR(args);
        ls_value_t rest = LS_CDR(args);
        int is_last = (rest.tag != LS_T_CONS);

        compile_form(c, form, tail && is_last);

        if (!is_last) {
            emit(c, OP_MAKE(OP_DUP, 0));
            patch_slots[n_patches++] = emit_placeholder(c); /* JUMP_IF_NOT_NIL -> end */
            emit(c, OP_MAKE(OP_POP, 0));
        }
        args = rest;
    }
    for (int i = 0; i < n_patches; i++)
        patch_jump(c, patch_slots[i], OP_JUMP_IF_NOT_NIL);
}

/* (when test body...) => (if test (progn body...)) */
static void compile_when(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "when: need test");
    ls_value_t test = LS_CAR(args);
    ls_value_t body = LS_CDR(args);

    compile_form(c, test, 0);
    int jmp = emit_placeholder(c);
    compile_progn(c, body, tail);
    int jmp_end = emit_placeholder(c);
    patch_jump(c, jmp, OP_JUMP_IF_NIL);
    emit(c, OP_MAKE(OP_NIL, 0));
    patch_jump(c, jmp_end, OP_JUMP);
}

/* (unless test body...) => (if (not test) (progn body...)) */
static void compile_unless(ls_compiler_t *c, ls_value_t args, int tail) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "unless: need test");
    ls_value_t test = LS_CAR(args);
    ls_value_t body = LS_CDR(args);

    compile_form(c, test, 0);
    int jmp = emit_placeholder(c);
    emit(c, OP_MAKE(OP_NIL, 0));
    int jmp_end = emit_placeholder(c);
    patch_jump(c, jmp, OP_JUMP_IF_NIL);
    compile_progn(c, body, tail);
    patch_jump(c, jmp_end, OP_JUMP);
}

/* (cond (test form*)...) */
static void compile_cond(ls_compiler_t *c, ls_value_t clauses, int tail) {
    int end_patches[256];
    int n_end = 0;

    while (clauses.tag == LS_T_CONS) {
        ls_value_t clause = LS_CAR(clauses);
        clauses = LS_CDR(clauses);
        if (clause.tag != LS_T_CONS)
            ls_error(c->L, "cond: bad clause");

        ls_value_t test = LS_CAR(clause);
        ls_value_t body = LS_CDR(clause);
        int is_last = (clauses.tag != LS_T_CONS);

        /* Check for (t ...) -- the default clause. */
        if (test.tag == LS_T_T || (test.tag == LS_T_SYMBOL &&
            (ls_symbol_t *)test.u.ptr == c->L->sym_t)) {
            if (body.tag == LS_T_NIL)
                emit(c, OP_MAKE(OP_T, 0));
            else
                compile_progn(c, body, tail);
            goto cond_end;
        }

        compile_form(c, test, 0);
        if (body.tag == LS_T_NIL) {
            /* (cond (test) ...) => test value itself is the result if
             * non-nil; but we need it on the stack either way. */
            emit(c, OP_MAKE(OP_DUP, 0));
            int skip = emit_placeholder(c);
            emit(c, OP_MAKE(OP_POP, 0));
            if (!is_last) {
                /* continue to next clause */
                patch_jump(c, skip, OP_JUMP_IF_NOT_NIL);
            } else {
                patch_jump(c, skip, OP_JUMP_IF_NOT_NIL);
                emit(c, OP_MAKE(OP_NIL, 0));
            }
            if (!is_last) {
                end_patches[n_end++] = emit_placeholder(c);
                /* Fall through to the nil-pop path. */
            }
            continue;
        }

        int next_clause = emit_placeholder(c);
        compile_progn(c, body, tail && is_last);
        if (!is_last)
            end_patches[n_end++] = emit_placeholder(c);
        patch_jump(c, next_clause, OP_JUMP_IF_NIL);
    }
    /* No clause matched => nil. */
    emit(c, OP_MAKE(OP_NIL, 0));

cond_end:
    for (int i = 0; i < n_end; i++)
        patch_jump(c, end_patches[i], OP_JUMP);
}

/* Compile a lambda and return the proto index in the parent's inner
 * proto array.  The lambda form is ((params...) body...). */
static int compile_lambda_inner(ls_compiler_t *parent, ls_value_t lambda_list,
                                ls_value_t body, ls_symbol_t *name);

/* (lambda (params...) body...) */
static void compile_lambda(ls_compiler_t *c, ls_value_t args) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "lambda: need params");
    ls_value_t params = LS_CAR(args);
    ls_value_t body   = LS_CDR(args);

    int proto_idx = compile_lambda_inner(c, params, body, NULL);
    emit(c, OP_MAKE(OP_CLOSURE, proto_idx));
}

/* (function name-or-lambda) */
static void compile_function_form(ls_compiler_t *c, ls_value_t args) {
    if (args.tag != LS_T_CONS) ls_error(c->L, "function: need argument");
    ls_value_t arg = LS_CAR(args);

    if (arg.tag == LS_T_SYMBOL) {
        /* #'name -- look up the function cell. */
        ls_symbol_t *sym = (ls_symbol_t *)arg.u.ptr;
        int slot = find_local(c, sym);
        if (slot >= 0) {
            emit(c, OP_MAKE(OP_LOAD_LOCAL, slot));
            return;
        }
        int uv = resolve_upval(c, sym);
        if (uv >= 0) {
            emit(c, OP_MAKE(OP_LOAD_UPVAL, uv));
            return;
        }
        /* Fall back to global function slot. */
        int ci = add_const(c, arg);
        emit(c, OP_MAKE(OP_LOAD_GLOBAL, ci));
        return;
    }
    if (arg.tag == LS_T_CONS) {
        /* #'(lambda ...) */
        ls_value_t head = LS_CAR(arg);
        if (head.tag == LS_T_SYMBOL && (ls_symbol_t *)head.u.ptr == c->L->sym_lambda) {
            compile_lambda(c, LS_CDR(arg));
            return;
        }
    }
    ls_error(c->L, "function: bad argument");
}

/* Compile a function call: (fn arg1 arg2 ...) */
static void compile_call(ls_compiler_t *c, ls_value_t head, ls_value_t args, int tail) {
    /* Compile the function position. */
    if (head.tag == LS_T_SYMBOL) {
        /* Try to resolve the symbol to look up function slot. */
        ls_symbol_t *sym = (ls_symbol_t *)head.u.ptr;
        int slot = find_local(c, sym);
        if (slot >= 0) {
            emit(c, OP_MAKE(OP_LOAD_LOCAL, slot));
        } else {
            int uv = resolve_upval(c, sym);
            if (uv >= 0) {
                emit(c, OP_MAKE(OP_LOAD_UPVAL, uv));
            } else {
                int ci = add_const(c, head);
                emit(c, OP_MAKE(OP_LOAD_GLOBAL, ci));
            }
        }
    } else {
        compile_form(c, head, 0);
    }

    /* Compile arguments left-to-right. */
    int nargs = 0;
    ls_value_t a = args;
    while (a.tag == LS_T_CONS) {
        compile_form(c, LS_CAR(a), 0);
        nargs++;
        a = LS_CDR(a);
    }

    if (tail)
        emit(c, OP_MAKE(OP_TAILCALL, nargs));
    else
        emit(c, OP_MAKE(OP_CALL, nargs));
}

/* ------------------------------------------------------------------ */
/*  Main form dispatcher                                               */
/* ------------------------------------------------------------------ */

static void compile_form(ls_compiler_t *c, ls_value_t form, int tail) {
    ls_state_t *L = c->L;

    if (form.tag != LS_T_CONS) {
        compile_atom(c, form);
        return;
    }

    ls_value_t head = LS_CAR(form);
    ls_value_t args = LS_CDR(form);

    if (head.tag == LS_T_SYMBOL) {
        ls_symbol_t *sym = (ls_symbol_t *)head.u.ptr;

        /* Special forms. */
        if (sym == L->sym_quote)    { compile_quote(c, args); return; }
        if (sym == L->sym_if)       { compile_if(c, args, tail); return; }
        if (sym == L->sym_progn)    { compile_progn(c, args, tail); return; }
        if (sym == L->sym_let)      { compile_let(c, args, tail); return; }
        if (sym == L->sym_letstar)  { compile_letstar(c, args, tail); return; }
        if (sym == L->sym_setq)     { compile_setq(c, args); return; }
        if (sym == L->sym_lambda)   { compile_lambda(c, args); return; }
        if (sym == L->sym_function) { compile_function_form(c, args); return; }
        if (sym == L->sym_and)      { compile_and(c, args, tail); return; }
        if (sym == L->sym_or)       { compile_or(c, args, tail); return; }
        if (sym == L->sym_when)     { compile_when(c, args, tail); return; }
        if (sym == L->sym_unless)   { compile_unless(c, args, tail); return; }
        if (sym == L->sym_cond)     { compile_cond(c, args, tail); return; }

        /* Recognize builtin two-arg arithmetic/comparison for direct
         * opcodes instead of a full call. */
        ls_value_t a2 = LS_CDR(args);  /* rest after first arg */
        if (args.tag == LS_T_CONS && a2.tag == LS_T_CONS &&
            LS_CDR(a2).tag == LS_T_NIL) {
            /* Exactly two arguments. */
            ls_opcode_t binop = OP_NOP;
            ls_symbol_t *sn = sym;
            const char *nm = sn->name ? sn->name->chars : "";
            if      (!strcmp(nm, "+"))  binop = OP_ADD;
            else if (!strcmp(nm, "-"))  binop = OP_SUB;
            else if (!strcmp(nm, "*"))  binop = OP_MUL;
            else if (!strcmp(nm, "/"))  binop = OP_DIV;
            else if (!strcmp(nm, "MOD"))binop = OP_MOD;
            else if (!strcmp(nm, "REM"))binop = OP_MOD;
            else if (!strcmp(nm, "EQ")) binop = OP_EQ;
            else if (!strcmp(nm, "<"))  binop = OP_LT;
            else if (!strcmp(nm, "<=")) binop = OP_LE;
            else if (!strcmp(nm, ">"))  binop = OP_GT;
            else if (!strcmp(nm, ">=")) binop = OP_GE;
            else if (!strcmp(nm, "="))  binop = OP_NUMEQ;

            if (binop != OP_NOP) {
                compile_form(c, LS_CAR(args), 0);
                compile_form(c, LS_CAR(a2),   0);
                emit(c, OP_MAKE(binop, 0));
                return;
            }
        }
        /* One-arg builtins. */
        if (args.tag == LS_T_CONS && LS_CDR(args).tag == LS_T_NIL) {
            const char *nm = sym->name ? sym->name->chars : "";
            if (!strcmp(nm, "CAR")) {
                compile_form(c, LS_CAR(args), 0);
                emit(c, OP_MAKE(OP_CAR, 0));
                return;
            }
            if (!strcmp(nm, "CDR")) {
                compile_form(c, LS_CAR(args), 0);
                emit(c, OP_MAKE(OP_CDR, 0));
                return;
            }
            if (!strcmp(nm, "NOT") || !strcmp(nm, "NULL")) {
                compile_form(c, LS_CAR(args), 0);
                emit(c, OP_MAKE(OP_NOT, 0));
                return;
            }
            if (!strcmp(nm, "-")) {
                compile_form(c, LS_CAR(args), 0);
                emit(c, OP_MAKE(OP_NEG, 0));
                return;
            }
        }
        /* Two-arg cons. */
        if (args.tag == LS_T_CONS && a2.tag == LS_T_CONS &&
            LS_CDR(a2).tag == LS_T_NIL) {
            const char *nm = sym->name ? sym->name->chars : "";
            if (!strcmp(nm, "CONS")) {
                compile_form(c, LS_CAR(args), 0);
                compile_form(c, LS_CAR(a2),   0);
                emit(c, OP_MAKE(OP_CONS, 0));
                return;
            }
        }
        /* N-arg list. */
        {
            const char *nm = sym->name ? sym->name->chars : "";
            if (!strcmp(nm, "LIST")) {
                int n = 0;
                ls_value_t a = args;
                while (a.tag == LS_T_CONS) {
                    compile_form(c, LS_CAR(a), 0);
                    n++;
                    a = LS_CDR(a);
                }
                emit(c, OP_MAKE(OP_LIST, n));
                return;
            }
        }
    }

    /* If the head is a lambda expression: ((lambda (...) body) args...) */
    if (head.tag == LS_T_CONS) {
        ls_value_t hcar = LS_CAR(head);
        if (hcar.tag == LS_T_SYMBOL &&
            (ls_symbol_t *)hcar.u.ptr == L->sym_lambda) {
            /* Compile as a closure then immediately call it. */
            compile_lambda(c, LS_CDR(head));
            int nargs = 0;
            ls_value_t a = args;
            while (a.tag == LS_T_CONS) {
                compile_form(c, LS_CAR(a), 0);
                nargs++;
                a = LS_CDR(a);
            }
            if (tail)
                emit(c, OP_MAKE(OP_TAILCALL, nargs));
            else
                emit(c, OP_MAKE(OP_CALL, nargs));
            return;
        }
    }

    /* Generic function call. */
    compile_call(c, head, args, tail);
}

/* ------------------------------------------------------------------ */
/*  Inner lambda compilation                                           */
/* ------------------------------------------------------------------ */

static int compile_lambda_inner(ls_compiler_t *parent, ls_value_t lambda_list,
                                ls_value_t body, ls_symbol_t *name) {
    ls_state_t *L = parent->L;

    ls_compiler_t child;
    memset(&child, 0, sizeof child);
    child.L       = L;
    child.parent  = parent;
    child.name    = name;

    /* Parse the lambda list and allocate locals for parameters. */
    int phase = 0;  /* 0=req, 1=opt, 2=rest */
    ls_value_t ll = lambda_list;
    while (ll.tag == LS_T_CONS) {
        ls_value_t p = LS_CAR(ll);
        ll = LS_CDR(ll);

        if (p.tag == LS_T_SYMBOL) {
            ls_symbol_t *ps = (ls_symbol_t *)p.u.ptr;
            if (ps == L->sym_ampersand_rest) {
                child.has_rest = 1;
                phase = 2;
                continue;
            }
            if (ps == L->sym_ampersand_optional) {
                phase = 1;
                continue;
            }
            if (ps == L->sym_ampersand_key || ps == L->sym_ampersand_aux ||
                ps == L->sym_ampersand_body || ps == L->sym_ampersand_allow_other_keys) {
                /* For simplicity, treat &key/&aux etc. like optionals. */
                phase = 1;
                continue;
            }
            add_local(&child, ps);
            if (phase == 0) child.n_args++;
            else child.n_opt++;
        } else if (p.tag == LS_T_CONS) {
            /* (name default) -- optional with default */
            ls_value_t pn = LS_CAR(p);
            if (pn.tag == LS_T_SYMBOL) {
                add_local(&child, (ls_symbol_t *)pn.u.ptr);
                child.n_opt++;
            }
        }
    }

    /* Compile the body. */
    compile_progn(&child, body, 1);
    emit(&child, OP_MAKE(OP_RETURN, 0));

    /* Build the proto object. */
    ls_value_t pv = ls_make_obj(L, LS_T_BYTECODE, sizeof(ls_proto_t));
    ls_proto_t *proto = (ls_proto_t *)pv.u.ptr;
    proto->h.tag = LS_T_BYTECODE;

    proto->code_len = (uint32_t)child.code_len;
    proto->code = (uint32_t *)malloc(child.code_len * sizeof(uint32_t));
    memcpy(proto->code, child.code, child.code_len * sizeof(uint32_t));

    proto->n_consts = (uint32_t)child.n_consts;
    if (child.n_consts > 0) {
        proto->consts = (ls_value_t *)malloc(child.n_consts * sizeof(ls_value_t));
        memcpy(proto->consts, child.consts, child.n_consts * sizeof(ls_value_t));
    }

    proto->n_upvals = (uint32_t)child.n_upvals;
    if (child.n_upvals > 0) {
        proto->upvals = (ls_symbol_t **)malloc(child.n_upvals * sizeof(ls_symbol_t *));
        for (int i = 0; i < child.n_upvals; i++)
            proto->upvals[i] = child.upvals[i].sym;
    }

    proto->n_args    = (uint32_t)child.n_args;
    proto->n_opt     = (uint32_t)child.n_opt;
    proto->n_locals  = (uint32_t)child.n_locals;
    proto->has_rest  = (uint32_t)child.has_rest;
    proto->name      = name;
    proto->source    = ls_nil_v();
    proto->line_info = NULL;
    proto->line_info_len = 0;

    /* Store any nested protos compiled inside this child into the
     * child's constant pool (they are referenced by OP_CLOSURE). */
    /* The inner_protos of *child* are already referenced by their
     * constant-pool index (added during compile_lambda_inner recursion
     * from the child).  Nothing extra to do. */

    /* Register this proto in the parent's inner array. */
    if (parent->n_inner >= COMP_MAX_INNER)
        ls_error(L, "bytecode compiler: too many nested lambdas");
    int idx = parent->n_inner++;
    parent->inner_protos[idx] = proto;

    /* Also add the proto as a constant in the parent so OP_CLOSURE can
     * reference it by constant-pool index. */
    int ci = add_const(parent, pv);
    (void)ci;  /* The CLOSURE instruction uses the inner index. */

    return idx;
}

/* ================================================================
 *  Top-level compilation entry point
 * ================================================================ */

ls_value_t ls_compile_to_bytecode(ls_state_t *L, ls_value_t form) {
    ls_compiler_t top;
    memset(&top, 0, sizeof top);
    top.L = L;

    compile_form(&top, form, 1);
    emit(&top, OP_MAKE(OP_RETURN, 0));

    /* Build the top-level proto. */
    ls_value_t pv = ls_make_obj(L, LS_T_BYTECODE, sizeof(ls_proto_t));
    ls_proto_t *proto = (ls_proto_t *)pv.u.ptr;
    proto->h.tag = LS_T_BYTECODE;

    proto->code_len = (uint32_t)top.code_len;
    proto->code = (uint32_t *)malloc(top.code_len * sizeof(uint32_t));
    memcpy(proto->code, top.code, top.code_len * sizeof(uint32_t));

    proto->n_consts = (uint32_t)top.n_consts;
    if (top.n_consts > 0) {
        proto->consts = (ls_value_t *)malloc(top.n_consts * sizeof(ls_value_t));
        memcpy(proto->consts, top.consts, top.n_consts * sizeof(ls_value_t));
    }

    proto->n_upvals  = 0;
    proto->upvals    = NULL;
    proto->n_args    = 0;
    proto->n_opt     = 0;
    proto->n_locals  = (uint32_t)top.n_locals;
    proto->has_rest  = 0;
    proto->name      = NULL;
    proto->source    = form;
    proto->line_info = NULL;
    proto->line_info_len = 0;

    /* Wrap in a bytecode closure. */
    ls_value_t fv = ls_make_obj(L, LS_T_BYTECODE, sizeof(ls_bytecode_fn_t));
    ls_bytecode_fn_t *fn = (ls_bytecode_fn_t *)fv.u.ptr;
    fn->proto      = proto;
    fn->upvals     = NULL;
    fn->nupvals    = 0;
    fn->jit_entry  = NULL;
    fn->call_count = 0;
    fn->name       = NULL;

    return fv;
}

/* ================================================================
 *  Virtual machine
 * ================================================================ */

#define VM_STACK_SIZE 1024

ls_value_t ls_vm_run(ls_state_t *L, ls_bytecode_fn_t *fn, int nargs, ls_value_t *args) {
    ls_proto_t  *proto  = fn->proto;
    uint32_t    *code   = proto->code;
    ls_value_t  *consts = proto->consts;
    ls_value_t  *upvals = fn->upvals;

    ls_value_t stack[VM_STACK_SIZE];
    int sp = 0;  /* stack pointer: points to the next free slot */

    /* Allocate space for locals.  Locals live at the bottom of the
     * stack and are directly indexed. */
    int n_locals = (int)proto->n_locals;
    for (int i = 0; i < n_locals; i++)
        stack[sp++] = ls_nil_v();

    /* Bind arguments into the first locals slots. */
    int n_params = (int)proto->n_args + (int)proto->n_opt;
    for (int i = 0; i < nargs && i < n_params; i++)
        stack[i] = args[i];

    /* &rest parameter: collect remaining args into a list. */
    if (proto->has_rest && n_params < n_locals) {
        ls_value_t rest = ls_nil_v();
        for (int i = nargs - 1; i >= n_params; i--)
            rest = ls_cons(L, args[i], rest);
        stack[n_params] = rest;
    }

    int pc = 0;

    /* Handler stack for PUSH_HANDLER / POP_HANDLER. */
    typedef struct vm_handler {
        int target_pc;
        int saved_sp;
    } vm_handler_t;
    vm_handler_t handlers[64];
    int hsp = 0;

    fn->call_count++;

    for (;;) {
        if (pc < 0 || pc >= (int)proto->code_len)
            ls_error(L, "VM: program counter out of bounds (pc=%d, len=%u)",
                     pc, proto->code_len);
        if (sp >= VM_STACK_SIZE - 4)
            ls_error(L, "VM: stack overflow");

        uint32_t instr = code[pc++];
        uint32_t op    = OP_GET_OP(instr);
        uint32_t arg   = OP_GET_ARG(instr);
        int32_t  sarg  = OP_GET_SARG(instr);

        switch (op) {

        case OP_NOP:
            break;

        /* -- Constants / immediates ------------------------------------ */
        case OP_CONST:
            if (arg >= proto->n_consts)
                ls_error(L, "VM: CONST index %u out of range", arg);
            stack[sp++] = consts[arg];
            break;

        case OP_NIL:
            stack[sp++] = ls_nil_v();
            break;

        case OP_T:
            stack[sp++] = ls_t_v();
            break;

        case OP_FIXNUM:
            stack[sp++] = ls_make_fixnum((int64_t)sarg);
            break;

        /* -- Locals / upvals / globals --------------------------------- */
        case OP_LOAD_LOCAL:
            if ((int)arg >= n_locals)
                ls_error(L, "VM: LOAD_LOCAL slot %u >= n_locals %d", arg, n_locals);
            stack[sp++] = stack[arg];
            break;

        case OP_STORE_LOCAL:
            if (sp < 1) ls_error(L, "VM: stack underflow on STORE_LOCAL");
            if ((int)arg >= n_locals)
                ls_error(L, "VM: STORE_LOCAL slot %u >= n_locals %d", arg, n_locals);
            stack[arg] = stack[--sp];
            break;

        case OP_LOAD_UPVAL:
            if (!upvals || arg >= fn->nupvals)
                ls_error(L, "VM: LOAD_UPVAL index %u out of range", arg);
            stack[sp++] = upvals[arg];
            break;

        case OP_STORE_UPVAL:
            if (sp < 1) ls_error(L, "VM: stack underflow on STORE_UPVAL");
            if (!upvals || arg >= fn->nupvals)
                ls_error(L, "VM: STORE_UPVAL index %u out of range", arg);
            upvals[arg] = stack[--sp];
            break;

        case OP_LOAD_GLOBAL: {
            if (arg >= proto->n_consts)
                ls_error(L, "VM: LOAD_GLOBAL const index %u out of range", arg);
            ls_value_t sym_v = consts[arg];
            if (sym_v.tag != LS_T_SYMBOL)
                ls_error(L, "VM: LOAD_GLOBAL const is not a symbol");
            ls_symbol_t *sym = (ls_symbol_t *)sym_v.u.ptr;
            /* Check function slot first, then value slot. */
            if (sym->sym_flags & LS_SYM_HAS_FN) {
                stack[sp++] = sym->function;
            } else if (sym->sym_flags & LS_SYM_HAS_VALUE) {
                stack[sp++] = sym->value;
            } else if (sym->value.tag != LS_T_NIL || sym->function.tag != LS_T_NIL) {
                /* Try value then function even without flags (common
                 * for symbols bound by setq at top level). */
                if (sym->value.tag != LS_T_NIL)
                    stack[sp++] = sym->value;
                else
                    stack[sp++] = sym->function;
            } else {
                ls_unbound_variable_error(L, sym);
            }
            break;
        }

        case OP_STORE_GLOBAL: {
            if (sp < 1) ls_error(L, "VM: stack underflow on STORE_GLOBAL");
            if (arg >= proto->n_consts)
                ls_error(L, "VM: STORE_GLOBAL const index %u out of range", arg);
            ls_value_t sym_v = consts[arg];
            if (sym_v.tag != LS_T_SYMBOL)
                ls_error(L, "VM: STORE_GLOBAL const is not a symbol");
            ls_symbol_t *sym = (ls_symbol_t *)sym_v.u.ptr;
            if (sym->sym_flags & LS_SYM_CONSTANT)
                ls_error(L, "VM: cannot assign to constant %s",
                         sym->name ? sym->name->chars : "?");
            sym->value = stack[--sp];
            sym->sym_flags |= LS_SYM_HAS_VALUE;
            break;
        }

        /* -- Stack manipulation ---------------------------------------- */
        case OP_POP:
            if (sp < 1) ls_error(L, "VM: stack underflow on POP");
            sp--;
            break;

        case OP_DUP:
            if (sp < 1) ls_error(L, "VM: stack underflow on DUP");
            stack[sp] = stack[sp - 1];
            sp++;
            break;

        /* -- Branching ------------------------------------------------- */
        case OP_JUMP:
            pc += sarg;
            break;

        case OP_JUMP_IF_NIL:
            if (sp < 1) ls_error(L, "VM: stack underflow on JUMP_IF_NIL");
            if (stack[--sp].tag == LS_T_NIL)
                pc += sarg;
            break;

        case OP_JUMP_IF_NOT_NIL:
            if (sp < 1) ls_error(L, "VM: stack underflow on JUMP_IF_NOT_NIL");
            if (stack[--sp].tag != LS_T_NIL)
                pc += sarg;
            break;

        /* -- Calls ----------------------------------------------------- */
        case OP_CALL:
        case OP_TAILCALL: {
            int na = (int)arg;
            if (sp < na + 1)
                ls_error(L, "VM: stack underflow on CALL (sp=%d, nargs=%d)", sp, na);
            ls_value_t *call_args = &stack[sp - na];
            ls_value_t callee = stack[sp - na - 1];
            sp -= (na + 1);

            ls_value_t result;
            if (callee.tag == LS_T_BYTECODE) {
                ls_bytecode_fn_t *bfn = (ls_bytecode_fn_t *)callee.u.ptr;

                /* JIT threshold check. */
                if (L->jit_enabled && bfn->call_count >= (uint32_t)L->jit_threshold &&
                    bfn->jit_entry == NULL) {
                    ls_jit_function(L, callee);
                }

                if (op == OP_TAILCALL && bfn == fn) {
                    /* Self tail-call: reuse the current frame. */
                    for (int i = 0; i < na && i < n_locals; i++)
                        stack[i] = call_args[i];
                    for (int i = na; i < n_locals; i++)
                        stack[i] = ls_nil_v();
                    sp = n_locals;
                    pc = 0;
                    bfn->call_count++;
                    break;
                }

                result = ls_vm_run(L, bfn, na, call_args);
            } else if (callee.tag == LS_T_NATIVE) {
                ls_native_t *nat = (ls_native_t *)callee.u.ptr;
                result = nat->fn(L, na, call_args);
            } else if (callee.tag == LS_T_FUNCTION || callee.tag == LS_T_GENERIC) {
                result = ls_apply(L, callee, na, call_args);
            } else {
                ls_error(L, "VM: attempt to call non-function (tag=%d)", callee.tag);
                result = ls_nil_v();
            }

            stack[sp++] = result;
            break;
        }

        case OP_RETURN:
            if (sp < 1) return ls_nil_v();
            return stack[sp - 1];

        case OP_HALT:
            if (sp < 1) return ls_nil_v();
            return stack[sp - 1];

        /* -- Arithmetic ------------------------------------------------ */
        case OP_ADD: {
            if (sp < 2) ls_error(L, "VM: stack underflow on ADD");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = ls_make_fixnum(a.u.fixnum + b.u.fixnum);
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = ls_make_flonum(da + db);
            }
            break;
        }

        case OP_SUB: {
            if (sp < 2) ls_error(L, "VM: stack underflow on SUB");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = ls_make_fixnum(a.u.fixnum - b.u.fixnum);
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = ls_make_flonum(da - db);
            }
            break;
        }

        case OP_MUL: {
            if (sp < 2) ls_error(L, "VM: stack underflow on MUL");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = ls_make_fixnum(a.u.fixnum * b.u.fixnum);
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = ls_make_flonum(da * db);
            }
            break;
        }

        case OP_DIV: {
            if (sp < 2) ls_error(L, "VM: stack underflow on DIV");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
            if (db == 0.0) ls_error(L, "VM: division by zero");
            double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
            /* Integer division when both fixnum and exact. */
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM &&
                b.u.fixnum != 0 && (a.u.fixnum % b.u.fixnum) == 0)
                stack[sp++] = ls_make_fixnum(a.u.fixnum / b.u.fixnum);
            else
                stack[sp++] = ls_make_flonum(da / db);
            break;
        }

        case OP_MOD: {
            if (sp < 2) ls_error(L, "VM: stack underflow on MOD");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM) {
                if (b.u.fixnum == 0) ls_error(L, "VM: mod by zero");
                /* CL mod: result has sign of divisor. */
                int64_t r = a.u.fixnum % b.u.fixnum;
                if (r != 0 && ((r ^ b.u.fixnum) < 0))
                    r += b.u.fixnum;
                stack[sp++] = ls_make_fixnum(r);
            } else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                if (db == 0.0) ls_error(L, "VM: mod by zero");
                double r = da - db * floor(da / db);
                stack[sp++] = ls_make_flonum(r);
            }
            break;
        }

        case OP_NEG: {
            if (sp < 1) ls_error(L, "VM: stack underflow on NEG");
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM)
                stack[sp++] = ls_make_fixnum(-a.u.fixnum);
            else
                stack[sp++] = ls_make_flonum(-a.u.flonum);
            break;
        }

        /* -- Comparisons ----------------------------------------------- */
        case OP_EQ: {
            if (sp < 2) ls_error(L, "VM: stack underflow on EQ");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            /* EQ: pointer identity (or both nil, or same fixnum). */
            int eq = (a.tag == b.tag && a.u.ptr == b.u.ptr);
            stack[sp++] = eq ? ls_t_v() : ls_nil_v();
            break;
        }

        case OP_NUMEQ: {
            if (sp < 2) ls_error(L, "VM: stack underflow on NUMEQ");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
            double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
            stack[sp++] = (da == db) ? ls_t_v() : ls_nil_v();
            break;
        }

        case OP_LT: {
            if (sp < 2) ls_error(L, "VM: stack underflow on LT");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = (a.u.fixnum < b.u.fixnum) ? ls_t_v() : ls_nil_v();
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = (da < db) ? ls_t_v() : ls_nil_v();
            }
            break;
        }

        case OP_LE: {
            if (sp < 2) ls_error(L, "VM: stack underflow on LE");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = (a.u.fixnum <= b.u.fixnum) ? ls_t_v() : ls_nil_v();
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = (da <= db) ? ls_t_v() : ls_nil_v();
            }
            break;
        }

        case OP_GT: {
            if (sp < 2) ls_error(L, "VM: stack underflow on GT");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = (a.u.fixnum > b.u.fixnum) ? ls_t_v() : ls_nil_v();
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = (da > db) ? ls_t_v() : ls_nil_v();
            }
            break;
        }

        case OP_GE: {
            if (sp < 2) ls_error(L, "VM: stack underflow on GE");
            ls_value_t b = stack[--sp];
            ls_value_t a = stack[--sp];
            if (a.tag == LS_T_FIXNUM && b.tag == LS_T_FIXNUM)
                stack[sp++] = (a.u.fixnum >= b.u.fixnum) ? ls_t_v() : ls_nil_v();
            else {
                double da = (a.tag == LS_T_FIXNUM) ? (double)a.u.fixnum : a.u.flonum;
                double db = (b.tag == LS_T_FIXNUM) ? (double)b.u.fixnum : b.u.flonum;
                stack[sp++] = (da >= db) ? ls_t_v() : ls_nil_v();
            }
            break;
        }

        /* -- Logic ----------------------------------------------------- */
        case OP_NOT: {
            if (sp < 1) ls_error(L, "VM: stack underflow on NOT");
            ls_value_t a = stack[--sp];
            stack[sp++] = (a.tag == LS_T_NIL) ? ls_t_v() : ls_nil_v();
            break;
        }

        /* -- Cons / list ----------------------------------------------- */
        case OP_CONS: {
            if (sp < 2) ls_error(L, "VM: stack underflow on CONS");
            ls_value_t cdr = stack[--sp];
            ls_value_t car = stack[--sp];
            stack[sp++] = ls_cons(L, car, cdr);
            break;
        }

        case OP_CAR: {
            if (sp < 1) ls_error(L, "VM: stack underflow on CAR");
            ls_value_t a = stack[--sp];
            stack[sp++] = ls_car(a);
            break;
        }

        case OP_CDR: {
            if (sp < 1) ls_error(L, "VM: stack underflow on CDR");
            ls_value_t a = stack[--sp];
            stack[sp++] = ls_cdr(a);
            break;
        }

        case OP_LIST: {
            int n = (int)arg;
            if (sp < n) ls_error(L, "VM: stack underflow on LIST");
            ls_value_t lst = ls_nil_v();
            for (int i = 0; i < n; i++)
                lst = ls_cons(L, stack[sp - n + i], lst);
            /* That built the list backwards; reverse it. */
            lst = ls_list_reverse(L, lst);
            sp -= n;
            stack[sp++] = lst;
            break;
        }

        /* -- Closures -------------------------------------------------- */
        case OP_CLOSURE: {
            if (arg >= proto->n_consts)
                ls_error(L, "VM: CLOSURE const index %u out of range", arg);
            ls_value_t proto_v = consts[arg];
            if (proto_v.tag != LS_T_BYTECODE)
                ls_error(L, "VM: CLOSURE const is not a proto");
            ls_proto_t *inner = (ls_proto_t *)proto_v.u.ptr;

            ls_value_t fv = ls_make_obj(L, LS_T_BYTECODE, sizeof(ls_bytecode_fn_t));
            ls_bytecode_fn_t *closure = (ls_bytecode_fn_t *)fv.u.ptr;
            closure->proto      = inner;
            closure->jit_entry  = NULL;
            closure->call_count = 0;
            closure->name       = inner->name;

            /* Capture upvalues. */
            closure->nupvals = inner->n_upvals;
            if (inner->n_upvals > 0) {
                closure->upvals = (ls_value_t *)malloc(inner->n_upvals * sizeof(ls_value_t));
                for (uint32_t i = 0; i < inner->n_upvals; i++) {
                    /* We need to look up the upval descriptor from the
                     * compiler state.  But at runtime we don't have that
                     * struct.  Instead, we use a convention: the proto
                     * stores the upvalue symbol names; we resolve by
                     * looking at the current frame's locals first and then
                     * at the current closure's upvals. */
                    if (inner->upvals && inner->upvals[i]) {
                        ls_symbol_t *uvsym = inner->upvals[i];
                        /* Search current locals. */
                        int found = 0;
                        for (int j = 0; j < n_locals; j++) {
                            /* We need the local's symbol name.  We look
                             * it up from the proto's const table where
                             * the compiler placed variable symbols. */
                            /* Simpler approach: during compilation we
                             * record enough info.  At runtime we use a
                             * flat index scheme encoded in the proto.
                             * For now, match by the upval symbol against
                             * the outer proto's locals by iterating
                             * the const table for symbol matches. */
                            (void)j;
                        }
                        /* Fallback: search current fn's upvals. */
                        if (!found && upvals) {
                            for (uint32_t j = 0; j < fn->nupvals; j++) {
                                if (upvals[j].tag == LS_T_SYMBOL &&
                                    (ls_symbol_t *)upvals[j].u.ptr == uvsym) {
                                    closure->upvals[i] = upvals[j];
                                    found = 1;
                                    break;
                                }
                            }
                        }
                        /* Last resort: get from locals by slot index.
                         * The compiler arranged upval slot i to capture
                         * local slot i from the parent when is_local=1.
                         * We encode this: upvals[i] maps to stack[i]. */
                        if (!found && (int)i < n_locals) {
                            closure->upvals[i] = stack[i];
                        } else if (!found) {
                            closure->upvals[i] = ls_nil_v();
                        }
                    } else {
                        /* No symbol recorded; use positional: grab from
                         * current frame's locals or parent upvals. */
                        if ((int)i < n_locals)
                            closure->upvals[i] = stack[i];
                        else if (upvals && i < fn->nupvals)
                            closure->upvals[i] = upvals[i];
                        else
                            closure->upvals[i] = ls_nil_v();
                    }
                }
            } else {
                closure->upvals = NULL;
            }

            stack[sp++] = fv;
            break;
        }

        /* -- Exception handling ---------------------------------------- */
        case OP_PUSH_HANDLER:
            if (hsp >= 64) ls_error(L, "VM: handler stack overflow");
            handlers[hsp].target_pc = pc + sarg;
            handlers[hsp].saved_sp  = sp;
            hsp++;
            break;

        case OP_POP_HANDLER:
            if (hsp > 0) hsp--;
            break;

        default:
            ls_error(L, "VM: unknown opcode %u at pc=%d", op, pc - 1);
            return ls_nil_v();
        }
    }
    /* Should never reach here. */
    return ls_nil_v();
}

/* ================================================================
 *  Disassembler
 * ================================================================ */

static void disasm_proto(ls_state_t *L, ls_proto_t *proto, int indent) {
    (void)L;
    const char *pad = "";
    char ibuf[64];
    if (indent > 0) {
        int n = indent * 2;
        if (n >= (int)sizeof ibuf) n = (int)sizeof ibuf - 1;
        memset(ibuf, ' ', n);
        ibuf[n] = '\0';
        pad = ibuf;
    }

    printf("%s; proto", pad);
    if (proto->name && proto->name->name)
        printf(" %s", proto->name->name->chars);
    printf("  args=%u opt=%u locals=%u upvals=%u rest=%u\n",
           proto->n_args, proto->n_opt, proto->n_locals,
           proto->n_upvals, proto->has_rest);
    printf("%s; %u instructions, %u constants\n",
           pad, proto->code_len, proto->n_consts);

    for (uint32_t i = 0; i < proto->code_len; i++) {
        uint32_t instr = proto->code[i];
        uint32_t opc   = OP_GET_OP(instr);
        uint32_t arg   = OP_GET_ARG(instr);
        int32_t  sarg  = OP_GET_SARG(instr);

        const char *name = (opc < OP_MAX) ? ls_opcode_names[opc] : "???";

        printf("%s  %4u  %-18s", pad, i, name);

        switch (opc) {
        case OP_CONST:
            printf(" %u", arg);
            if (arg < proto->n_consts) {
                ls_value_t cv = proto->consts[arg];
                if (cv.tag == LS_T_SYMBOL) {
                    ls_symbol_t *s = (ls_symbol_t *)cv.u.ptr;
                    if (s->name) printf("  ; %s", s->name->chars);
                }
                else if (cv.tag == LS_T_FIXNUM) printf("  ; %lld", (long long)cv.u.fixnum);
                else if (cv.tag == LS_T_FLONUM) printf("  ; %g", cv.u.flonum);
                else if (cv.tag == LS_T_STRING) {
                    ls_string_t *ss = (ls_string_t *)cv.u.ptr;
                    if (ss && ss->chars) printf("  ; \"%s\"", ss->chars);
                }
            }
            break;
        case OP_FIXNUM:       printf(" %d", sarg); break;
        case OP_LOAD_LOCAL:   printf(" %u", arg);  break;
        case OP_STORE_LOCAL:  printf(" %u", arg);  break;
        case OP_LOAD_UPVAL:   printf(" %u", arg);  break;
        case OP_STORE_UPVAL:  printf(" %u", arg);  break;
        case OP_LOAD_GLOBAL:
        case OP_STORE_GLOBAL:
            printf(" %u", arg);
            if (arg < proto->n_consts) {
                ls_value_t cv = proto->consts[arg];
                if (cv.tag == LS_T_SYMBOL) {
                    ls_symbol_t *s = (ls_symbol_t *)cv.u.ptr;
                    if (s->name) printf("  ; %s", s->name->chars);
                }
            }
            break;
        case OP_JUMP:
        case OP_JUMP_IF_NIL:
        case OP_JUMP_IF_NOT_NIL:
        case OP_PUSH_HANDLER:
            printf(" %+d -> %u", sarg, (uint32_t)((int32_t)i + 1 + sarg));
            break;
        case OP_CALL:
        case OP_TAILCALL:     printf(" %u", arg); break;
        case OP_CLOSURE:      printf(" %u", arg); break;
        case OP_LIST:         printf(" %u", arg); break;
        default: break;
        }
        printf("\n");
    }

    /* Print inner protos. */
    for (uint32_t i = 0; i < proto->n_consts; i++) {
        if (proto->consts[i].tag == LS_T_BYTECODE) {
            /* Could be a proto (if it has code). */
            ls_proto_t *inner = (ls_proto_t *)proto->consts[i].u.ptr;
            if (inner->code && inner->code_len > 0) {
                printf("%s  -- inner proto const[%u] --\n", pad, i);
                disasm_proto(L, inner, indent + 1);
            }
        }
    }
}

/* ================================================================
 *  Native builtins: (compile form), (disassemble fn)
 * ================================================================ */

static ls_value_t bi_compile(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) ls_error(L, "compile: need 1 argument");
    return ls_compile_to_bytecode(L, args[0]);
}

static ls_value_t bi_vm_eval(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) ls_error(L, "vm-eval: need 1 argument");
    ls_value_t fn_v = ls_compile_to_bytecode(L, args[0]);
    if (fn_v.tag != LS_T_BYTECODE)
        ls_error(L, "vm-eval: compilation failed");
    ls_bytecode_fn_t *fn = (ls_bytecode_fn_t *)fn_v.u.ptr;
    return ls_vm_run(L, fn, 0, NULL);
}

static ls_value_t bi_disassemble(ls_state_t *L, int nargs, ls_value_t *args) {
    if (nargs < 1) ls_error(L, "disassemble: need 1 argument");
    ls_value_t v = args[0];

    ls_proto_t *proto = NULL;
    if (v.tag == LS_T_BYTECODE) {
        /* Could be a bytecode_fn or a proto.  Check if it has a proto
         * pointer (bytecode_fn) or a code pointer (proto). */
        ls_bytecode_fn_t *bfn = (ls_bytecode_fn_t *)v.u.ptr;
        if (bfn->proto)
            proto = bfn->proto;
        else {
            /* Might be a raw proto. */
            ls_proto_t *p = (ls_proto_t *)v.u.ptr;
            if (p->code) proto = p;
        }
    }

    if (!proto) {
        /* Try to compile it first. */
        ls_value_t compiled = ls_compile_to_bytecode(L, v);
        if (compiled.tag == LS_T_BYTECODE) {
            ls_bytecode_fn_t *bfn = (ls_bytecode_fn_t *)compiled.u.ptr;
            proto = bfn->proto;
        }
    }

    if (!proto) {
        ls_error(L, "disassemble: cannot disassemble value");
        return ls_nil_v();
    }

    disasm_proto(L, proto, 0);
    return ls_nil_v();
}

/* ================================================================
 *  Init
 * ================================================================ */

void ls_init_vm(ls_state_t *L) {
    ls_defun(L, "COMMON-LISP", "COMPILE-TO-BYTECODE", bi_compile, 1, 1);
    ls_defun(L, "COMMON-LISP", "VM-EVAL", bi_vm_eval, 1, 1);
    ls_defun(L, "COMMON-LISP", "DISASSEMBLE", bi_disassemble, 1, 1);
}

/* REPL entry point: compile FORM to bytecode and run it on the VM.
 * Falls back to the interpreter on compilation failure (so unsupported
 * special forms still work). */
ls_value_t ls_vm_compile_and_run(ls_state_t *L, ls_value_t form) {
    ls_value_t fn_v = ls_compile_to_bytecode(L, form);
    if (fn_v.tag != LS_T_BYTECODE) {
        /* fall back to interpreter */
        return ls_eval(L, form, L->genv);
    }
    ls_bytecode_fn_t *fn = (ls_bytecode_fn_t *)fn_v.u.ptr;
    return ls_vm_run(L, fn, 0, NULL);
}
/*** End: lsvm.c ***/

/*** Begin: lsaot.c ***/
/* lsaot.c -- AOT C transpiler for Litesrpent.
 *
 * Parses Lisp source, emits equivalent C code that links against the
 * Litesrpent runtime (lsrt.h / lsrt.c), then invokes the host C
 * compiler to produce a native executable.
 *
 * The generated C uses the runtime's tagged-value type (ls_value_t)
 * so it is fully compatible with the interpreter for mixed-mode use.
 */

/* ================================================================
 *  Compiler context -- threaded through every emit helper
 * ================================================================ */

#define AOT_MAX_LOCALS  256
#define AOT_MAX_LAMBDAS 512

typedef struct local_var {
    const char *name;        /* Lisp symbol name */
    char c_name[64];         /* C identifier */
    int  depth;              /* nesting depth for let scoping */
} local_var_t;

typedef struct lambda_info {
    int  id;                 /* unique id for naming the C function */
    char c_name[64];         /* generated C function name */
} lambda_info_t;

typedef struct compiler_ctx {
    ls_state_t  *L;
    FILE        *out;
    FILE        *hdr;            /* forward declarations section */
    int          indent;

    /* Local variable tracking. */
    local_var_t  locals[AOT_MAX_LOCALS];
    int          n_locals;
    int          scope_depth;

    /* Lambda lifting. */
    lambda_info_t lambdas[AOT_MAX_LAMBDAS];
    int           n_lambdas;

    /* Deferred lambda bodies (written after current function). */
    char         *deferred_buf;
    size_t        deferred_len;
    size_t        deferred_cap;
    FILE         *deferred;       /* memstream / tmpfile for lambda bodies */

    /* For generating unique C identifiers. */
    int           tmp_counter;
    int           label_counter;

    /* Flags. */
    int           in_tail_pos;     /* 1 if current expr is in tail position */
    int           in_expr_ctx;     /* 1 = expression ctx (emit value), 0 = stmt */
} compiler_ctx_t;

/* ================================================================
 *  Forward declarations
 * ================================================================ */

static void emit_expr(FILE *out, ls_value_t form, compiler_ctx_t *ctx);
static void emit_body(FILE *out, ls_value_t forms, compiler_ctx_t *ctx);
static void emit_toplevel_defun(FILE *out, ls_value_t form, compiler_ctx_t *ctx);
static void emit_toplevel_expr(FILE *out, ls_value_t form, compiler_ctx_t *ctx);

/* ================================================================
 *  Utility helpers
 * ================================================================ */

/* Write indentation. */
static void emit_indent(FILE *out, compiler_ctx_t *ctx) {
    for (int i = 0; i < ctx->indent; i++) fprintf(out, "    ");
}

/* Sanitise a Lisp symbol name into a valid C identifier. */
static void sanitise_name(const char *lisp_name, char *c_name, size_t cap) {
    size_t j = 0;
    for (size_t i = 0; lisp_name[i] && j + 1 < cap; i++) {
        char ch = lisp_name[i];
        if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
            (ch >= '0' && ch <= '9') || ch == '_') {
            c_name[j++] = (ch >= 'A' && ch <= 'Z') ? (char)(ch - 'A' + 'a') : ch;
        } else if (ch == '-') {
            c_name[j++] = '_';
        } else if (ch == '?' && j + 2 < cap) {
            c_name[j++] = '_'; c_name[j++] = 'p';
        } else if (ch == '!' && j + 2 < cap) {
            c_name[j++] = '_'; c_name[j++] = 'b';
        } else if (ch == '*') {
            c_name[j++] = '_';
        } else if (ch == '+') {
            if (j + 4 < cap) { memcpy(c_name + j, "_add", 4); j += 4; }
        } else if (ch == '/') {
            if (j + 4 < cap) { memcpy(c_name + j, "_div", 4); j += 4; }
        } else if (ch == '<') {
            if (j + 3 < cap) { memcpy(c_name + j, "_lt", 3); j += 3; }
        } else if (ch == '>') {
            if (j + 3 < cap) { memcpy(c_name + j, "_gt", 3); j += 3; }
        } else if (ch == '=') {
            if (j + 3 < cap) { memcpy(c_name + j, "_eq", 3); j += 3; }
        } else {
            /* hex-escape anything else */
            if (j + 3 < cap) { j += snprintf(c_name + j, cap - j, "x%02x", (unsigned char)ch); }
        }
    }
    c_name[j] = '\0';
}

/* Push a local variable binding. Returns the C identifier. */
static const char *ctx_push_local(compiler_ctx_t *ctx, const char *lisp_name) {
    if (ctx->n_locals >= AOT_MAX_LOCALS) {
        ls_error(ctx->L, "AOT: too many local variables");
        return "ERROR_LOCAL";
    }
    local_var_t *lv = &ctx->locals[ctx->n_locals];
    lv->name = lisp_name;
    lv->depth = ctx->scope_depth;
    snprintf(lv->c_name, sizeof lv->c_name, "lv_%d_", ctx->n_locals);
    sanitise_name(lisp_name, lv->c_name + strlen(lv->c_name),
                  sizeof(lv->c_name) - strlen(lv->c_name));
    ctx->n_locals++;
    return lv->c_name;
}

/* Find a local variable by Lisp name (search innermost first). */
static const char *ctx_find_local(compiler_ctx_t *ctx, const char *lisp_name) {
    for (int i = ctx->n_locals - 1; i >= 0; i--) {
        if (strcmp(ctx->locals[i].name, lisp_name) == 0)
            return ctx->locals[i].c_name;
    }
    return NULL;
}

/* Pop locals down to the given depth. */
static void ctx_pop_to_depth(compiler_ctx_t *ctx, int depth) {
    while (ctx->n_locals > 0 && ctx->locals[ctx->n_locals - 1].depth > depth)
        ctx->n_locals--;
}

/* Get a fresh temporary name. */
static int ctx_fresh_tmp(compiler_ctx_t *ctx) {
    return ctx->tmp_counter++;
}

/* Check if a form's head matches a known symbol. */
static int form_head_is(ls_state_t *L, ls_value_t form, ls_symbol_t *sym) {
    if (form.tag != LS_T_CONS) return 0;
    ls_value_t head = ls_car(form);
    return head.tag == LS_T_SYMBOL && (ls_symbol_t *)head.u.ptr == sym;
}

/* Check if a symbol name matches a string (case insensitive). */
static int sym_name_eq(ls_value_t v, const char *name) {
    if (v.tag != LS_T_SYMBOL) return 0;
    ls_symbol_t *s = (ls_symbol_t *)v.u.ptr;
    if (!s->name || !s->name->chars) return 0;
    const char *sn = s->name->chars;
    for (size_t i = 0; ; i++) {
        char a = sn[i], b = name[i];
        if (a >= 'a' && a <= 'z') a = (char)(a - 32);
        if (b >= 'a' && b <= 'z') b = (char)(b - 32);
        if (a != b) return 0;
        if (a == '\0') return 1;
    }
}

