static ls_stream_t *make_file_stream(ls_state_t *L, FILE *fp, int dir) {
    ls_value_t v = ls_make_obj(L, LS_T_STREAM, sizeof(ls_stream_t));
    ls_stream_t *s = (ls_stream_t *)v.u.ptr;
    s->fp = fp;
    s->direction = dir;
    s->owns_fp = 0;
    s->ungot_char = -1;
    return s;
}

